export enum TaskStatus {
  NOT_STARTED = 'NOT_STARTED',
  IN_PROGRESS = 'IN_PROGRESS',
  DONE = 'DONE',
  NEEDS_FOLLOWUP = 'NEEDS_FOLLOWUP',
  BLOCKED = 'BLOCKED'
}

export interface TaskLog {
  id: string;
  timestamp: number;
  workerName: string;
  description: string;
  status: TaskStatus;
}

export interface Unit {
  id: string;
  buildingId: string;
  number: number;
  status: TaskStatus;
  history: TaskLog[];
  nextSteps?: string;
}

export interface Building {
  id: string;
  name: string;
  totalUnits: number;
}

export interface ProjectState {
  buildings: Building[];
  units: Record<string, Unit>; // key is "buildingId-unitNumber"
}

import React from 'react';
import { TaskStatus } from './types';

export const STATUS_CONFIG: Record<TaskStatus, { label: string; color: string; icon: string }> = {
  [TaskStatus.NOT_STARTED]: {
    label: 'טרם החל',
    color: 'bg-gray-100 text-gray-600 border-gray-200',
    icon: '⚪'
  },
  [TaskStatus.IN_PROGRESS]: {
    label: 'בביצוע',
    color: 'bg-blue-100 text-blue-700 border-blue-200',
    icon: '🔵'
  },
  [TaskStatus.DONE]: {
    label: 'הושלם',
    color: 'bg-green-100 text-green-700 border-green-200',
    icon: '🟢'
  },
  [TaskStatus.NEEDS_FOLLOWUP]: {
    label: 'משימת המשך',
    color: 'bg-yellow-100 text-yellow-700 border-yellow-200',
    icon: '🟡'
  },
  [TaskStatus.BLOCKED]: {
    label: 'מעוכב/תקוע',
    color: 'bg-red-100 text-red-700 border-red-200',
    icon: '🔴'
  }
};

export const BUILDINGS_COUNT = 33;
export const UNITS_PER_BUILDING = 50;

import { ProjectState, Building, Unit, TaskStatus, TaskLog } from '../types';
import { BUILDINGS_COUNT, UNITS_PER_BUILDING } from '../constants';

const STORAGE_KEY = 'plumbtrack_data_v1';

export const initializeData = (): ProjectState => {
  const saved = localStorage.getItem(STORAGE_KEY);
  if (saved) {
    return JSON.parse(saved);
  }

  const buildings: Building[] = Array.from({ length: BUILDINGS_COUNT }, (_, i) => ({
    id: `b-${i + 1}`,
    name: `בניין ${i + 1}`,
    totalUnits: UNITS_PER_BUILDING
  }));

  const initialState: ProjectState = {
    buildings,
    units: {}
  };

  return initialState;
};

export const saveData = (state: ProjectState) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
};

export const getUnit = (state: ProjectState, buildingId: string, unitNumber: number): Unit => {
  const key = `${buildingId}-${unitNumber}`;
  if (state.units[key]) return state.units[key];

  return {
    id: key,
    buildingId,
    number: unitNumber,
    status: TaskStatus.NOT_STARTED,
    history: []
  };
};

export const updateUnit = (
  state: ProjectState, 
  unit: Unit, 
  newLog?: Omit<TaskLog, 'id' | 'timestamp'>
): ProjectState => {
  const newState = { ...state };
  const updatedUnit = { ...unit };

  if (newLog) {
    const logEntry: TaskLog = {
      ...newLog,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now()
    };
    updatedUnit.history = [logEntry, ...updatedUnit.history];
    updatedUnit.status = newLog.status;
  }

  newState.units[unit.id] = updatedUnit;
  saveData(newState);
  return newState;
};

import React from 'react';
import { Building, ProjectState } from '../types';
import { STATUS_CONFIG } from '../constants';

interface Props {
  buildings: Building[];
  selectedBuildingId: string | null;
  onSelect: (id: string) => void;
  state: ProjectState;
}

const BuildingSelector: React.FC<Props> = ({ buildings, selectedBuildingId, onSelect, state }) => {
  // Calculate completion percentage for each building
  const getCompletionStats = (buildingId: string) => {
    let completed = 0;
    for (let i = 1; i <= 50; i++) {
      const unitKey = `${buildingId}-${i}`;
      if (state.units[unitKey]?.status === 'DONE') completed++;
    }
    return Math.round((completed / 50) * 100);
  };

  return (
    <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 gap-3 p-4">
      {buildings.map((b) => {
        const progress = getCompletionStats(b.id);
        const isActive = selectedBuildingId === b.id;

        return (
          <button
            key={b.id}
            onClick={() => onSelect(b.id)}
            className={`flex flex-col items-center justify-center p-4 rounded-xl transition-all border-2 shadow-sm ${
              isActive 
                ? 'bg-blue-600 border-blue-700 text-white transform scale-105 z-10' 
                : 'bg-white border-gray-100 hover:border-blue-300 text-gray-700'
            }`}
          >
            <span className="text-lg font-bold">{b.name}</span>
            <div className="w-full mt-2 h-1.5 bg-gray-200 rounded-full overflow-hidden">
              <div 
                className={`h-full rounded-full transition-all ${isActive ? 'bg-white' : 'bg-blue-500'}`} 
                style={{ width: `${progress}%` }}
              />
            </div>
            <span className={`text-[10px] mt-1 ${isActive ? 'text-blue-100' : 'text-gray-400'}`}>
              {progress}% הושלם
            </span>
          </button>
        );
      })}
    </div>
  );
};

export default BuildingSelector;

import React from 'react';
import { ProjectState, TaskStatus } from '../types';
import { STATUS_CONFIG, UNITS_PER_BUILDING } from '../constants';
import { getUnit } from '../services/dataService';

interface Props {
  buildingId: string;
  state: ProjectState;
  onSelectUnit: (unitNumber: number) => void;
}

const UnitGrid: React.FC<Props> = ({ buildingId, state, onSelectUnit }) => {
  const units = Array.from({ length: UNITS_PER_BUILDING }, (_, i) => i + 1);

  return (
    <div className="bg-white rounded-2xl shadow-sm p-6 border border-gray-100">
      <div className="flex items-center justify-between mb-6">
        <h2 className="text-xl font-bold text-gray-800">רשימת דירות</h2>
        <div className="flex gap-2 flex-wrap">
          {Object.entries(STATUS_CONFIG).map(([status, config]) => (
            <div key={status} className="flex items-center gap-1 text-xs">
              <span className={`w-2 h-2 rounded-full ${config.color.split(' ')[0]}`}></span>
              <span className="text-gray-500">{config.label}</span>
            </div>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-5 sm:grid-cols-6 md:grid-cols-8 lg:grid-cols-10 gap-3">
        {units.map((num) => {
          const unitData = getUnit(state, buildingId, num);
          const config = STATUS_CONFIG[unitData.status];

          return (
            <button
              key={num}
              onClick={() => onSelectUnit(num)}
              className={`aspect-square flex flex-col items-center justify-center rounded-lg border transition-all hover:shadow-md active:scale-95 ${config.color}`}
            >
              <span className="text-xs font-medium opacity-70">דירה</span>
              <span className="text-lg font-bold">{num}</span>
            </button>
          );
        })}
      </div>
    </div>
  );
};

export default UnitGrid;

import React, { useState } from 'react';
import { Unit, TaskStatus, TaskLog } from '../types';
import { STATUS_CONFIG } from '../constants';

interface Props {
  unit: Unit;
  onClose: () => void;
  onSave: (status: TaskStatus, worker: string, description: string) => void;
}

const UnitModal: React.FC<Props> = ({ unit, onClose, onSave }) => {
  const [worker, setWorker] = useState('');
  const [desc, setDesc] = useState('');
  const [status, setStatus] = useState<TaskStatus>(unit.status);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!worker || !desc) return alert('נא למלא שם עובד ותיאור');
    onSave(status, worker, desc);
    setWorker('');
    setDesc('');
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
      <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
        {/* Header */}
        <div className="p-6 border-b flex justify-between items-center bg-gray-50">
          <div>
            <h3 className="text-2xl font-bold text-gray-800">דירה {unit.number}</h3>
            <p className="text-sm text-gray-500">בניין: {unit.buildingId.split('-')[1]}</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-200 rounded-full transition-colors text-2xl">&times;</button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-8">
          {/* New Entry Form */}
          <section className="bg-blue-50/50 p-5 rounded-2xl border border-blue-100">
            <h4 className="text-sm font-bold text-blue-800 mb-4 uppercase tracking-wider">דיווח חדש</h4>
            <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 pr-1">שם העובד</label>
                <input 
                  value={worker}
                  onChange={e => setWorker(e.target.value)}
                  className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none" 
                  placeholder="למשל: איציק האינסטלטור"
                />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 pr-1">סטטוס עדכני</label>
                <select 
                  value={status}
                  onChange={e => setStatus(e.target.value as TaskStatus)}
                  className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none bg-white"
                >
                  {Object.entries(STATUS_CONFIG).map(([s, cfg]) => (
                    <option key={s} value={s}>{cfg.label}</option>
                  ))}
                </select>
              </div>
              <div className="md:col-span-2 space-y-1">
                <label className="text-xs font-semibold text-gray-500 pr-1">מה בוצע? / משימת המשך</label>
                <textarea 
                  value={desc}
                  onChange={e => setDesc(e.target.value)}
                  rows={2}
                  className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none resize-none"
                  placeholder="תיאור העבודה שבוצעה או מה צריך לעשות בהמשך..."
                />
              </div>
              <button 
                type="submit"
                className="md:col-span-2 bg-blue-600 text-white font-bold py-3 rounded-xl hover:bg-blue-700 transition-all shadow-lg active:scale-95"
              >
                עדכון דירה
              </button>
            </form>
          </section>

          {/* History Timeline */}
          <section>
            <h4 className="text-sm font-bold text-gray-400 mb-6 uppercase tracking-wider">היסטוריית עבודה</h4>
            {unit.history.length === 0 ? (
              <div className="text-center py-10 text-gray-400 border-2 border-dashed rounded-2xl italic">אין דיווחים קודמים לדירה זו</div>
            ) : (
              <div className="space-y-6 relative before:absolute before:right-3 before:top-2 before:bottom-2 before:w-0.5 before:bg-gray-100">
                {unit.history.map((log) => (
                  <div key={log.id} className="relative pr-10">
                    <div className={`absolute right-0 top-1 w-6 h-6 rounded-full border-4 border-white shadow-sm ${STATUS_CONFIG[log.status].color.split(' ')[0]}`}></div>
                    <div className="bg-white border rounded-xl p-4 shadow-sm">
                      <div className="flex justify-between items-start mb-2">
                        <span className="font-bold text-gray-800">{log.workerName}</span>
                        <span className="text-[10px] text-gray-400 bg-gray-50 px-2 py-1 rounded-md">
                          {new Date(log.timestamp).toLocaleString('he-IL')}
                        </span>
                      </div>
                      <p className="text-sm text-gray-600 leading-relaxed whitespace-pre-wrap">{log.description}</p>
                      <div className="mt-3 inline-flex items-center gap-2">
                        <span className={`text-[10px] px-2 py-0.5 rounded-full border ${STATUS_CONFIG[log.status].color}`}>
