import React, { useState, useEffect, useMemo } from 'react';
import { ProjectState, TaskStatus, Unit } from './types';
import { initializeData, getUnit, updateUnit } from './services/dataService';
import BuildingSelector from './components/BuildingSelector';
import UnitGrid from './components/UnitGrid';
import UnitModal from './components/UnitModal';

const App: React.FC = () => {
  const [state, setState] = useState<ProjectState>(() => initializeData());
  const [selectedBuildingId, setSelectedBuildingId] = useState<string | null>(null);
  const [selectedUnitNumber, setSelectedUnitNumber] = useState<number | null>(null);
  const [searchTerm, setSearchTerm] = useState('');

  // Auto-select first building if none selected
  useEffect(() => {
    if (!selectedBuildingId && state.buildings.length > 0) {
      setSelectedBuildingId(state.buildings[0].id);
    }
  }, [state.buildings, selectedBuildingId]);

  const activeUnit = useMemo(() => {
    if (!selectedBuildingId || !selectedUnitNumber) return null;
    return getUnit(state, selectedBuildingId, selectedUnitNumber);
  }, [state, selectedBuildingId, selectedUnitNumber]);

  const handleUpdateUnit = (status: TaskStatus, worker: string, description: string) => {
    if (!activeUnit) return;
    const newState = updateUnit(state, activeUnit, { status, workerName: worker, description });
    setState(newState);
    // Keep the modal open but it will refresh with new state because of activeUnit recalculation
  };

  const filteredBuildings = state.buildings.filter(b => 
    b.name.includes(searchTerm) || b.id.includes(searchTerm)
  );

  return (
    <div className="min-h-screen bg-slate-50 text-right" dir="rtl">
      {/* Top Navbar */}
      <header className="sticky top-0 z-40 bg-blue-800 text-white shadow-lg p-4">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-white p-2 rounded-lg text-blue-800 text-2xl font-black">PT</div>
            <div>
              <h1 className="text-xl font-bold leading-none">PlumbTrack Pro</h1>
              <p className="text-[10px] text-blue-200 mt-1 uppercase tracking-widest">מערכת ניהול פרויקט אינסטלציה</p>
            </div>
          </div>

          <div className="w-full md:w-64 relative">
            <input 
              type="text" 
              placeholder="חיפוש בניין..." 
              value={searchTerm}
              onChange={e => setSearchTerm(e.target.value)}
              className="w-full bg-blue-700/50 border border-blue-500/30 rounded-full px-10 py-2 text-sm placeholder:text-blue-300 outline-none focus:ring-2 focus:ring-white/30"
            />
            <span className="absolute right-3 top-2.5 opacity-50">🔍</span>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto pb-20 px-4">
        {/* Statistics Bar */}
        <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mt-6">
          <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 flex flex-col items-center">
            <span className="text-xs text-gray-400 font-bold uppercase">סה"כ בניינים</span>
            <span className="text-2xl font-black text-blue-600">{state.buildings.length}</span>
          </div>
          <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 flex flex-col items-center">
            <span className="text-xs text-gray-400 font-bold uppercase">סה"כ דירות</span>
            <span className="text-2xl font-black text-blue-600">{state.buildings.length * 50}</span>
          </div>
          <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 flex flex-col items-center">
            <span className="text-xs text-gray-400 font-bold uppercase">דירות שהושלמו</span>
            <span className="text-2xl font-black text-green-600">
              {Object.values(state.units).filter(u => u.status === TaskStatus.DONE).length}
            </span>
          </div>
          <div className="bg-white p-4 rounded-2xl shadow-sm border border-gray-100 flex flex-col items-center">
            <span className="text-xs text-gray-400 font-bold uppercase">במעקב המשך</span>
            <span className="text-2xl font-black text-yellow-500">
              {Object.values(state.units).filter(u => u.status === TaskStatus.NEEDS_FOLLOWUP).length}
            </span>
          </div>
        </div>

        {/* Building Navigation */}
        <section className="mt-8">
          <div className="flex items-center justify-between mb-4 px-2">
            <h2 className="text-lg font-bold text-gray-700 flex items-center gap-2">
              <span className="w-8 h-8 rounded-full bg-blue-100 text-blue-600 flex items-center justify-center text-sm">🏢</span>
              בחירת בניין
            </h2>
            {searchTerm && <span className="text-xs text-blue-500">מציג {filteredBuildings.length} תוצאות חיפוש</span>}
          </div>
          <BuildingSelector 
            buildings={filteredBuildings} 
            selectedBuildingId={selectedBuildingId} 
            onSelect={setSelectedBuildingId}
            state={state}
          />
        </section>

        {/* Units View */}
        {selectedBuildingId && (
          <section className="mt-10 animate-in fade-in slide-in-from-bottom-4 duration-500">
            <UnitGrid 
              buildingId={selectedBuildingId} 
              state={state} 
              onSelectUnit={setSelectedUnitNumber} 
            />
          </section>
        )}
      </main>

      {/* Apartment Detail Modal */}
      {activeUnit && (
        <UnitModal 
          unit={activeUnit} 
          onClose={() => setSelectedUnitNumber(null)} 
          onSave={handleUpdateUnit}
        />
      )}

      {/* Mobile Sticky Footer Info */}
      <footer className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-md border-t p-3 text-center text-[10px] text-gray-400 z-30">
        PlumbTrack v1.0 • מערכת ניהול פרויקט בזמן אמת • כל הנתונים נשמרים מקומית
      </footer>
    </div>
  );
};

