        <div className="flex-1 overflow-y-auto p-6 space-y-8">
          {/* New Entry Form */}
          <section className="bg-blue-50/50 p-5 rounded-2xl border border-blue-100">
            <h4 className="text-sm font-bold text-blue-800 mb-4 uppercase tracking-wider">{t.newReport}</h4>
            <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 px-1">{t.workerName}</label>
                <input 
                  value={worker}
                  onChange={e => setWorker(e.target.value)}
                  className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none" 
                  placeholder={t.workerExample}
                />
              </div>
              <div className="space-y-1">
                <label className="text-xs font-semibold text-gray-500 px-1">{t.currentStatus}</label>
                <select 
                  value={status}
                  onChange={e => setStatus(e.target.value as TaskStatus)}
                  className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none bg-white"
                >
                  {Object.entries(STATUS_CONFIG).map(([s, cfg]) => (
                    <option key={s} value={s}>{(t as any)[cfg.labelKey]}</option>
                  ))}
                </select>
              </div>
              <div className="md:col-span-2 space-y-1">
                <label className="text-xs font-semibold text-gray-500 px-1">{t.whatWasDone}</label>
                <textarea 
                  value={desc}
                  onChange={e => setDesc(e.target.value)}
                  rows={2}
                  className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none resize-none"
                  placeholder={t.descriptionPlaceholder}
                />
              </div>
              <button 
                type="submit"
                className="md:col-span-2 bg-blue-600 text-white font-bold py-3 rounded-xl hover:bg-blue-700 transition-all shadow-lg active:scale-95"
              >
                {t.updateButton}
              </button>
            </form>
          </section>

          {/* History Timeline */}
          <section>
            <h4 className="text-sm font-bold text-gray-400 mb-6 uppercase tracking-wider">{t.workHistory}</h4>
            {unit.history.length === 0 ? (
              <div className="text-center py-10 text-gray-400 border-2 border-dashed rounded-2xl italic">{t.noHistory}</div>
            ) : (
              <div className={`space-y-6 relative before:absolute ${lang === 'ru' ? 'before:left-3' : 'before:right-3'} before:top-2 before:bottom-2 before:w-0.5 before:bg-gray-100`}>
