                    <div className={`absolute ${lang === 'ru' ? 'left-0' : 'right-0'} top-1 w-6 h-6 rounded-full border-4 border-white shadow-sm ${STATUS_CONFIG[log.status].color.split(' ')[0]}`}></div>
                    <div className={`bg-white border rounded-xl p-4 shadow-sm ${lang === 'ru' ? 'text-left' : 'text-right'}`}>
                      <div className="flex justify-between items-start mb-2 flex-wrap gap-2">
                        <span className="font-bold text-gray-800">{log.workerName}</span>
                        <span className="text-[10px] text-gray-400 bg-gray-50 px-2 py-1 rounded-md">
                          {new Date(log.timestamp).toLocaleString(lang === 'ru' ? 'ru-RU' : 'he-IL')}
                        </span>
                      </div>
                      <p className="text-sm text-gray-600 leading-relaxed whitespace-pre-wrap">{log.description}</p>
                      <div className="mt-3 inline-flex items-center gap-2">
                        <span className={`text-[10px] px-2 py-0.5 rounded-full border ${STATUS_CONFIG[log.status].color}`}>
