import { Language, translations } from '../translations';

interface Props {
  unit: Unit;
  onClose: () => void;
  onSave: (status: TaskStatus, worker: string, contractor: string, description: string) => void;
  lang: Language;
}

const UnitModal: React.FC<Props> = ({ unit, onClose, onSave, lang }) => {
  const [worker, setWorker] = useState('');
  const [desc, setDesc] = useState('');
  const [status, setStatus] = useState<TaskStatus>(unit.status);
  const [contractor, setContractor] = useState(CONTRACTORS[0].id);
  const t = translations[lang];

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!worker || !desc) return alert(t.alertFillFields);

    // Find the translated label for the selected contractor to save it
    const selectedContractor = (t as any)[CONTRACTORS.find(c => c.id === contractor)?.labelKey || ''];

    onSave(status, worker, selectedContractor, desc);
    setWorker('');
    setDesc('');
  };

  // Extract the specific ID part (after building prefix)
