export enum TaskStatus {
  NOT_STARTED = 'NOT_STARTED',
  IN_PROGRESS = 'IN_PROGRESS',
  DONE = 'DONE',
  NEEDS_FOLLOWUP = 'NEEDS_FOLLOWUP',
  BLOCKED = 'BLOCKED'
}

export type Discipline = 'plumbing' | 'general';

export interface TaskLog {
  id: string;
  timestamp: number;
  workerName: string;
  contractor: string;
  description: string;
  status: TaskStatus;
  discipline: Discipline; // New field to categorize the log
}

export interface Unit {
  id: string;
  buildingId: string;
  number: number;
  // Separate status for each discipline
  statuses: Record<Discipline, TaskStatus>;
  history: TaskLog[];
}

export interface Building {
  id: string;
  name: string;
  totalUnits: number;
}

export interface ProjectState {
  buildings: Building[];
  units: Record<string, Unit>;
}

import { ProjectState, Building, Unit, TaskStatus, TaskLog, Discipline } from '../types';
import { BUILDINGS_COUNT, UNITS_PER_BUILDING } from '../constants';

const STORAGE_KEY = 'plumbtrack_data_v1';

export const initializeData = (): ProjectState => {
  const saved = localStorage.getItem(STORAGE_KEY);
  if (saved) {
    return JSON.parse(saved);
  }

  const buildings: Building[] = Array.from({ length: BUILDINGS_COUNT }, (_, i) => ({
    id: `b-${i + 1}`,
    name: `בניין ${i + 1}`,
    totalUnits: UNITS_PER_BUILDING
  }));

  const initialState: ProjectState = {
    buildings,
    units: {}
  };

  return initialState;
};

export const saveData = (state: ProjectState) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(state));
};

export const getUnit = (state: ProjectState, buildingId: string, unitId: string | number): Unit => {
  const key = `${buildingId}-${unitId}`;
  if (state.units[key]) return state.units[key];

  return {
    id: key,
    buildingId,
    number: typeof unitId === 'number' ? unitId : 0,
    statuses: {
      plumbing: TaskStatus.NOT_STARTED,
      general: TaskStatus.NOT_STARTED
    },
    history: []
  };
};

export const updateUnit = (
  state: ProjectState, 
  unit: Unit, 
  newLog?: Omit<TaskLog, 'id' | 'timestamp'>
): ProjectState => {
  const newState = { ...state };
  const updatedUnit = { ...unit };

  if (newLog) {
    const logEntry: TaskLog = {
      ...newLog,
      id: Math.random().toString(36).substr(2, 9),
      timestamp: Date.now()
    };
    updatedUnit.history = [logEntry, ...updatedUnit.history];

    // Update the specific status for the discipline
    updatedUnit.statuses = {
      ...updatedUnit.statuses,
      [newLog.discipline]: newLog.status
    };
  }

  newState.units[unit.id] = updatedUnit;
  saveData(newState);
  return newState;
};

import React from 'react';
import { Building, ProjectState, Discipline } from '../types';
import { Language, translations } from '../translations';
import { getUnit } from '../services/dataService';

interface Props {
  buildings: Building[];
  selectedBuildingId: string | null;
  onSelect: (id: string) => void;
  state: ProjectState;
  lang: Language;
  discipline: Discipline;
}

const BuildingSelector: React.FC<Props> = ({ buildings, selectedBuildingId, onSelect, state, lang, discipline }) => {
  const t = translations[lang];

  const getCompletionStats = (buildingId: string) => {
    let completed = 0;
    for (let i = 1; i <= 50; i++) {
      const unit = getUnit(state, buildingId, i);
      if (unit.statuses[discipline] === 'DONE') completed++;
    }
    return Math.round((completed / 50) * 100);
  };

  return (
    <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-6 gap-3 p-4">
      {buildings.map((b) => {
        const progress = getCompletionStats(b.id);
        const isActive = selectedBuildingId === b.id;
        const buildingName = lang === 'ru' ? b.name.replace('בניין', 'Здание') : b.name;

        return (
          <button
            key={b.id}
            onClick={() => onSelect(b.id)}
            className={`flex flex-col items-center justify-center p-4 rounded-xl transition-all border-2 shadow-sm ${
              isActive 
                ? 'bg-blue-600 border-blue-700 text-white transform scale-105 z-10' 
                : 'bg-white border-gray-100 hover:border-blue-300 text-gray-700'
            }`}
          >
            <span className="text-lg font-bold whitespace-nowrap">{buildingName}</span>
            <div className="w-full mt-2 h-1.5 bg-gray-200 rounded-full overflow-hidden">
              <div 
                className={`h-full rounded-full transition-all ${isActive ? 'bg-white' : 'bg-blue-500'}`} 
                style={{ width: `${progress}%` }}
              />
            </div>
            <span className={`text-[10px] mt-1 ${isActive ? 'text-blue-100' : 'text-gray-400'}`}>
              {progress}% {t.completed}
            </span>
          </button>
        );
      })}
    </div>
  );
};

