  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!worker || !desc) return alert(t.alertFillFields);

    const selectedContractor = (t as any)[CONTRACTORS.find(c => c.id === contractor)?.labelKey || ''];

    onSave(status, worker, selectedContractor, desc, reportDiscipline);
    setWorker('');
    setDesc('');
