    newLog?: { status: TaskStatus, worker: string, contractor: string, description: string, discipline: Discipline },
    newAppointment?: Omit<Appointment, 'id' | 'createdAt' | 'isCompleted'>,
    completeAppointmentId?: string
  }) => void;
