        {/* Header */}
        <div className="p-6 border-b flex justify-between items-center bg-gray-50">
          <div className={lang === 'ru' ? 'text-left' : 'text-right'}>
            <h3 className="text-2xl font-bold text-gray-800">{displayName}</h3>
            <p className="text-sm text-gray-500">{t.building}: {unit.buildingId.split('-')[1]}</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-200 rounded-full transition-colors text-2xl leading-none">&times;</button>
        </div>

        {/* Modal Tabs */}
        <div className="flex border-b">
          <button 
            onClick={() => setActiveTab('report')}
            className={`flex-1 py-3 font-bold text-sm transition-all ${activeTab === 'report' ? 'text-blue-600 border-b-2 border-blue-600 bg-blue-50/30' : 'text-gray-400'}`}
          >
            📋 {t.newReport}
          </button>
          <button 
            onClick={() => setActiveTab('schedule')}
            className={`flex-1 py-3 font-bold text-sm transition-all ${activeTab === 'schedule' ? 'text-blue-600 border-b-2 border-blue-600 bg-blue-50/30' : 'text-gray-400'}`}
          >
            📅 {t.viewSchedule}
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-8">
          {activeTab === 'report' ? (
            <>
              <section className="bg-blue-50/50 p-5 rounded-2xl border border-blue-100 shadow-inner">
                <form onSubmit={handleReportSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.disciplineLabel}</label>
                    <div className="flex bg-white rounded-xl border p-1">
                      <button type="button" onClick={() => setReportDiscipline('plumbing')} className={`flex-1 py-1 rounded-lg text-xs font-bold transition-all ${reportDiscipline === 'plumbing' ? 'bg-blue-600 text-white' : 'text-gray-400'}`}>{t.tabPlumbing}</button>
                      <button type="button" onClick={() => setReportDiscipline('general')} className={`flex-1 py-1 rounded-lg text-xs font-bold transition-all ${reportDiscipline === 'general' ? 'bg-blue-600 text-white' : 'text-gray-400'}`}>{t.tabGeneral}</button>
                    </div>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.contractorLabel}</label>
                    <select value={contractor} onChange={e => setContractor(e.target.value)} className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none bg-white">
                      {CONTRACTORS.map(c => <option key={c.id} value={c.id}>{c.icon} {(t as any)[c.labelKey]}</option>)}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.workerName}</label>
                    <input value={worker} onChange={e => setWorker(e.target.value)} className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none" placeholder={t.workerExample} />
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.currentStatus}</label>
                    <select value={status} onChange={e => setStatus(e.target.value as TaskStatus)} className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none bg-white">
                      {Object.entries(STATUS_CONFIG).map(([s, cfg]) => <option key={s} value={s}>{(t as any)[cfg.labelKey]}</option>)}
                    </select>
                  </div>
                  <div className="md:col-span-2 space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.whatWasDone}</label>
                    <textarea value={desc} onChange={e => setDesc(e.target.value)} rows={2} className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none resize-none" placeholder={t.descriptionPlaceholder} />
                  </div>
                  <button type="submit" className="md:col-span-2 bg-blue-600 text-white font-bold py-3 rounded-xl hover:bg-blue-700 transition-all shadow-lg active:scale-95">{t.updateButton}</button>
                </form>
              </section>

              <section>
                <h4 className="text-sm font-bold text-gray-400 mb-6 uppercase tracking-wider">{t.workHistory}</h4>
                {unit.history.length === 0 ? <div className="text-center py-10 text-gray-400 border-2 border-dashed rounded-2xl italic">{t.noHistory}</div> : (
                  <div className={`space-y-6 relative before:absolute ${lang === 'ru' ? 'before:left-3' : 'before:right-3'} before:top-2 before:bottom-2 before:w-0.5 before:bg-gray-100`}>
                    {unit.history.map((log) => (
                      <div key={log.id} className={`relative ${lang === 'ru' ? 'pl-10' : 'pr-10'}`}>
                        <div className={`absolute ${lang === 'ru' ? 'left-0' : 'right-0'} top-1 w-6 h-6 rounded-full border-4 border-white shadow-sm ${STATUS_CONFIG[log.status].color.split(' ')[0]}`}></div>
                        <div className={`bg-white border rounded-xl p-4 shadow-sm ${lang === 'ru' ? 'text-left' : 'text-right'}`}>
                          <div className="flex justify-between items-start mb-1 flex-wrap gap-2">
                            <div className="flex flex-col">
                              <span className="font-bold text-gray-800">{log.workerName}</span>
                              <div className="flex items-center gap-2">
                                <span className="text-[10px] text-blue-600 font-semibold">{log.contractor}</span>
                                <span className={`text-[9px] px-1.5 py-0.5 rounded bg-gray-100 text-gray-500 border`}>{(t as any)[log.discipline === 'plumbing' ? 'tabPlumbing' : 'tabGeneral']}</span>
                              </div>
                            </div>
                            <span className="text-[10px] text-gray-400 bg-gray-50 px-2 py-1 rounded-md">{new Date(log.timestamp).toLocaleString(lang === 'ru' ? 'ru-RU' : 'he-IL')}</span>
                          </div>
                          <p className="text-sm text-gray-600 leading-relaxed whitespace-pre-wrap">{log.description}</p>
                          <div className="mt-3"><span className={`text-[10px] px-2 py-0.5 rounded-full border ${STATUS_CONFIG[log.status].color}`}>{(t as any)[STATUS_CONFIG[log.status].labelKey]}</span></div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </section>
            </>
          ) : (
            <>
              <section className="bg-yellow-50/50 p-5 rounded-2xl border border-yellow-100 shadow-inner">
                <h4 className="text-sm font-bold text-yellow-800 mb-4 uppercase tracking-wider">{t.scheduleTitle}</h4>
                <form onSubmit={handleAppSubmit} className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.dateLabel}</label>
                    <input type="date" value={appDate} onChange={e => setAppDate(e.target.value)} className="w-full px-4 py-2 rounded-xl border border-gray-200 outline-none" />
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.timeLabel}</label>
                    <input type="time" value={appTime} onChange={e => setAppTime(e.target.value)} className="w-full px-4 py-2 rounded-xl border border-gray-200 outline-none" />
                  </div>
                  <div className="col-span-2 space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.tenantLabel}</label>
                    <input type="text" value={appTenant} onChange={e => setAppTenant(e.target.value)} className="w-full px-4 py-2 rounded-xl border border-gray-200 outline-none" placeholder="למשל: משפחת כהן" />
                  </div>
                  <div className="col-span-2 space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.notesLabel}</label>
                    <textarea value={appNotes} onChange={e => setAppNotes(e.target.value)} rows={2} className="w-full px-4 py-2 rounded-xl border border-gray-200 outline-none resize-none" />
                  </div>
                  <button type="submit" className="col-span-2 bg-yellow-600 text-white font-bold py-3 rounded-xl hover:bg-yellow-700 transition-all shadow-lg active:scale-95">{t.addAppointment}</button>
                </form>
              </section>

              <section>
                <h4 className="text-sm font-bold text-gray-400 mb-4 uppercase tracking-wider">{t.upcomingAppointments}</h4>
                {unit.appointments.length === 0 ? <div className="text-center py-10 text-gray-400 border-2 border-dashed rounded-2xl italic">{t.noAppointments}</div> : (
                  <div className="space-y-3">
                    {unit.appointments.map(app => (
                      <div key={app.id} className={`p-4 rounded-xl border-2 flex justify-between items-center ${app.isCompleted ? 'bg-gray-50 border-gray-100 opacity-60' : 'bg-white border-blue-100 shadow-sm'}`}>
                        <div>
                          <div className="flex items-center gap-2 mb-1">
                            <span className="text-lg font-bold text-blue-900">{app.time}</span>
                            <span className="text-xs font-bold text-gray-400">{app.date}</span>
                          </div>
                          <div className="text-sm font-bold text-gray-800">{app.tenantName}</div>
                          <div className="text-xs text-gray-500 italic">{app.notes}</div>
                        </div>
                        {!app.isCompleted && (
                          <button 
                            onClick={() => onSave({ completeAppointmentId: app.id })}
                            className="bg-green-100 text-green-700 px-3 py-1.5 rounded-lg text-xs font-bold hover:bg-green-200"
                          >
                            ✔️ {t.appointmentDone}
                          </button>
                        )}
                      </div>
                    ))}
                  </div>
                )}
              </section>
            </>
          )}
        </div>
      </div>
    </div>
  );
};

export default UnitModal;

import React, { useState, useEffect, useMemo } from 'react';
import { ProjectState, TaskStatus, Unit, Discipline, Appointment } from './types';
import { initializeData, getUnit, updateUnit } from './services/dataService';
import BuildingSelector from './components/BuildingSelector';
import UnitGrid from './components/UnitGrid';
import UnitModal from './components/UnitModal';
import ContractorView from './components/ContractorView';
import ScheduleView from './components/ScheduleView';
import { Language, translations } from './translations';
import { PUBLIC_AREAS, STATUS_CONFIG } from './constants';

const App: React.FC = () => {
  const [state, setState] = useState<ProjectState>(() => initializeData());
  const [selectedBuildingId, setSelectedBuildingId] = useState<string | null>(null);
  const [selectedUnitId, setSelectedUnitId] = useState<string | number | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'units' | 'public' | 'contractors' | 'schedule'>('units');
  const [activeDiscipline, setActiveDiscipline] = useState<Discipline>('general');

  const [lang, setLang] = useState<Language>(() => {
    return (localStorage.getItem('app_lang') as Language) || 'he';
  });

  useEffect(() => {
    localStorage.setItem('app_lang', lang);
    document.documentElement.dir = lang === 'he' ? 'rtl' : 'ltr';
    document.documentElement.lang = lang;
  }, [lang]);

  const t = translations[lang];

  useEffect(() => {
    if (!selectedBuildingId && state.buildings.length > 0) {
      setSelectedBuildingId(state.buildings[0].id);
    }
  }, [state.buildings, selectedBuildingId]);

  const activeUnit = useMemo(() => {
    if (!selectedBuildingId || selectedUnitId === null) return null;
    return getUnit(state, selectedBuildingId, selectedUnitId);
  }, [state, selectedBuildingId, selectedUnitId]);

  const handleUpdateUnit = (updates: { 
    newLog?: { status: TaskStatus, worker: string, contractor: string, description: string, discipline: Discipline },
    newAppointment?: Omit<Appointment, 'id' | 'createdAt' | 'isCompleted'>,
    completeAppointmentId?: string
  }) => {
    if (!activeUnit) return;
    const newState = updateUnit(state, activeUnit, {
      newLog: updates.newLog,
      newAppointment: updates.newAppointment,
      completeAppointmentId: updates.completeAppointmentId
    });
    setState(newState);
  };

  const filteredBuildings = state.buildings.filter(b => {
    const buildingName = lang === 'ru' ? b.name.replace('בניין', 'Здание') : b.name;
    return buildingName.includes(searchTerm) || b.id.includes(searchTerm) || b.name.includes(searchTerm);
  });

  const toggleLanguage = () => {
    setLang(prev => prev === 'he' ? 'ru' : 'he');
  };

  const handleSelectFromOtherView = (buildingId: string, unitId: string | number) => {
    setSelectedBuildingId(buildingId);
    setSelectedUnitId(unitId);
  };

  return (
    <div className={`min-h-screen bg-slate-50 ${lang === 'ru' ? 'text-left' : 'text-right'}`} dir={lang === 'he' ? 'rtl' : 'ltr'}>
      <header className="sticky top-0 z-40 bg-blue-900 text-white shadow-lg p-4">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-3 w-full md:w-auto">
            <div className="bg-white p-2 px-3 rounded-lg text-blue-900 text-xl font-black">בדק</div>
            <div className="flex-1">
              <h1 className="text-xl font-bold leading-none">{t.appName}</h1>
              <p className="text-[10px] text-blue-200 mt-1 uppercase tracking-widest font-medium">{t.appSubName}</p>
            </div>
            <button onClick={toggleLanguage} className="md:hidden bg-blue-800 hover:bg-blue-700 px-3 py-1 rounded-full text-xs font-bold transition-colors border border-blue-600">
              {t.langToggle}
            </button>
          </div>

          <div className="flex items-center gap-4 w-full md:w-auto">
            <div className="flex-1 md:w-64 relative">
              <input type="text" placeholder={t.searchPlaceholder} value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className={`w-full bg-blue-800/50 border border-blue-400/30 rounded-full ${lang === 'ru' ? 'pl-10 pr-4' : 'pr-10 pl-4'} py-2 text-sm placeholder:text-blue-300 outline-none focus:ring-2 focus:ring-white/30`} />
              <span className={`absolute ${lang === 'ru' ? 'right-3' : 'right-3'} top-2.5 opacity-50`}>🔍</span>
            </div>
            <button onClick={toggleLanguage} className="hidden md:block bg-blue-800 hover:bg-blue-700 px-4 py-2 rounded-full text-sm font-bold transition-colors border border-blue-600 shadow-inner">
              {t.langToggle}
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto pb-20 px-4">
        {/* Navigation Tabs */}
        <div className="flex gap-2 my-6 bg-gray-200/50 p-1 rounded-xl w-full overflow-x-auto no-scrollbar md:w-fit mx-auto md:mx-0">
          <button onClick={() => setViewMode('units')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2 rounded-lg font-bold transition-all ${viewMode === 'units' ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewUnits}</button>
          <button onClick={() => setViewMode('public')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2 rounded-lg font-bold transition-all ${viewMode === 'public' ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewPublic}</button>
          <button onClick={() => setViewMode('contractors')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2 rounded-lg font-bold transition-all ${viewMode === 'contractors' ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewContractors}</button>
          <button onClick={() => setViewMode('schedule')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2 rounded-lg font-bold transition-all ${viewMode === 'schedule' ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewSchedule}</button>
        </div>

        {viewMode === 'contractors' ? (
          <ContractorView state={state} lang={lang} onSelectUnit={handleSelectFromOtherView} />
        ) : viewMode === 'schedule' ? (
          <ScheduleView state={state} lang={lang} onSelectUnit={handleSelectFromOtherView} />
        ) : (
          <>
            {/* Discipline Tabs */}
            <div className="flex justify-center mb-6">
              <div className="bg-white p-1.5 rounded-2xl shadow-md border flex gap-1 w-full max-w-md">
                <button onClick={() => setActiveDiscipline('general')} className={`flex-1 py-3 px-4 rounded-xl font-bold transition-all flex items-center justify-center gap-2 ${activeDiscipline === 'general' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500 hover:bg-gray-50'}`}>🛠️ {t.tabGeneral}</button>
                <button onClick={() => setActiveDiscipline('plumbing')} className={`flex-1 py-3 px-4 rounded-xl font-bold transition-all flex items-center justify-center gap-2 ${activeDiscipline === 'plumbing' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500 hover:bg-gray-50'}`}>🚰 {t.tabPlumbing}</button>
              </div>
            </div>

            <section className="mt-8">
              <BuildingSelector buildings={filteredBuildings} selectedBuildingId={selectedBuildingId} onSelect={setSelectedBuildingId} state={state} lang={lang} discipline={activeDiscipline} />
            </section>

            {selectedBuildingId && (
              <section className="mt-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
                {viewMode === 'units' ? (
                  <UnitGrid buildingId={selectedBuildingId} state={state} onSelectUnit={(num) => setSelectedUnitId(num)} lang={lang} discipline={activeDiscipline} />
                ) : (
                  <div className="bg-white rounded-2xl shadow-sm p-6 border border-gray-100">
                    <h2 className="text-xl font-bold text-gray-800 mb-6">{t.publicAreas}</h2>
                    <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4">
                      {PUBLIC_AREAS.map(area => {
                        const unitData = getUnit(state, selectedBuildingId, area.id);
                        const currentStatus = unitData.statuses[activeDiscipline];
                        const config = STATUS_CONFIG[currentStatus];
                        return (
                          <button key={area.id} onClick={() => setSelectedUnitId(area.id)} className={`flex items-center gap-4 p-4 rounded-xl border-2 transition-all hover:shadow-md active:scale-95 text-right ${config.color}`}>
                            <span className="text-3xl">{area.icon}</span>
                            <div className="flex flex-col">
                              <span className="font-bold text-lg">{(t as any)[area.labelKey]}</span>
                              <span className="text-xs opacity-70">{(t as any)[config.labelKey]}</span>
                            </div>
                          </button>
                        );
                      })}
                    </div>
                  </div>
                )}
              </section>
            )}
          </>
        )}
      </main>

      {activeUnit && (
        <UnitModal unit={activeUnit} onClose={() => setSelectedUnitId(null)} onSave={handleUpdateUnit} lang={lang} activeDiscipline={activeDiscipline} />
      )}

      <footer className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-md border-t p-3 text-center text-[10px] text-gray-400 z-30">
        {t.footerInfo}
      </footer>
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { Unit, TaskStatus, Discipline, Appointment } from '../types';
import { STATUS_CONFIG, PUBLIC_AREAS, CONTRACTORS } from '../constants';
import { Language, translations } from '../translations';

interface Props {
  unit: Unit;
  onClose: () => void;
  onSave: (updates: { 
    // Fix: Changed 'worker' to 'workerName' to align with the TaskLog interface defined in types.ts
    newLog?: { status: TaskStatus, workerName: string, contractor: string, description: string, discipline: Discipline },
    newAppointment?: Omit<Appointment, 'id' | 'createdAt' | 'isCompleted'>,
    completeAppointmentId?: string
  }) => void;
  lang: Language;
  activeDiscipline: Discipline;
}

const UnitModal: React.FC<Props> = ({ unit, onClose, onSave, lang, activeDiscipline }) => {
  const [activeTab, setActiveTab] = useState<'report' | 'schedule'>('report');
  const [worker, setWorker] = useState('');
  const [desc, setDesc] = useState('');
  const [status, setStatus] = useState<TaskStatus>(unit.statuses[activeDiscipline]);
  const [contractor, setContractor] = useState(CONTRACTORS[0].id);
  const [reportDiscipline, setReportDiscipline] = useState<Discipline>(activeDiscipline);

  // Appointment Form State
  const [appDate, setAppDate] = useState('');
  const [appTime, setAppTime] = useState('');
  const [appTenant, setAppTenant] = useState('');
  const [appNotes, setAppNotes] = useState('');

  const t = translations[lang];

  const handleReportSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!worker || !desc) return alert(t.alertFillFields);
    const selectedContractor = (t as any)[CONTRACTORS.find(c => c.id === contractor)?.labelKey || ''];
    // Fix: Updated object property from 'worker' to 'workerName' to satisfy Type compatibility
    onSave({ 
      newLog: { status, workerName: worker, contractor: selectedContractor, description: desc, discipline: reportDiscipline } 
    });
    setWorker('');
    setDesc('');
  };

  const handleAppSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!appDate || !appTime || !appTenant) return alert(t.alertFillFields);
    onSave({ 
      newAppointment: { date: appDate, time: appTime, tenantName: appTenant, notes: appNotes } 
    });
    setAppDate('');
    setAppTime('');
    setAppTenant('');
    setAppNotes('');
  };

  const unitIdentifier = unit.id.split('-').slice(1).join('-');
  const isPublicArea = isNaN(Number(unitIdentifier));
  const publicAreaConfig = isPublicArea ? PUBLIC_AREAS.find(a => a.id === unitIdentifier) : null;
  const displayName = isPublicArea 
    ? (t as any)[publicAreaConfig?.labelKey || ''] 
    : `${t.apartment} ${unitIdentifier}`;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
      <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
        {/* Header */}
        <div className="p-6 border-b flex justify-between items-center bg-gray-50">
          <div className={lang === 'ru' ? 'text-left' : 'text-right'}>
            <h3 className="text-2xl font-bold text-gray-800">{displayName}</h3>
            <p className="text-sm text-gray-500">{t.building}: {unit.buildingId.split('-')[1]}</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-200 rounded-full transition-colors text-2xl leading-none">&times;</button>
        </div>

        {/* Modal Tabs */}
        <div className="flex border-b">
          <button 
            onClick={() => setActiveTab('report')}
            className={`flex-1 py-3 font-bold text-sm transition-all ${activeTab === 'report' ? 'text-blue-600 border-b-2 border-blue-600 bg-blue-50/30' : 'text-gray-400'}`}
          >
            📋 {t.newReport}
          </button>
          <button 
            onClick={() => setActiveTab('schedule')}
            className={`flex-1 py-3 font-bold text-sm transition-all ${activeTab === 'schedule' ? 'text-blue-600 border-b-2 border-blue-600 bg-blue-50/30' : 'text-gray-400'}`}
          >
            📅 {t.viewSchedule}
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-8">
          {activeTab === 'report' ? (
            <>
              <section className="bg-blue-50/50 p-5 rounded-2xl border border-blue-100 shadow-inner">
                <form onSubmit={handleReportSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.disciplineLabel}</label>
                    <div className="flex bg-white rounded-xl border p-1">
                      <button type="button" onClick={() => setReportDiscipline('plumbing')} className={`flex-1 py-1 rounded-lg text-xs font-bold transition-all ${reportDiscipline === 'plumbing' ? 'bg-blue-600 text-white' : 'text-gray-400'}`}>{t.tabPlumbing}</button>
                      <button type="button" onClick={() => setReportDiscipline('general')} className={`flex-1 py-1 rounded-lg text-xs font-bold transition-all ${reportDiscipline === 'general' ? 'bg-blue-600 text-white' : 'text-gray-400'}`}>{t.tabGeneral}</button>
                    </div>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.contractorLabel}</label>
                    <select value={contractor} onChange={e => setContractor(e.target.value)} className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none bg-white">
                      {CONTRACTORS.map(c => <option key={c.id} value={c.id}>{c.icon} {(t as any)[c.labelKey]}</option>)}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.workerName}</label>
                    <input value={worker} onChange={e => setWorker(e.target.value)} className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none" placeholder={t.workerExample} />
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.currentStatus}</label>
                    <select value={status} onChange={e => setStatus(e.target.value as TaskStatus)} className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none bg-white">
                      {Object.entries(STATUS_CONFIG).map(([s, cfg]) => <option key={s} value={s}>{(t as any)[cfg.labelKey]}</option>)}
                    </select>
                  </div>
                  <div className="md:col-span-2 space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.whatWasDone}</label>
                    <textarea value={desc} onChange={e => setDesc(e.target.value)} rows={2} className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none resize-none" placeholder={t.descriptionPlaceholder} />
                  </div>
                  <button type="submit" className="md:col-span-2 bg-blue-600 text-white font-bold py-3 rounded-xl hover:bg-blue-700 transition-all shadow-lg active:scale-95">{t.updateButton}</button>
                </form>
              </section>

              <section>
                <h4 className="text-sm font-bold text-gray-400 mb-6 uppercase tracking-wider">{t.workHistory}</h4>
                {unit.history.length === 0 ? <div className="text-center py-10 text-gray-400 border-2 border-dashed rounded-2xl italic">{t.noHistory}</div> : (
                  <div className={`space-y-6 relative before:absolute ${lang === 'ru' ? 'before:left-3' : 'before:right-3'} before:top-2 before:bottom-2 before:w-0.5 before:bg-gray-100`}>
                    {unit.history.map((log) => (
                      <div key={log.id} className={`relative ${lang === 'ru' ? 'pl-10' : 'pr-10'}`}>
                        <div className={`absolute ${lang === 'ru' ? 'left-0' : 'right-0'} top-1 w-6 h-6 rounded-full border-4 border-white shadow-sm ${STATUS_CONFIG[log.status].color.split(' ')[0]}`}></div>
                        <div className={`bg-white border rounded-xl p-4 shadow-sm ${lang === 'ru' ? 'text-left' : 'text-right'}`}>
                          <div className="flex justify-between items-start mb-1 flex-wrap gap-2">
                            <div className="flex flex-col">
                              <span className="font-bold text-gray-800">{log.workerName}</span>
                              <div className="flex items-center gap-2">
                                <span className="text-[10px] text-blue-600 font-semibold">{log.contractor}</span>
                                <span className={`text-[9px] px-1.5 py-0.5 rounded bg-gray-100 text-gray-500 border`}>{(t as any)[log.discipline === 'plumbing' ? 'tabPlumbing' : 'tabGeneral']}</span>
                              </div>
                            </div>
                            <span className="text-[10px] text-gray-400 bg-gray-50 px-2 py-1 rounded-md">{new Date(log.timestamp).toLocaleString(lang === 'ru' ? 'ru-RU' : 'he-IL')}</span>
                          </div>
                          <p className="text-sm text-gray-600 leading-relaxed whitespace-pre-wrap">{log.description}</p>
                          <div className="mt-3"><span className={`text-[10px] px-2 py-0.5 rounded-full border ${STATUS_CONFIG[log.status].color}`}>{(t as any)[STATUS_CONFIG[log.status].labelKey]}</span></div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </section>
            </>
          ) : (
            <>
              <section className="bg-yellow-50/50 p-5 rounded-2xl border border-yellow-100 shadow-inner">
                <h4 className="text-sm font-bold text-yellow-800 mb-4 uppercase tracking-wider">{t.scheduleTitle}</h4>
                <form onSubmit={handleAppSubmit} className="grid grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.dateLabel}</label>
                    <input type="date" value={appDate} onChange={e => setAppDate(e.target.value)} className="w-full px-4 py-2 rounded-xl border border-gray-200 outline-none" />
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.timeLabel}</label>
                    <input type="time" value={appTime} onChange={e => setAppTime(e.target.value)} className="w-full px-4 py-2 rounded-xl border border-gray-200 outline-none" />
                  </div>
                  <div className="col-span-2 space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.tenantLabel}</label>
                    <input type="text" value={appTenant} onChange={e => setAppTenant(e.target.value)} className="w-full px-4 py-2 rounded-xl border border-gray-200 outline-none" placeholder="למשל: משפחת כהן" />
                  </div>
                  <div className="col-span-2 space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.notesLabel}</label>
                    <textarea value={appNotes} onChange={e => setAppNotes(e.target.value)} rows={2} className="w-full px-4 py-2 rounded-xl border border-gray-200 outline-none resize-none" />
                  </div>
                  <button type="submit" className="col-span-2 bg-yellow-600 text-white font-bold py-3 rounded-xl hover:bg-yellow-700 transition-all shadow-lg active:scale-95">{t.addAppointment}</button>
                </form>
              </section>

              <section>
                <h4 className="text-sm font-bold text-gray-400 mb-4 uppercase tracking-wider">{t.upcomingAppointments}</h4>
                {unit.appointments.length === 0 ? <div className="text-center py-10 text-gray-400 border-2 border-dashed rounded-2xl italic">{t.noAppointments}</div> : (
                  <div className="space-y-3">
                    {unit.appointments.map(app => (
                      <div key={app.id} className={`p-4 rounded-xl border-2 flex justify-between items-center ${app.isCompleted ? 'bg-gray-50 border-gray-100 opacity-60' : 'bg-white border-blue-100 shadow-sm'}`}>
                        <div>
                          <div className="flex items-center gap-2 mb-1">
                            <span className="text-lg font-bold text-blue-900">{app.time}</span>
                            <span className="text-xs font-bold text-gray-400">{app.date}</span>
                          </div>
                          <div className="text-sm font-bold text-gray-800">{app.tenantName}</div>
                          <div className="text-xs text-gray-500 italic">{app.notes}</div>
                        </div>
                        {!app.isCompleted && (
                          <button 
                            onClick={() => onSave({ completeAppointmentId: app.id })}
                            className="bg-green-100 text-green-700 px-3 py-1.5 rounded-lg text-xs font-bold hover:bg-green-200"
                          >
                            ✔️ {t.appointmentDone}
                          </button>
                        )}
                      </div>
                    ))}
                  </div>
                )}
              </section>
            </>
          )}
        </div>
      </div>
    </div>
  );
};

export default UnitModal;

import React, { useState, useEffect, useMemo } from 'react';
import { ProjectState, TaskStatus, Unit, Discipline, Appointment } from './types';
import { initializeData, getUnit, updateUnit } from './services/dataService';
import BuildingSelector from './components/BuildingSelector';
import UnitGrid from './components/UnitGrid';
import UnitModal from './components/UnitModal';
import ContractorView from './components/ContractorView';
import ScheduleView from './components/ScheduleView';
import { Language, translations } from './translations';
import { PUBLIC_AREAS, STATUS_CONFIG } from './constants';

const App: React.FC = () => {
  const [state, setState] = useState<ProjectState>(() => initializeData());
  const [selectedBuildingId, setSelectedBuildingId] = useState<string | null>(null);
  const [selectedUnitId, setSelectedUnitId] = useState<string | number | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'units' | 'public' | 'contractors' | 'schedule'>('units');
  const [activeDiscipline, setActiveDiscipline] = useState<Discipline>('general');

  const [lang, setLang] = useState<Language>(() => {
    return (localStorage.getItem('app_lang') as Language) || 'he';
  });

  useEffect(() => {
    localStorage.setItem('app_lang', lang);
    document.documentElement.dir = lang === 'he' ? 'rtl' : 'ltr';
    document.documentElement.lang = lang;
  }, [lang]);

  const t = translations[lang];

  useEffect(() => {
    if (!selectedBuildingId && state.buildings.length > 0) {
      setSelectedBuildingId(state.buildings[0].id);
    }
  }, [state.buildings, selectedBuildingId]);

  const activeUnit = useMemo(() => {
    if (!selectedBuildingId || selectedUnitId === null) return null;
    return getUnit(state, selectedBuildingId, selectedUnitId);
  }, [state, selectedBuildingId, selectedUnitId]);

  const handleUpdateUnit = (updates: { 
    // Fix: Rename 'worker' to 'workerName' to match the TaskLog interface expected by updateUnit
    newLog?: { status: TaskStatus, workerName: string, contractor: string, description: string, discipline: Discipline },
    newAppointment?: Omit<Appointment, 'id' | 'createdAt' | 'isCompleted'>,
    completeAppointmentId?: string
  }) => {
    if (!activeUnit) return;
    const newState = updateUnit(state, activeUnit, {
      newLog: updates.newLog,
      newAppointment: updates.newAppointment,
      completeAppointmentId: updates.completeAppointmentId
    });
    setState(newState);
  };

  const filteredBuildings = state.buildings.filter(b => {
    const buildingName = lang === 'ru' ? b.name.replace('בניין', 'Здание') : b.name;
    return buildingName.includes(searchTerm) || b.id.includes(searchTerm) || b.name.includes(searchTerm);
  });

  const toggleLanguage = () => {
    setLang(prev => prev === 'he' ? 'ru' : 'he');
  };

  const handleSelectFromOtherView = (buildingId: string, unitId: string | number) => {
    setSelectedBuildingId(buildingId);
    setSelectedUnitId(unitId);
  };

  return (
    <div className={`min-h-screen bg-slate-50 ${lang === 'ru' ? 'text-left' : 'text-right'}`} dir={lang === 'he' ? 'rtl' : 'ltr'}>
      <header className="sticky top-0 z-40 bg-blue-900 text-white shadow-lg p-4">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-3 w-full md:w-auto">
            <div className="bg-white p-2 px-3 rounded-lg text-blue-900 text-xl font-black">בדק</div>
            <div className="flex-1">
              <h1 className="text-xl font-bold leading-none">{t.appName}</h1>
              <p className="text-[10px] text-blue-200 mt-1 uppercase tracking-widest font-medium">{t.appSubName}</p>
            </div>
            <button onClick={toggleLanguage} className="md:hidden bg-blue-800 hover:bg-blue-700 px-3 py-1 rounded-full text-xs font-bold transition-colors border border-blue-600">
              {t.langToggle}
            </button>
          </div>

          <div className="flex items-center gap-4 w-full md:w-auto">
            <div className="flex-1 md:w-64 relative">
              <input type="text" placeholder={t.searchPlaceholder} value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className={`w-full bg-blue-800/50 border border-blue-400/30 rounded-full ${lang === 'ru' ? 'pl-10 pr-4' : 'pr-10 pl-4'} py-2 text-sm placeholder:text-blue-300 outline-none focus:ring-2 focus:ring-white/30`} />
              <span className={`absolute ${lang === 'ru' ? 'right-3' : 'right-3'} top-2.5 opacity-50`}>🔍</span>
            </div>
            <button onClick={toggleLanguage} className="hidden md:block bg-blue-800 hover:bg-blue-700 px-4 py-2 rounded-full text-sm font-bold transition-colors border border-blue-600 shadow-inner">
              {t.langToggle}
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto pb-20 px-4">
        {/* Navigation Tabs */}
        <div className="flex gap-2 my-6 bg-gray-200/50 p-1 rounded-xl w-full overflow-x-auto no-scrollbar md:w-fit mx-auto md:mx-0">
          <button onClick={() => setViewMode('units')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2 rounded-lg font-bold transition-all ${viewMode === 'units' ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewUnits}</button>
          <button onClick={() => setViewMode('public')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2 rounded-lg font-bold transition-all ${viewMode === 'public' ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewPublic}</button>
          <button onClick={() => setViewMode('contractors')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2 rounded-lg font-bold transition-all ${viewMode === 'contractors' ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewContractors}</button>
          <button onClick={() => setViewMode('schedule')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2 rounded-lg font-bold transition-all ${viewMode === 'schedule' ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewSchedule}</button>
        </div>

        {viewMode === 'contractors' ? (
          <ContractorView state={state} lang={lang} onSelectUnit={handleSelectFromOtherView} />
        ) : viewMode === 'schedule' ? (
          <ScheduleView state={state} lang={lang} onSelectUnit={handleSelectFromOtherView} />
        ) : (
          <>
            {/* Discipline Tabs */}
            <div className="flex justify-center mb-6">
              <div className="bg-white p-1.5 rounded-2xl shadow-md border flex gap-1 w-full max-w-md">
                <button onClick={() => setActiveDiscipline('general')} className={`flex-1 py-3 px-4 rounded-xl font-bold transition-all flex items-center justify-center gap-2 ${activeDiscipline === 'general' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500 hover:bg-gray-50'}`}>🛠️ {t.tabGeneral}</button>
                <button onClick={() => setActiveDiscipline('plumbing')} className={`flex-1 py-3 px-4 rounded-xl font-bold transition-all flex items-center justify-center gap-2 ${activeDiscipline === 'plumbing' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500 hover:bg-gray-50'}`}>🚰 {t.tabPlumbing}</button>
              </div>
            </div>

            <section className="mt-8">
              <BuildingSelector buildings={filteredBuildings} selectedBuildingId={selectedBuildingId} onSelect={setSelectedBuildingId} state={state} lang={lang} discipline={activeDiscipline} />
            </section>

            {selectedBuildingId && (
              <section className="mt-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
                {viewMode === 'units' ? (
                  <UnitGrid buildingId={selectedBuildingId} state={state} onSelectUnit={(num) => setSelectedUnitId(num)} lang={lang} discipline={activeDiscipline} />
                ) : (
                  <div className="bg-white rounded-2xl shadow-sm p-6 border border-gray-100">
                    <h2 className="text-xl font-bold text-gray-800 mb-6">{t.publicAreas}</h2>
                    <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4">
                      {PUBLIC_AREAS.map(area => {
                        const unitData = getUnit(state, selectedBuildingId, area.id);
                        const currentStatus = unitData.statuses[activeDiscipline];
                        const config = STATUS_CONFIG[currentStatus];
                        return (
                          <button key={area.id} onClick={() => setSelectedUnitId(area.id)} className={`flex items-center gap-4 p-4 rounded-xl border-2 transition-all hover:shadow-md active:scale-95 text-right ${config.color}`}>
                            <span className="text-3xl">{area.icon}</span>
                            <div className="flex flex-col">
                              <span className="font-bold text-lg">{(t as any)[area.labelKey]}</span>
                              <span className="text-xs opacity-70">{(t as any)[config.labelKey]}</span>
                            </div>
                          </button>
                        );
                      })}
                    </div>
                  </div>
                )}
              </section>
            )}
          </>
        )}
      </main>

      {activeUnit && (
        <UnitModal unit={activeUnit} onClose={() => setSelectedUnitId(null)} onSave={handleUpdateUnit} lang={lang} activeDiscipline={activeDiscipline} />
      )}

      <footer className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-md border-t p-3 text-center text-[10px] text-gray-400 z-30">
        {t.footerInfo}
      </footer>
    </div>
  );
};

export default App;

export enum TaskStatus {
  NOT_STARTED = 'NOT_STARTED',
  IN_PROGRESS = 'IN_PROGRESS',
  DONE = 'DONE',
  NEEDS_FOLLOWUP = 'NEEDS_FOLLOWUP',
  BLOCKED = 'BLOCKED'
}

export type Discipline = 'plumbing' | 'general';

export interface Appointment {
  id: string;
  date: string;
  time: string;
  tenantName: string;
  contractor: string; // Added field to know which pro is assigned
  notes: string;
  isCompleted: boolean;
  createdAt: number;
}

export interface TaskLog {
  id: string;
  timestamp: number;
  workerName: string;
  contractor: string;
  description: string;
  status: TaskStatus;
  discipline: Discipline;
}

export interface Unit {
  id: string;
  buildingId: string;
  number: number;
  statuses: Record<Discipline, TaskStatus>;
  history: TaskLog[];
  appointments: Appointment[]; // New field for scheduled visits
}

export interface Building {
  id: string;
  name: string;
  totalUnits: number;
}

export interface ProjectState {
  buildings: Building[];
  units: Record<string, Unit>;
}

import React, { useState } from 'react';
import { Unit, TaskStatus, Discipline, Appointment } from '../types';
import { STATUS_CONFIG, PUBLIC_AREAS, CONTRACTORS } from '../constants';
import { Language, translations } from '../translations';

interface Props {
  unit: Unit;
  onClose: () => void;
  onSave: (updates: { 
    newLog?: { status: TaskStatus, workerName: string, contractor: string, description: string, discipline: Discipline },
    newAppointment?: Omit<Appointment, 'id' | 'createdAt' | 'isCompleted'>,
    completeAppointmentId?: string
  }) => void;
  lang: Language;
  activeDiscipline: Discipline;
}

const UnitModal: React.FC<Props> = ({ unit, onClose, onSave, lang, activeDiscipline }) => {
  const [activeTab, setActiveTab] = useState<'report' | 'schedule'>('report');
  const [worker, setWorker] = useState('');
  const [desc, setDesc] = useState('');
  const [status, setStatus] = useState<TaskStatus>(unit.statuses[activeDiscipline]);
  const [contractor, setContractor] = useState(CONTRACTORS[0].id);
  const [reportDiscipline, setReportDiscipline] = useState<Discipline>(activeDiscipline);

  // Appointment Form State
  const [appDate, setAppDate] = useState('');
  const [appTime, setAppTime] = useState('');
  const [appTenant, setAppTenant] = useState('');
  const [appContractor, setAppContractor] = useState(CONTRACTORS[0].id); // New state for appointment contractor
  const [appNotes, setAppNotes] = useState('');

  const t = translations[lang];

  const handleReportSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!worker || !desc) return alert(t.alertFillFields);
    const selectedContractor = (t as any)[CONTRACTORS.find(c => c.id === contractor)?.labelKey || ''];
    onSave({ 
      newLog: { status, workerName: worker, contractor: selectedContractor, description: desc, discipline: reportDiscipline } 
    });
    setWorker('');
    setDesc('');
  };

  const handleAppSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!appDate || !appTime || !appTenant) return alert(t.alertFillFields);
    const selectedContractor = (t as any)[CONTRACTORS.find(c => c.id === appContractor)?.labelKey || ''];
    onSave({ 
      newAppointment: { 
        date: appDate, 
        time: appTime, 
        tenantName: appTenant, 
        contractor: selectedContractor, // Pass the contractor label
        notes: appNotes 
      } 
    });
    setAppDate('');
    setAppTime('');
    setAppTenant('');
    setAppNotes('');
  };

  const unitIdentifier = unit.id.split('-').slice(1).join('-');
  const isPublicArea = isNaN(Number(unitIdentifier));
  const publicAreaConfig = isPublicArea ? PUBLIC_AREAS.find(a => a.id === unitIdentifier) : null;
  const displayName = isPublicArea 
    ? (t as any)[publicAreaConfig?.labelKey || ''] 
    : `${t.apartment} ${unitIdentifier}`;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
      <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
        {/* Header */}
        <div className="p-6 border-b flex justify-between items-center bg-gray-50">
          <div className={lang === 'ru' ? 'text-left' : 'text-right'}>
            <h3 className="text-2xl font-bold text-gray-800">{displayName}</h3>
            <p className="text-sm text-gray-500">{t.building}: {unit.buildingId.split('-')[1]}</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-200 rounded-full transition-colors text-2xl leading-none">&times;</button>
        </div>

        {/* Modal Tabs */}
        <div className="flex border-b">
          <button 
            onClick={() => setActiveTab('report')}
            className={`flex-1 py-3 font-bold text-sm transition-all ${activeTab === 'report' ? 'text-blue-600 border-b-2 border-blue-600 bg-blue-50/30' : 'text-gray-400'}`}
          >
            📋 {t.newReport}
          </button>
          <button 
            onClick={() => setActiveTab('schedule')}
            className={`flex-1 py-3 font-bold text-sm transition-all ${activeTab === 'schedule' ? 'text-blue-600 border-b-2 border-blue-600 bg-blue-50/30' : 'text-gray-400'}`}
          >
            📅 {t.viewSchedule}
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-8">
          {activeTab === 'report' ? (
            <>
              <section className="bg-blue-50/50 p-5 rounded-2xl border border-blue-100 shadow-inner">
                <form onSubmit={handleReportSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.disciplineLabel}</label>
                    <div className="flex bg-white rounded-xl border p-1">
                      <button type="button" onClick={() => setReportDiscipline('plumbing')} className={`flex-1 py-1 rounded-lg text-xs font-bold transition-all ${reportDiscipline === 'plumbing' ? 'bg-blue-600 text-white' : 'text-gray-400'}`}>{t.tabPlumbing}</button>
                      <button type="button" onClick={() => setReportDiscipline('general')} className={`flex-1 py-1 rounded-lg text-xs font-bold transition-all ${reportDiscipline === 'general' ? 'bg-blue-600 text-white' : 'text-gray-400'}`}>{t.tabGeneral}</button>
                    </div>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.contractorLabel}</label>
                    <select value={contractor} onChange={e => setContractor(e.target.value)} className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none bg-white">
                      {CONTRACTORS.map(c => <option key={c.id} value={c.id}>{c.icon} {(t as any)[c.labelKey]}</option>)}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.workerName}</label>
                    <input value={worker} onChange={e => setWorker(e.target.value)} className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none" placeholder={t.workerExample} />
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.currentStatus}</label>
