import React from 'react';
import { ProjectState, Unit, Appointment } from '../types';
import { Language, translations } from '../translations';
import { CONTRACTORS } from '../constants';

interface Props {
  state: ProjectState;
  lang: Language;
  onSelectUnit: (buildingId: string, unitId: string | number) => void;
}

const ScheduleView: React.FC<Props> = ({ state, lang, onSelectUnit }) => {
  const t = translations[lang];

  // Flatten all appointments from all units
  const allAppointments: { unit: Unit, app: Appointment }[] = [];
  (Object.values(state.units) as Unit[]).forEach(unit => {
    unit.appointments.forEach(app => {
      if (!app.isCompleted) {
        allAppointments.push({ unit, app });
      }
    });
  });

  // Sort by date and time
  allAppointments.sort((a, b) => 
    new Date(`${a.app.date} ${a.app.time}`).getTime() - new Date(`${b.app.date} ${b.app.time}`).getTime()
  );

  const today = new Date().toISOString().split('T')[0];

  return (
    <div className="space-y-6">
      <h2 className="text-xl font-bold text-gray-800 mb-6 flex items-center gap-2">
        <span className="text-2xl">📅</span>
        {t.viewSchedule}
      </h2>

      {allAppointments.length === 0 ? (
        <div className="bg-white rounded-2xl p-12 text-center border-2 border-dashed text-gray-400">
          <div className="text-4xl mb-4">📭</div>
          <p>{t.noAppointments}</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {allAppointments.map(({ unit, app }) => {
            const buildingId = unit.buildingId.split('-')[1];
            const unitId = unit.id.split('-').slice(1).join('-');
            const isPublic = isNaN(Number(unitId));
            const isToday = app.date === today;

            // Find contractor icon
            const contractorConfig = CONTRACTORS.find(c => (t as any)[c.labelKey] === app.contractor);

            return (
              <button
                key={app.id}
                onClick={() => onSelectUnit(unit.buildingId, isPublic ? unitId : Number(unitId))}
                className={`text-right group p-4 rounded-2xl border-2 transition-all hover:shadow-lg ${
                  isToday ? 'bg-blue-50 border-blue-200' : 'bg-white border-gray-100'
                }`}
              >
                <div className="flex justify-between items-start mb-3">
                  <div className={`px-2 py-1 rounded-lg text-[10px] font-black uppercase ${isToday ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-500'}`}>
                    {isToday ? t.today : app.date}
                  </div>
                  <div className="text-lg font-bold text-blue-900">{app.time}</div>
                </div>

                <div className="mb-3">
                  <div className="text-sm font-bold text-gray-800">
                    {t.building} {buildingId} - {isPublic ? (t as any)[`area_${unitId}`] : `${t.apartment} ${unitId}`}
                  </div>
                  <div className="flex items-center gap-2 mt-2">
                    <span className="text-xs text-gray-500 flex items-center gap-1">
                      <span>👤</span> {app.tenantName}
                    </span>
                    <span className="text-[10px] bg-white border px-2 py-0.5 rounded-full font-bold text-blue-700 shadow-sm flex items-center gap-1">
                      {contractorConfig?.icon} {app.contractor}
                    </span>
                  </div>
                </div>

                {app.notes && (
                  <div className="text-[11px] text-gray-600 bg-white/50 p-2 rounded-lg border border-gray-200/50 italic mt-2">
                    {app.notes}
                  </div>
                )}

                <div className="mt-3 flex justify-end">
                   <span className="text-[10px] text-blue-500 font-bold group-hover:underline">פרטי הדירה ←</span>
                </div>
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default ScheduleView;

import React, { useState, useEffect, useMemo } from 'react';
import { ProjectState, TaskStatus, Unit, Discipline, Appointment } from './types';
import { initializeData, getUnit, updateUnit } from './services/dataService';
import BuildingSelector from './components/BuildingSelector';
import UnitGrid from './components/UnitGrid';
import UnitModal from './components/UnitModal';
import ContractorView from './components/ContractorView';
import ScheduleView from './components/ScheduleView';
import { Language, translations } from './translations';
import { PUBLIC_AREAS, STATUS_CONFIG } from './constants';

const App: React.FC = () => {
  const [state, setState] = useState<ProjectState>(() => initializeData());
  const [selectedBuildingId, setSelectedBuildingId] = useState<string | null>(null);
  const [selectedUnitId, setSelectedUnitId] = useState<string | number | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'units' | 'public' | 'contractors' | 'schedule'>('units');
  const [activeDiscipline, setActiveDiscipline] = useState<Discipline>('general');

  const [lang, setLang] = useState<Language>(() => {
    return (localStorage.getItem('app_lang') as Language) || 'he';
  });

  useEffect(() => {
    localStorage.setItem('app_lang', lang);
    document.documentElement.dir = lang === 'he' ? 'rtl' : 'ltr';
    document.documentElement.lang = lang;
  }, [lang]);

  const t = translations[lang];

  useEffect(() => {
    if (!selectedBuildingId && state.buildings.length > 0) {
      setSelectedBuildingId(state.buildings[0].id);
    }
  }, [state.buildings, selectedBuildingId]);

  const activeUnit = useMemo(() => {
    if (!selectedBuildingId || selectedUnitId === null) return null;
    return getUnit(state, selectedBuildingId, selectedUnitId);
  }, [state, selectedBuildingId, selectedUnitId]);

  const handleUpdateUnit = (updates: { 
    newLog?: { status: TaskStatus, workerName: string, contractor: string, description: string, discipline: Discipline },
    newAppointment?: Omit<Appointment, 'id' | 'createdAt' | 'isCompleted'>,
    completeAppointmentId?: string
  }) => {
    if (!activeUnit) return;
    const newState = updateUnit(state, activeUnit, {
      newLog: updates.newLog,
      newAppointment: updates.newAppointment,
      completeAppointmentId: updates.completeAppointmentId
    });
    setState(newState);
  };

  const filteredBuildings = state.buildings.filter(b => {
    const buildingName = lang === 'ru' ? b.name.replace('בניין', 'Здание') : b.name;
    return buildingName.includes(searchTerm) || b.id.includes(searchTerm) || b.name.includes(searchTerm);
  });

  const toggleLanguage = () => {
    setLang(prev => prev === 'he' ? 'ru' : 'he');
  };

  const handleSelectFromOtherView = (buildingId: string, unitId: string | number) => {
    setSelectedBuildingId(buildingId);
    setSelectedUnitId(unitId);
  };

  return (
    <div className={`min-h-screen bg-slate-50 ${lang === 'ru' ? 'text-left' : 'text-right'}`} dir={lang === 'he' ? 'rtl' : 'ltr'}>
      <header className="sticky top-0 z-40 bg-blue-900 text-white shadow-lg p-4">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-3 w-full md:w-auto">
            <div className="bg-white p-2 px-3 rounded-lg text-blue-900 text-xl font-black">בדק</div>
            <div className="flex-1">
              <h1 className="text-xl font-bold leading-none">{t.appName}</h1>
              <p className="text-[10px] text-blue-200 mt-1 uppercase tracking-widest font-medium">{t.appSubName}</p>
            </div>
            <button onClick={toggleLanguage} className="md:hidden bg-blue-800 hover:bg-blue-700 px-3 py-1 rounded-full text-xs font-bold transition-colors border border-blue-600">
              {t.langToggle}
            </button>
          </div>

          <div className="flex items-center gap-4 w-full md:w-auto">
            <div className="flex-1 md:w-64 relative">
              <input type="text" placeholder={t.searchPlaceholder} value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className={`w-full bg-blue-800/50 border border-blue-400/30 rounded-full ${lang === 'ru' ? 'pl-10 pr-4' : 'pr-10 pl-4'} py-2 text-sm placeholder:text-blue-300 outline-none focus:ring-2 focus:ring-white/30`} />
              <span className={`absolute ${lang === 'ru' ? 'right-3' : 'right-3'} top-2.5 opacity-50`}>🔍</span>
            </div>
            <button onClick={toggleLanguage} className="hidden md:block bg-blue-800 hover:bg-blue-700 px-4 py-2 rounded-full text-sm font-bold transition-colors border border-blue-600 shadow-inner">
              {t.langToggle}
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto pb-20 px-4">
        {/* Navigation Tabs */}
        <div className="flex gap-2 my-6 bg-gray-200/50 p-1 rounded-xl w-full overflow-x-auto no-scrollbar md:w-fit mx-auto md:mx-0">
          <button onClick={() => setViewMode('units')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2 rounded-lg font-bold transition-all ${viewMode === 'units' ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewUnits}</button>
          <button onClick={() => setViewMode('public')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2 rounded-lg font-bold transition-all ${viewMode === 'public' ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewPublic}</button>
          <button onClick={() => setViewMode('contractors')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2 rounded-lg font-bold transition-all ${viewMode === 'contractors' ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewContractors}</button>
          <button onClick={() => setViewMode('schedule')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2 rounded-lg font-bold transition-all ${viewMode === 'schedule' ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewSchedule}</button>
        </div>

        {viewMode === 'contractors' ? (
          <ContractorView state={state} lang={lang} onSelectUnit={handleSelectFromOtherView} />
        ) : viewMode === 'schedule' ? (
          <ScheduleView state={state} lang={lang} onSelectUnit={handleSelectFromOtherView} />
        ) : (
          <>
            {/* Discipline Tabs */}
            <div className="flex justify-center mb-6">
              <div className="bg-white p-1.5 rounded-2xl shadow-md border flex gap-1 w-full max-w-md">
                <button onClick={() => setActiveDiscipline('general')} className={`flex-1 py-3 px-4 rounded-xl font-bold transition-all flex items-center justify-center gap-2 ${activeDiscipline === 'general' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500 hover:bg-gray-50'}`}>🛠️ {t.tabGeneral}</button>
                <button onClick={() => setActiveDiscipline('plumbing')} className={`flex-1 py-3 px-4 rounded-xl font-bold transition-all flex items-center justify-center gap-2 ${activeDiscipline === 'plumbing' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500 hover:bg-gray-50'}`}>🚰 {t.tabPlumbing}</button>
              </div>
            </div>

            <section className="mt-8">
              <BuildingSelector buildings={filteredBuildings} selectedBuildingId={selectedBuildingId} onSelect={setSelectedBuildingId} state={state} lang={lang} discipline={activeDiscipline} />
            </section>

            {selectedBuildingId && (
              <section className="mt-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
                {viewMode === 'units' ? (
                  <UnitGrid buildingId={selectedBuildingId} state={state} onSelectUnit={(num) => setSelectedUnitId(num)} lang={lang} discipline={activeDiscipline} />
                ) : (
                  <div className="bg-white rounded-2xl shadow-sm p-6 border border-gray-100">
                    <h2 className="text-xl font-bold text-gray-800 mb-6">{t.publicAreas}</h2>
                    <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4">
                      {PUBLIC_AREAS.map(area => {
                        const unitData = getUnit(state, selectedBuildingId, area.id);
                        const currentStatus = unitData.statuses[activeDiscipline];
                        const config = STATUS_CONFIG[currentStatus];
                        return (
                          <button key={area.id} onClick={() => setSelectedUnitId(area.id)} className={`flex items-center gap-4 p-4 rounded-xl border-2 transition-all hover:shadow-md active:scale-95 text-right ${config.color}`}>
                            <span className="text-3xl">{area.icon}</span>
                            <div className="flex flex-col">
                              <span className="font-bold text-lg">{(t as any)[area.labelKey]}</span>
                              <span className="text-xs opacity-70">{(t as any)[config.labelKey]}</span>
                            </div>
                          </button>
                        );
                      })}
                    </div>
                  </div>
                )}
              </section>
            )}
          </>
        )}
      </main>

      {activeUnit && (
        <UnitModal unit={activeUnit} onClose={() => setSelectedUnitId(null)} onSave={handleUpdateUnit} lang={lang} activeDiscipline={activeDiscipline} />
      )}

      <footer className="fixed bottom-0 left-0 right-0 bg-white/80 backdrop-blur-md border-t p-3 text-center text-[10px] text-gray-400 z-30">
        {t.footerInfo}
      </footer>
    </div>
  );
};

export default App;

