import { Language, translations } from '../translations';

interface Props {
  unit: Unit;
  onClose: () => void;
  onSave: (updates: { 
    newLog?: { status: TaskStatus, workerName: string, contractor: string, description: string, discipline: Discipline },
    newAppointment?: Omit<Appointment, 'id' | 'createdAt' | 'isCompleted'>,
    completeAppointmentId?: string
  }) => void;
  lang: Language;
  activeDiscipline: Discipline;
}

const UnitModal: React.FC<Props> = ({ unit, onClose, onSave, lang, activeDiscipline }) => {
  const [activeTab, setActiveTab] = useState<'report' | 'schedule'>('report');
  const [worker, setWorker] = useState('');
  const [desc, setDesc] = useState('');
  const [status, setStatus] = useState<TaskStatus>(unit.statuses[activeDiscipline]);
  const [contractor, setContractor] = useState(CONTRACTORS[0].id);
  const [reportDiscipline, setReportDiscipline] = useState<Discipline>(activeDiscipline);

  // Appointment Form State
  const [appDate, setAppDate] = useState('');
  const [appTime, setAppTime] = useState('');
  const [appTenant, setAppTenant] = useState('');
  const [appContractor, setAppContractor] = useState(CONTRACTORS[0].id);
  const [appManager, setAppManager] = useState(MANAGERS[0].id); // New state for manager
  const [appNotes, setAppNotes] = useState('');

  const t = translations[lang];

  const handleReportSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!worker || !desc) return alert(t.alertFillFields);
    const selectedContractor = (t as any)[CONTRACTORS.find(c => c.id === contractor)?.labelKey || ''];
    onSave({ 
      newLog: { status, workerName: worker, contractor: selectedContractor, description: desc, discipline: reportDiscipline } 
    });
    setWorker('');
    setDesc('');
  };

  const handleAppSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!appDate || !appTime || !appTenant) return alert(t.alertFillFields);

    const selectedContractor = (t as any)[CONTRACTORS.find(c => c.id === appContractor)?.labelKey || ''];
    const selectedManager = MANAGERS.find(m => m.id === appManager);
    const managerLabel = selectedManager?.id === 'none' ? '' : (selectedManager?.name || '');

    onSave({ 
      newAppointment: { 
        date: appDate, 
        time: appTime, 
        tenantName: appTenant, 
        contractor: selectedContractor,
        managerName: managerLabel, // Pass the manager name
        notes: appNotes 
      } 
    });
    setAppDate('');
    setAppTime('');
    setAppTenant('');
    setAppNotes('');
  };

  const unitIdentifier = unit.id.split('-').slice(1).join('-');
  const isPublicArea = isNaN(Number(unitIdentifier));
  const publicAreaConfig = isPublicArea ? PUBLIC_AREAS.find(a => a.id === unitIdentifier) : null;
  const displayName = isPublicArea 
    ? (t as any)[publicAreaConfig?.labelKey || ''] 
    : `${t.apartment} ${unitIdentifier}`;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
      <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
        {/* Header */}
        <div className="p-6 border-b flex justify-between items-center bg-gray-50">
          <div className={lang === 'ru' ? 'text-left' : 'text-right'}>
            <h3 className="text-2xl font-bold text-gray-800">{displayName}</h3>
            <p className="text-sm text-gray-500">{t.building}: {unit.buildingId.split('-')[1]}</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-200 rounded-full transition-colors text-2xl leading-none">&times;</button>
        </div>

        {/* Modal Tabs */}
        <div className="flex border-b">
          <button 
            onClick={() => setActiveTab('report')}
            className={`flex-1 py-3 font-bold text-sm transition-all ${activeTab === 'report' ? 'text-blue-600 border-b-2 border-blue-600 bg-blue-50/30' : 'text-gray-400'}`}
          >
            📋 {t.newReport}
          </button>
          <button 
            onClick={() => setActiveTab('schedule')}
            className={`flex-1 py-3 font-bold text-sm transition-all ${activeTab === 'schedule' ? 'text-blue-600 border-b-2 border-blue-600 bg-blue-50/30' : 'text-gray-400'}`}
          >
            📅 {t.viewSchedule}
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 space-y-8">
          {activeTab === 'report' ? (
            <>
              <section className="bg-blue-50/50 p-5 rounded-2xl border border-blue-100 shadow-inner">
                <form onSubmit={handleReportSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.disciplineLabel}</label>
                    <div className="flex bg-white rounded-xl border p-1">
                      <button type="button" onClick={() => setReportDiscipline('plumbing')} className={`flex-1 py-1 rounded-lg text-xs font-bold transition-all ${reportDiscipline === 'plumbing' ? 'bg-blue-600 text-white' : 'text-gray-400'}`}>{t.tabPlumbing}</button>
                      <button type="button" onClick={() => setReportDiscipline('general')} className={`flex-1 py-1 rounded-lg text-xs font-bold transition-all ${reportDiscipline === 'general' ? 'bg-blue-600 text-white' : 'text-gray-400'}`}>{t.tabGeneral}</button>
                    </div>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.contractorLabel}</label>
                    <select value={contractor} onChange={e => setContractor(e.target.value)} className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none bg-white">
                      {CONTRACTORS.map(c => <option key={c.id} value={c.id}>{c.icon} {(t as any)[c.labelKey]}</option>)}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.workerName}</label>
                    <input value={worker} onChange={e => setWorker(e.target.value)} className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none" placeholder={t.workerExample} />
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.currentStatus}</label>
                    <select value={status} onChange={e => setStatus(e.target.value as TaskStatus)} className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none bg-white">
                      {Object.entries(STATUS_CONFIG).map(([s, cfg]) => <option key={s} value={s}>{(t as any)[cfg.labelKey]}</option>)}
                    </select>
                  </div>
                  <div className="md:col-span-2 space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.whatWasDone}</label>
                    <textarea value={desc} onChange={e => setDesc(e.target.value)} rows={2} className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none resize-none" placeholder={t.descriptionPlaceholder} />
                  </div>
                  <button type="submit" className="md:col-span-2 bg-blue-600 text-white font-bold py-3 rounded-xl hover:bg-blue-700 transition-all shadow-lg active:scale-95">{t.updateButton}</button>
                </form>
              </section>

              <section>
                <h4 className="text-sm font-bold text-gray-400 mb-6 uppercase tracking-wider">{t.workHistory}</h4>
                {unit.history.length === 0 ? <div className="text-center py-10 text-gray-400 border-2 border-dashed rounded-2xl italic">{t.noHistory}</div> : (
                  <div className={`space-y-6 relative before:absolute ${lang === 'ru' ? 'before:left-3' : 'before:right-3'} before:top-2 before:bottom-2 before:w-0.5 before:bg-gray-100`}>
                    {unit.history.map((log) => (
                      <div key={log.id} className={`relative ${lang === 'ru' ? 'pl-10' : 'pr-10'}`}>
                        <div className={`absolute ${lang === 'ru' ? 'left-0' : 'right-0'} top-1 w-6 h-6 rounded-full border-4 border-white shadow-sm ${STATUS_CONFIG[log.status].color.split(' ')[0]}`}></div>
                        <div className={`bg-white border rounded-xl p-4 shadow-sm ${lang === 'ru' ? 'text-left' : 'text-right'}`}>
                          <div className="flex justify-between items-start mb-1 flex-wrap gap-2">
                            <div className="flex flex-col">
                              <span className="font-bold text-gray-800">{log.workerName}</span>
                              <div className="flex items-center gap-2">
                                <span className="text-[10px] text-blue-600 font-semibold">{log.contractor}</span>
                                <span className={`text-[9px] px-1.5 py-0.5 rounded bg-gray-100 text-gray-500 border`}>{(t as any)[log.discipline === 'plumbing' ? 'tabPlumbing' : 'tabGeneral']}</span>
                              </div>
                            </div>
                            <span className="text-[10px] text-gray-400 bg-gray-50 px-2 py-1 rounded-md">{new Date(log.timestamp).toLocaleString(lang === 'ru' ? 'ru-RU' : 'he-IL')}</span>
                          </div>
                          <p className="text-sm text-gray-600 leading-relaxed whitespace-pre-wrap">{log.description}</p>
                          <div className="mt-3"><span className={`text-[10px] px-2 py-0.5 rounded-full border ${STATUS_CONFIG[log.status].color}`}>{(t as any)[STATUS_CONFIG[log.status].labelKey]}</span></div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </section>
            </>
          ) : (
            <>
              <section className="bg-yellow-50/50 p-5 rounded-2xl border border-yellow-100 shadow-inner">
                <h4 className="text-sm font-bold text-yellow-800 mb-4 uppercase tracking-wider">{t.scheduleTitle}</h4>
                <form onSubmit={handleAppSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.dateLabel}</label>
                    <input type="date" value={appDate} onChange={e => setAppDate(e.target.value)} className="w-full px-4 py-2 rounded-xl border border-gray-200 outline-none" />
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.timeLabel}</label>
                    <input type="time" value={appTime} onChange={e => setAppTime(e.target.value)} className="w-full px-4 py-2 rounded-xl border border-gray-200 outline-none" />
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.contractorLabel}</label>
                    <select value={appContractor} onChange={e => setAppContractor(e.target.value)} className="w-full px-4 py-2 rounded-xl border border-gray-200 outline-none bg-white">
                      {CONTRACTORS.map(c => <option key={c.id} value={c.id}>{c.icon} {(t as any)[c.labelKey]}</option>)}
                    </select>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.managerLabel}</label>
                    <select value={appManager} onChange={e => setAppManager(e.target.value)} className="w-full px-4 py-2 rounded-xl border border-gray-200 outline-none bg-white font-bold">
                      {MANAGERS.map(m => <option key={m.id} value={m.id}>{m.icon} {m.id === 'none' ? t.none : m.name}</option>)}
                    </select>
                  </div>
                  <div className="col-span-1 md:col-span-2 space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.tenantLabel}</label>
                    <input type="text" value={appTenant} onChange={e => setAppTenant(e.target.value)} className="w-full px-4 py-2 rounded-xl border border-gray-200 outline-none" placeholder="למשל: משפחת כהן" />
                  </div>
                  <div className="col-span-1 md:col-span-2 space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.notesLabel}</label>
                    <textarea value={appNotes} onChange={e => setAppNotes(e.target.value)} rows={2} className="w-full px-4 py-2 rounded-xl border border-gray-200 outline-none resize-none" />
                  </div>
                  <button type="submit" className="col-span-1 md:col-span-2 bg-yellow-600 text-white font-bold py-3 rounded-xl hover:bg-yellow-700 transition-all shadow-lg active:scale-95">{t.addAppointment}</button>
                </form>
              </section>

              <section>
                <h4 className="text-sm font-bold text-gray-400 mb-4 uppercase tracking-wider">{t.upcomingAppointments}</h4>
                {unit.appointments.length === 0 ? <div className="text-center py-10 text-gray-400 border-2 border-dashed rounded-2xl italic">{t.noAppointments}</div> : (
                  <div className="space-y-3">
                    {unit.appointments.map(app => (
                      <div key={app.id} className={`p-4 rounded-xl border-2 flex justify-between items-center ${app.isCompleted ? 'bg-gray-50 border-gray-100 opacity-60' : 'bg-white border-blue-100 shadow-sm'}`}>
                        <div>
                          <div className="flex items-center gap-2 mb-1">
                            <span className="text-lg font-bold text-blue-900">{app.time}</span>
                            <span className="text-xs font-bold text-gray-400">{app.date}</span>
                          </div>
                          <div className="flex flex-wrap items-center gap-2">
                             <span className="text-sm font-bold text-gray-800">{app.tenantName}</span>
                             <span className="text-[10px] bg-blue-50 text-blue-600 px-2 py-0.5 rounded border border-blue-100 font-bold">{app.contractor}</span>
                             {app.managerName && (
                               <span className="text-[10px] bg-gray-50 text-gray-600 px-2 py-0.5 rounded border border-gray-200 font-bold">👔 {app.managerName}</span>
                             )}
                          </div>
                          <div className="text-xs text-gray-500 italic mt-1">{app.notes}</div>
                        </div>
                        {!app.isCompleted && (
                          <button 
                            onClick={() => onSave({ completeAppointmentId: app.id })}
                            className="bg-green-100 text-green-700 px-3 py-1.5 rounded-lg text-xs font-bold hover:bg-green-200"
                          >
                            ✔️ {t.appointmentDone}
                          </button>
                        )}
                      </div>
                    ))}
                  </div>
                )}
              </section>
            </>
          )}
        </div>
      </div>
    </div>
  );
};

export default UnitModal;

import React from 'react';
import { ProjectState, Unit, Appointment } from '../types';
import { Language, translations } from '../translations';
import { CONTRACTORS, MANAGERS } from '../constants';

interface Props {
  state: ProjectState;
  lang: Language;
  onSelectUnit: (buildingId: string, unitId: string | number) => void;
}

const ScheduleView: React.FC<Props> = ({ state, lang, onSelectUnit }) => {
  const t = translations[lang];

  // Flatten all appointments from all units
  const allAppointments: { unit: Unit, app: Appointment }[] = [];
  (Object.values(state.units) as Unit[]).forEach(unit => {
    unit.appointments.forEach(app => {
      if (!app.isCompleted) {
        allAppointments.push({ unit, app });
      }
    });
  });

  // Sort by date and time
  allAppointments.sort((a, b) => 
    new Date(`${a.app.date} ${a.app.time}`).getTime() - new Date(`${b.app.date} ${b.app.time}`).getTime()
  );

  const today = new Date().toISOString().split('T')[0];

  return (
    <div className="space-y-6">
      <h2 className="text-xl font-bold text-gray-800 mb-6 flex items-center gap-2">
        <span className="text-2xl">📅</span>
        {t.viewSchedule}
      </h2>

      {allAppointments.length === 0 ? (
        <div className="bg-white rounded-2xl p-12 text-center border-2 border-dashed text-gray-400">
          <div className="text-4xl mb-4">📭</div>
          <p>{t.noAppointments}</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {allAppointments.map(({ unit, app }) => {
            const buildingId = unit.buildingId.split('-')[1];
            const unitId = unit.id.split('-').slice(1).join('-');
            const isPublic = isNaN(Number(unitId));
            const isToday = app.date === today;

            // Find contractor icon
            const contractorConfig = CONTRACTORS.find(c => (t as any)[c.labelKey] === app.contractor);

            return (
              <button
                key={app.id}
                onClick={() => onSelectUnit(unit.buildingId, isPublic ? unitId : Number(unitId))}
                className={`text-right group p-4 rounded-2xl border-2 transition-all hover:shadow-lg ${
                  isToday ? 'bg-blue-50 border-blue-200' : 'bg-white border-gray-100'
                }`}
              >
                <div className="flex justify-between items-start mb-3">
                  <div className={`px-2 py-1 rounded-lg text-[10px] font-black uppercase ${isToday ? 'bg-blue-600 text-white' : 'bg-gray-100 text-gray-500'}`}>
                    {isToday ? t.today : app.date}
                  </div>
                  <div className="text-lg font-bold text-blue-900">{app.time}</div>
                </div>

                <div className="mb-3">
                  <div className="text-sm font-bold text-gray-800">
                    {t.building} {buildingId} - {isPublic ? (t as any)[`area_${unitId}`] : `${t.apartment} ${unitId}`}
                  </div>

                  <div className="flex flex-wrap items-center gap-2 mt-2">
                    <span className="text-xs text-gray-500 flex items-center gap-1">
                      <span>👤</span> {app.tenantName}
                    </span>
                    <span className="text-[10px] bg-white border px-2 py-0.5 rounded-full font-bold text-blue-700 shadow-sm flex items-center gap-1">
                      {contractorConfig?.icon} {app.contractor}
                    </span>
                    {app.managerName && (
                      <span className="text-[10px] bg-gray-100 border px-2 py-0.5 rounded-full font-bold text-gray-600 shadow-sm flex items-center gap-1">
                        👔 {app.managerName}
                      </span>
                    )}
                  </div>
                </div>

                {app.notes && (
                  <div className="text-[11px] text-gray-600 bg-white/50 p-2 rounded-lg border border-gray-200/50 italic mt-2">
                    {app.notes}
                  </div>
                )}

                <div className="mt-3 flex justify-end">
                   <span className="text-[10px] text-blue-500 font-bold group-hover:underline">פרטי הדירה ←</span>
                </div>
              </button>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default ScheduleView;

export enum TaskStatus {
  NOT_STARTED = 'NOT_STARTED',
  IN_PROGRESS = 'IN_PROGRESS',
  DONE = 'DONE',
  NEEDS_FOLLOWUP = 'NEEDS_FOLLOWUP',
  BLOCKED = 'BLOCKED'
}

export type Discipline = 'plumbing' | 'general';

export interface Appointment {
  id: string;
  date: string;
  time: string;
  tenantName: string;
  contractor: string; // This will now hold either the contractor name or "מנהל עבודה"
  notes: string;
  isCompleted: boolean;
  createdAt: number;
}

export interface TaskLog {
  id: string;
  timestamp: number;
  workerName: string;
  contractor: string;
  description: string;
  status: TaskStatus;
  discipline: Discipline;
}

export interface Unit {
  id: string;
  buildingId: string;
  number: number;
  statuses: Record<Discipline, TaskStatus>;
  history: TaskLog[];
  appointments: Appointment[];
}

export interface Building {
  id: string;
  name: string;
  totalUnits: number;
}

export interface ProjectState {
  buildings: Building[];
  units: Record<string, Unit>;
}

import { TaskStatus } from './types';

export const STATUS_CONFIG: Record<TaskStatus, { labelKey: string; color: string; icon: string }> = {
  [TaskStatus.NOT_STARTED]: {
    labelKey: 'notStarted',
    color: 'bg-gray-100 text-gray-600 border-gray-200',
    icon: '⚪'
  },
  [TaskStatus.IN_PROGRESS]: {
    labelKey: 'inProgress',
    color: 'bg-blue-100 text-blue-700 border-blue-200',
    icon: '🔵'
  },
  [TaskStatus.DONE]: {
    labelKey: 'completed',
    color: 'bg-green-100 text-green-700 border-green-200',
    icon: '🟢'
  },
  [TaskStatus.NEEDS_FOLLOWUP]: {
    labelKey: 'needsFollowup',
    color: 'bg-yellow-100 text-yellow-700 border-yellow-200',
    icon: '🟡'
  },
  [TaskStatus.BLOCKED]: {
    labelKey: 'blocked',
    color: 'bg-red-100 text-red-700 border-red-200',
    icon: '🔴'
  }
};

export const BUILDINGS_COUNT = 33;
export const UNITS_PER_BUILDING = 50;

export const PUBLIC_AREAS = [
  { id: 'lobby', labelKey: 'area_lobby', icon: '🏢' },
  { id: 'parking', labelKey: 'area_parking', icon: '🚗' },
  { id: 'yard', labelKey: 'area_yard', icon: '🌳' },
  { id: 'roof', labelKey: 'area_roof', icon: '🏠' },
  { id: 'stairwell', labelKey: 'area_stairwell', icon: '🪜' },
  { id: 'elevators', labelKey: 'area_elevators', icon: '🛗' }
];

export const CONTRACTORS = [
  { id: 'manager', labelKey: 'contractor_manager', icon: '👔' }, // Integrated as requested
  { id: 'internal', labelKey: 'contractor_internal', icon: '🛠️' },
  { id: 'rappelling', labelKey: 'contractor_rappelling', icon: '🧗' },
  { id: 'telefire', labelKey: 'contractor_telefire', icon: '🔥' },
  { id: 'emperion', labelKey: 'contractor_emperion', icon: '🚰' },
  { id: 'itumit', labelKey: 'contractor_itumit', icon: '💧' }
];

import React, { useState } from 'react';
import { Unit, TaskStatus, Discipline, Appointment } from '../types';
import { STATUS_CONFIG, PUBLIC_AREAS, CONTRACTORS } from '../constants';
import { Language, translations } from '../translations';

interface Props {
  unit: Unit;
  onClose: () => void;
  onSave: (updates: { 
    newLog?: { status: TaskStatus, workerName: string, contractor: string, description: string, discipline: Discipline },
    newAppointment?: Omit<Appointment, 'id' | 'createdAt' | 'isCompleted'>,
    completeAppointmentId?: string
  }) => void;
  lang: Language;
  activeDiscipline: Discipline;
}

const UnitModal: React.FC<Props> = ({ unit, onClose, onSave, lang, activeDiscipline }) => {
  const [activeTab, setActiveTab] = useState<'report' | 'schedule'>('report');
  const [worker, setWorker] = useState('');
  const [desc, setDesc] = useState('');
  const [status, setStatus] = useState<TaskStatus>(unit.statuses[activeDiscipline]);
  const [contractor, setContractor] = useState(CONTRACTORS[0].id);
  const [reportDiscipline, setReportDiscipline] = useState<Discipline>(activeDiscipline);

  // Appointment Form State
  const [appDate, setAppDate] = useState('');
  const [appTime, setAppTime] = useState('');
  const [appTenant, setAppTenant] = useState('');
  const [appContractor, setAppContractor] = useState(CONTRACTORS[0].id);
  const [appNotes, setAppNotes] = useState('');

  const t = translations[lang];

  const handleReportSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!worker || !desc) return alert(t.alertFillFields);
    const selectedContractor = (t as any)[CONTRACTORS.find(c => c.id === contractor)?.labelKey || ''];
    onSave({ 
      newLog: { status, workerName: worker, contractor: selectedContractor, description: desc, discipline: reportDiscipline } 
    });
    setWorker('');
    setDesc('');
  };

  const handleAppSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!appDate || !appTime || !appTenant) return alert(t.alertFillFields);

    const selectedContractor = (t as any)[CONTRACTORS.find(c => c.id === appContractor)?.labelKey || ''];

    onSave({ 
      newAppointment: { 
        date: appDate, 
        time: appTime, 
        tenantName: appTenant, 
        contractor: selectedContractor,
        notes: appNotes 
      } 
    });
    setAppDate('');
    setAppTime('');
    setAppTenant('');
    setAppNotes('');
  };

  const unitIdentifier = unit.id.split('-').slice(1).join('-');
