                    <label className="text-xs font-semibold text-gray-500 px-1">{t.contractorLabel}</label>
                    <select value={appContractor} onChange={e => setAppContractor(e.target.value)} className="w-full px-4 py-2 rounded-xl border border-gray-200 outline-none bg-white font-bold">
                      {CONTRACTORS.map(c => <option key={c.id} value={c.id}>{c.icon} {(t as any)[c.labelKey]}</option>)}
