                          <div className="flex flex-wrap items-center gap-2">
                             <span className="text-sm font-bold text-gray-800">{app.tenantName}</span>
                             <span className={`text-[10px] px-2 py-0.5 rounded border font-bold ${app.contractor.includes('מנהל') ? 'bg-gray-100 text-gray-700 border-gray-300' : 'bg-blue-50 text-blue-600 border-blue-100'}`}>{app.contractor}</span>
