    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/50 backdrop-blur-sm">
      <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
        {/* Header */}
        <div className="p-6 border-b flex justify-between items-center bg-gray-50">
          <div className={lang === 'ru' ? 'text-left' : 'text-right'}>
            <h3 className="text-2xl font-bold text-gray-800">{displayName}</h3>
            <p className="text-sm text-gray-500">{t.building}: {unit.buildingId.split('-')[1]}</p>
          </div>
          <button onClick={onClose} className="p-2 hover:bg-gray-200 rounded-full transition-colors text-2xl leading-none">&times;</button>
        </div>

        {/* Modal Tabs */}
        <div className="flex border-b bg-gray-50/50">
          <button 
            onClick={() => setActiveTab('report')}
            className={`flex-1 py-4 font-bold text-xs md:text-sm transition-all flex items-center justify-center gap-2 ${activeTab === 'report' ? 'text-blue-600 border-b-2 border-blue-600 bg-white' : 'text-gray-400 hover:text-gray-600'}`}
          >
            📋 <span className="hidden sm:inline">{t.newReport}</span>
          </button>
          <button 
            onClick={() => setActiveTab('schedule')}
            className={`flex-1 py-4 font-bold text-xs md:text-sm transition-all flex items-center justify-center gap-2 ${activeTab === 'schedule' ? 'text-blue-600 border-b-2 border-blue-600 bg-white' : 'text-gray-400 hover:text-gray-600'}`}
          >
            📅 <span className="hidden sm:inline">{t.viewSchedule}</span>
          </button>
          <button 
            onClick={() => setActiveTab('history')}
            className={`flex-1 py-4 font-bold text-xs md:text-sm transition-all flex items-center justify-center gap-2 ${activeTab === 'history' ? 'text-blue-600 border-b-2 border-blue-600 bg-white' : 'text-gray-400 hover:text-gray-600'}`}
          >
            📜 <span className="hidden sm:inline">{t.viewHistory}</span>
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6">
          {activeTab === 'report' && (
            <div className="animate-in fade-in duration-300">
              <section className="bg-blue-50/50 p-6 rounded-2xl border border-blue-100 shadow-inner">
                <form onSubmit={handleReportSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.disciplineLabel}</label>
                    <div className="flex bg-white rounded-xl border p-1 shadow-sm">
                      <button type="button" onClick={() => setReportDiscipline('plumbing')} className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${reportDiscipline === 'plumbing' ? 'bg-blue-600 text-white' : 'text-gray-400'}`}>{t.tabPlumbing}</button>
                      <button type="button" onClick={() => setReportDiscipline('general')} className={`flex-1 py-2 rounded-lg text-xs font-bold transition-all ${reportDiscipline === 'general' ? 'bg-blue-600 text-white' : 'text-gray-400'}`}>{t.tabGeneral}</button>
                    </div>
                  </div>
                  <div className="space-y-1">
                    <label className="text-xs font-semibold text-gray-500 px-1">{t.contractorLabel}</label>
                    <select value={contractor} onChange={e => setContractor(e.target.value)} className="w-full px-4 py-2 rounded-xl border border-gray-200 focus:ring-2 focus:ring-blue-500 outline-none bg-white font-bold shadow-sm">
                      {CONTRACTORS.map(c => <option key={c.id} value={c.id}>{c.icon} {(t as any)[c.labelKey]}</option>)}
