            <div className="flex-1">
              <h1 className="text-xl font-bold leading-none">{t.appName}</h1>
              <p className="text-[10px] text-blue-200 mt-1 uppercase tracking-widest font-medium">{t.appSubName}</p>
            </div>
            <button onClick={toggleLanguage} className="md:hidden bg-blue-800 hover:bg-blue-700 px-3 py-1 rounded-full text-xs font-bold transition-colors border border-blue-600">
              {t.langToggle}
            </button>
          </div>

          <div className="flex items-center gap-4 w-full md:w-auto">
            <div className="flex-1 md:w-64 relative">
              <input type="text" placeholder={t.searchPlaceholder} value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className={`w-full bg-blue-800/50 border border-blue-400/30 rounded-full ${lang === 'ru' ? 'pl-10 pr-4' : 'pr-10 pl-4'} py-2 text-sm placeholder:text-blue-300 outline-none focus:ring-2 focus:ring-white/30`} />
              <span className={`absolute ${lang === 'ru' ? 'right-3' : 'right-3'} top-2.5 opacity-50`}>🔍</span>
            </div>
            <button onClick={toggleLanguage} className="hidden md:block bg-blue-800 hover:bg-blue-700 px-4 py-2 rounded-full text-sm font-bold transition-colors border border-blue-600 shadow-inner">
              {t.langToggle}
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto pb-20 px-4">
        {/* Navigation Tabs */}
        <div className="flex gap-2 my-6 bg-gray-200/50 p-1 rounded-xl w-full overflow-x-auto no-scrollbar md:w-fit mx-auto md:mx-0 shadow-inner">
          <button onClick={() => setViewMode('units')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2 rounded-lg font-bold transition-all ${viewMode === 'units' ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewUnits}</button>
          <button onClick={() => setViewMode('public')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2 rounded-lg font-bold transition-all ${viewMode === 'public' ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewPublic}</button>
          <button onClick={() => setViewMode('contractors')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2 rounded-lg font-bold transition-all ${viewMode === 'contractors' ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewContractors}</button>
          <button onClick={() => setViewMode('schedule')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2 rounded-lg font-bold transition-all ${viewMode === 'schedule' ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewSchedule}</button>
          <button onClick={() => setViewMode('history')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2 rounded-lg font-bold transition-all ${viewMode === 'history' ? 'bg-white shadow-sm text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewHistory}</button>
        </div>

        {viewMode === 'contractors' ? (
          <ContractorView state={state} lang={lang} onSelectUnit={handleSelectFromOtherView} />
