          <ScheduleView state={state} lang={lang} onSelectUnit={handleSelectFromOtherView} />
        ) : viewMode === 'history' ? (
          <ProjectHistoryView state={state} lang={lang} onSelectUnit={handleSelectFromOtherView} />
        ) : (
          <>
            {/* Discipline Tabs */}
            <div className="flex justify-center mb-6">
              <div className="bg-white p-1.5 rounded-2xl shadow-md border flex gap-1 w-full max-w-md">
                <button onClick={() => setActiveDiscipline('general')} className={`flex-1 py-3 px-4 rounded-xl font-bold transition-all flex items-center justify-center gap-2 ${activeDiscipline === 'general' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500 hover:bg-gray-50'}`}>👷 {t.tabGeneral}</button>
                <button onClick={() => setActiveDiscipline('plumbing')} className={`flex-1 py-3 px-4 rounded-xl font-bold transition-all flex items-center justify-center gap-2 ${activeDiscipline === 'plumbing' ? 'bg-blue-600 text-white shadow-lg' : 'text-gray-500 hover:bg-gray-50'}`}>🚰 {t.tabPlumbing}</button>
              </div>
            </div>

            <section className="mt-8">
              <BuildingSelector buildings={filteredBuildings} selectedBuildingId={selectedBuildingId} onSelect={setSelectedBuildingId} state={state} lang={lang} discipline={activeDiscipline} />
            </section>

            {selectedBuildingId && (
              <section className="mt-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
                {viewMode === 'units' ? (
                  <UnitGrid buildingId={selectedBuildingId} state={state} onSelectUnit={(num) => setSelectedUnitId(num)} lang={lang} discipline={activeDiscipline} />
                ) : (
                  <div className="bg-white rounded-2xl shadow-sm p-6 border border-gray-100">
                    <h2 className="text-xl font-bold text-gray-800 mb-6">{t.publicAreas}</h2>
                    <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-4">
                      {PUBLIC_AREAS.map(area => {
                        const unitData = getUnit(state, selectedBuildingId, area.id);
                        const currentStatus = unitData.statuses[activeDiscipline];
                        const config = STATUS_CONFIG[currentStatus];
                        return (
                          <button key={area.id} onClick={() => setSelectedUnitId(area.id)} className={`flex items-center gap-4 p-4 rounded-xl border-2 transition-all hover:shadow-md active:scale-95 text-right ${config.color}`}>
