import React, { useState, useMemo } from 'react';
import { ProjectState, TaskLog, Unit } from '../types';
import { STATUS_CONFIG, CONTRACTORS, PUBLIC_AREAS, UNITS_PER_BUILDING } from '../constants';
import { Language, translations } from '../translations';

interface Props {
  state: ProjectState;
  lang: Language;
  onSelectUnit: (buildingId: string, unitId: string | number) => void;
}

const ProjectHistoryView: React.FC<Props> = ({ state, lang, onSelectUnit }) => {
  const [filterBuilding, setFilterBuilding] = useState<string>('all');
  const [filterContractor, setFilterContractor] = useState<string>('all');
  const [filterUnit, setFilterUnit] = useState<string>('all');

  const t = translations[lang];

  // Flatten and filter logs
  const filteredLogs = useMemo(() => {
    const allLogs: { log: TaskLog, unit: Unit }[] = [];
    (Object.values(state.units) as Unit[]).forEach(unit => {
      unit.history.forEach(log => {
        const matchesBuilding = filterBuilding === 'all' || unit.buildingId === filterBuilding;
        const matchesContractor = filterContractor === 'all' || log.contractor === filterContractor;

        const unitIdParts = unit.id.split('-');
        const unitIdentifier = unitIdParts[unitIdParts.length - 1];
        const matchesUnit = filterUnit === 'all' || unitIdentifier === filterUnit;

        if (matchesBuilding && matchesContractor && matchesUnit) {
          allLogs.push({ log, unit });
        }
      });
    });
    // Sort by newest first
    return allLogs.sort((a, b) => b.log.timestamp - a.log.timestamp);
  }, [state, filterBuilding, filterContractor, filterUnit]);

  const resetFilters = () => {
    setFilterBuilding('all');
    setFilterContractor('all');
    setFilterUnit('all');
  };

  return (
    <div className="space-y-6">
      <div className="flex flex-col gap-6">
        <h2 className="text-xl font-bold text-gray-800 flex items-center gap-2">
          <span className="text-2xl">📜</span>
          {t.fullHistoryTitle}
        </h2>

        {/* Filters Grid */}
        <div className="bg-white p-4 rounded-2xl border border-gray-100 shadow-sm grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
          {/* Building Filter */}
          <div className="space-y-1">
            <label className="text-[10px] font-bold text-gray-400 uppercase px-1">{t.filterByBuilding}</label>
            <select 
              value={filterBuilding} 
              onChange={(e) => {
                setFilterBuilding(e.target.value);
                setFilterUnit('all'); // Reset unit when building changes to avoid confusion
              }}
              className="w-full bg-gray-50 border border-gray-200 rounded-xl px-3 py-2.5 text-sm font-bold focus:ring-2 focus:ring-blue-500 outline-none"
            >
              <option value="all">{t.allBuildings}</option>
              {state.buildings.map(b => (
                <option key={b.id} value={b.id}>{lang === 'ru' ? b.name.replace('בניין', 'Здание') : b.name}</option>
              ))}
            </select>
          </div>

          {/* Contractor Filter */}
          <div className="space-y-1">
            <label className="text-[10px] font-bold text-gray-400 uppercase px-1">{t.filterByContractor}</label>
            <select 
              value={filterContractor} 
              onChange={(e) => setFilterContractor(e.target.value)}
              className="w-full bg-gray-50 border border-gray-200 rounded-xl px-3 py-2.5 text-sm font-bold focus:ring-2 focus:ring-blue-500 outline-none"
            >
              <option value="all">{t.allContractors}</option>
              {CONTRACTORS.map(c => (
                <option key={c.id} value={(t as any)[c.labelKey]}>{c.icon} {(t as any)[c.labelKey]}</option>
              ))}
            </select>
          </div>

          {/* Unit Filter */}
          <div className="space-y-1">
            <label className="text-[10px] font-bold text-gray-400 uppercase px-1">{t.filterByUnit}</label>
            <select 
              value={filterUnit} 
              onChange={(e) => setFilterUnit(e.target.value)}
              className="w-full bg-gray-50 border border-gray-200 rounded-xl px-3 py-2.5 text-sm font-bold focus:ring-2 focus:ring-blue-500 outline-none"
            >
              <option value="all">{t.allUnits}</option>
              <optgroup label={t.apartment}>
                {Array.from({ length: UNITS_PER_BUILDING }, (_, i) => i + 1).map(num => (
                  <option key={num} value={num.toString()}>{t.apartment} {num}</option>
                ))}
              </optgroup>
              <optgroup label={t.publicAreas}>
                {PUBLIC_AREAS.map(area => (
                  <option key={area.id} value={area.id}>{(t as any)[area.labelKey]}</option>
                ))}
              </optgroup>
            </select>
          </div>

          {/* Reset Button */}
          <div className="flex items-end">
            <button 
              onClick={resetFilters}
              className="w-full py-2.5 rounded-xl border border-gray-200 text-gray-400 text-xs font-bold hover:bg-gray-50 transition-colors"
            >
              הסר מסננים ×
            </button>
          </div>
        </div>
      </div>

      {filteredLogs.length === 0 ? (
        <div className="bg-white rounded-2xl p-12 text-center border-2 border-dashed text-gray-400">
          <div className="text-4xl mb-4">📂</div>
          <p>{t.noHistory}</p>
        </div>
      ) : (
        <div className="space-y-4">
          <div className="text-[10px] font-bold text-gray-400 px-2 uppercase tracking-widest">
            {t.resultsFound.replace('{count}', filteredLogs.length.toString())}
          </div>
          {filteredLogs.map(({ log, unit }) => {
            const buildingNum = unit.buildingId.split('-')[1];
            const unitIdParts = unit.id.split('-');
            const unitIdentifier = unitIdParts[unitIdParts.length - 1];
            const isPublic = isNaN(Number(unitIdentifier));
            const statusCfg = STATUS_CONFIG[log.status];

            return (
              <div 
                key={log.id} 
                className="bg-white rounded-2xl border border-gray-100 shadow-sm p-4 flex flex-col md:flex-row gap-4 items-start md:items-center hover:border-blue-200 transition-colors"
              >
                <div className={`flex flex-col items-center justify-center p-2 rounded-xl border min-w-[90px] bg-gray-50`}>
                  <span className="text-[10px] text-gray-400 font-bold uppercase">{t.building} {buildingNum}</span>
                  <span className="text-lg font-black text-blue-900 leading-tight">
                    {isPublic ? 'SA' : unitIdentifier}
                  </span>
                  {isPublic && <span className="text-[8px] text-blue-500 font-bold">ציבורי</span>}
                </div>

                <div className="flex-1 space-y-1">
                  <div className="flex flex-wrap items-center gap-2">
                    <span className="text-sm font-bold text-gray-800">{log.workerName}</span>
                    <span className={`text-[10px] px-2 py-0.5 rounded border font-bold ${log.contractor.includes('מנהל') ? 'bg-gray-100 text-gray-700' : 'bg-blue-50 text-blue-600 border-blue-100'}`}>
                      {log.contractor}
                    </span>
                    <span className="text-[10px] text-gray-400 bg-gray-50 px-2 py-0.5 rounded">
                      {new Date(log.timestamp).toLocaleString(lang === 'ru' ? 'ru-RU' : 'he-IL')}
                    </span>
                  </div>
                  <p className="text-sm text-gray-600 line-clamp-2 md:line-clamp-1">{log.description}</p>
                </div>

                <div className="flex items-center gap-3 w-full md:w-auto justify-between md:justify-end">
                  <span className={`text-[10px] px-3 py-1 rounded-full border font-bold ${statusCfg.color}`}>
                    {(t as any)[statusCfg.labelKey]}
                  </span>
                  <button 
                    onClick={() => onSelectUnit(unit.buildingId, isPublic ? unitIdentifier : Number(unitIdentifier))}
                    className="text-blue-600 text-xs font-bold hover:underline whitespace-nowrap bg-blue-50 px-3 py-1.5 rounded-lg"
                  >
                    {t.apartment} ←
                  </button>
                </div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
};

export default ProjectHistoryView;

import React, { useState } from 'react';
import { Unit, TaskStatus, Discipline, Appointment } from '../types';
import { STATUS_CONFIG, PUBLIC_AREAS, CONTRACTORS } from '../constants';
import { Language, translations } from '../translations';

interface Props {
  unit: Unit;
  onClose: () => void;
  onSave: (updates: { 
    newLog?: { status: TaskStatus, workerName: string, contractor: string, description: string, discipline: Discipline },
    newAppointment?: Omit<Appointment, 'id' | 'createdAt' | 'isCompleted'>,
    completeAppointmentId?: string
  }) => void;
  lang: Language;
  activeDiscipline: Discipline;
}

const UnitModal: React.FC<Props> = ({ unit, onClose, onSave, lang, activeDiscipline }) => {
  // Changed default tab to 'history' as requested
  const [activeTab, setActiveTab] = useState<'report' | 'schedule' | 'history'>('history');
  const [worker, setWorker] = useState('');
  const [desc, setDesc] = useState('');
  const [status, setStatus] = useState<TaskStatus>(unit.statuses[activeDiscipline]);
  const [contractor, setContractor] = useState(CONTRACTORS[0].id);
  const [reportDiscipline, setReportDiscipline] = useState<Discipline>(activeDiscipline);

  // Appointment Form State
  const [appDate, setAppDate] = useState('');
  const [appTime, setAppTime] = useState('');
  const [appTenant, setAppTenant] = useState('');
  const [appContractor, setAppContractor] = useState(CONTRACTORS[0].id);
  const [appNotes, setAppNotes] = useState('');

  const t = translations[lang];

  const handleReportSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!worker || !desc) return alert(t.alertFillFields);
    const selectedContractor = (t as any)[CONTRACTORS.find(c => c.id === contractor)?.labelKey || ''];
    onSave({ 
      newLog: { status, workerName: worker, contractor: selectedContractor, description: desc, discipline: reportDiscipline } 
    });
    setWorker('');
    setDesc('');
    setActiveTab('history');
  };

  const handleAppSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!appDate || !appTime || !appTenant) return alert(t.alertFillFields);
    const selectedContractor = (t as any)[CONTRACTORS.find(c => c.id === appContractor)?.labelKey || ''];
    onSave({ 
      newAppointment: { 
        date: appDate, 
        time: appTime, 
        tenantName: appTenant, 
        contractor: selectedContractor,
        notes: appNotes 
      } 
    });
    setAppDate('');
    setAppTime('');
    setAppTenant('');
    setAppNotes('');
  };

  const unitIdentifier = unit.id.split('-').slice(1).join('-');
  const isPublicArea = isNaN(Number(unitIdentifier));
  const publicAreaConfig = isPublicArea ? PUBLIC_AREAS.find(a => a.id === unitIdentifier) : null;
  const displayName = isPublicArea 
    ? (t as any)[publicAreaConfig?.labelKey || ''] 
    : `${t.apartment} ${unitIdentifier}`;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-md">
      <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[95vh]">
        {/* Header with Title and Close Button */}
        <div className="p-6 border-b flex justify-between items-center bg-gray-50/80">
          <div className={lang === 'ru' ? 'text-left' : 'text-right'}>
            <h3 className="text-2xl font-black text-blue-900 tracking-tight">{displayName}</h3>
            <p className="text-xs font-bold text-gray-400 uppercase tracking-widest">{t.building}: {unit.buildingId.split('-')[1]}</p>
          </div>
          <button onClick={onClose} className="w-10 h-10 flex items-center justify-center hover:bg-red-50 hover:text-red-500 rounded-full transition-all text-3xl font-light">&times;</button>
        </div>

        {/* Status Overview - New Section */}
        <div className="bg-white px-6 py-4 flex gap-3 border-b overflow-x-auto no-scrollbar">
          {(['general', 'plumbing'] as Discipline[]).map((disc) => {
            const currentStatus = unit.statuses[disc];
            const cfg = STATUS_CONFIG[currentStatus];
            return (
              <div key={disc} className={`flex-1 min-w-[140px] p-3 rounded-2xl border-2 flex items-center gap-3 transition-all ${cfg.color}`}>
                <span className="text-xl">{disc === 'general' ? '👷' : '🚰'}</span>
                <div className="flex flex-col">
                  <span className="text-[9px] font-black uppercase opacity-60">{(t as any)[disc === 'general' ? 'tabGeneral' : 'tabPlumbing']}</span>
                  <span className="text-xs font-bold leading-none">{(t as any)[cfg.labelKey]}</span>
                </div>
              </div>
            );
          })}
        </div>

        {/* Modal Tabs */}
        <div className="flex border-b bg-gray-50/50">
          <button 
            onClick={() => setActiveTab('history')}
            className={`flex-1 py-4 font-bold text-xs md:text-sm transition-all flex items-center justify-center gap-2 ${activeTab === 'history' ? 'text-blue-600 border-b-2 border-blue-600 bg-white' : 'text-gray-400 hover:text-gray-600'}`}
          >
            📜 {t.viewHistory}
          </button>
          <button 
            onClick={() => setActiveTab('schedule')}
            className={`flex-1 py-4 font-bold text-xs md:text-sm transition-all flex items-center justify-center gap-2 ${activeTab === 'schedule' ? 'text-blue-600 border-b-2 border-blue-600 bg-white' : 'text-gray-400 hover:text-gray-600'}`}
          >
            📅 {t.viewSchedule}
          </button>
          <button 
            onClick={() => setActiveTab('report')}
            className={`flex-1 py-4 font-bold text-xs md:text-sm transition-all flex items-center justify-center gap-2 ${activeTab === 'report' ? 'text-blue-600 border-b-2 border-blue-600 bg-white' : 'text-gray-400 hover:text-gray-600'}`}
          >
            📋 {t.newReport}
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 bg-slate-50/30">
          {activeTab === 'history' && (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
              <div className="flex justify-between items-center mb-6">
                <h4 className="text-sm font-black text-gray-400 uppercase tracking-widest">{t.workHistory}</h4>
                <button 
                  onClick={() => setActiveTab('schedule')}
                  className="text-xs font-bold text-blue-600 bg-blue-50 px-3 py-1.5 rounded-full hover:bg-blue-100 transition-colors"
