                  <p className="italic font-medium">{t.noHistory}</p>
                </div>
              ) : (
                <div className={`space-y-6 relative before:absolute ${lang === 'ru' ? 'before:left-4' : 'before:right-4'} before:top-2 before:bottom-2 before:w-1 before:bg-blue-50`}>
