                          <span className="text-[10px] font-black text-gray-300 bg-gray-50 px-2 py-1 rounded-md">
                            {new Date(log.timestamp).toLocaleString(lang === 'ru' ? 'ru-RU' : 'he-IL')}
                          </span>
                        </div>
                        <p className="text-sm text-gray-600 leading-relaxed font-medium bg-slate-50/50 p-3 rounded-xl border border-slate-100">
                          {log.description}
                        </p>
                        <div className="mt-4 flex justify-end">
                           <span className={`text-[10px] px-3 py-1 rounded-full border font-black uppercase tracking-wider ${STATUS_CONFIG[log.status].color}`}>
                             {(t as any)[STATUS_CONFIG[log.status].labelKey]}
                           </span>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {activeTab === 'schedule' && (
            <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-300">
              <section className="bg-yellow-50/30 p-6 rounded-3xl border-2 border-yellow-100/50">
                <h4 className="text-sm font-black text-yellow-800 mb-5 uppercase tracking-widest flex items-center gap-2">
                  <span>📅</span> {t.scheduleTitle}
                </h4>
                <form onSubmit={handleAppSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-5">
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1">{t.dateLabel}</label>
                    <input type="date" value={appDate} onChange={e => setAppDate(e.target.value)} className="w-full px-4 py-3 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none transition-all font-bold" />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1">{t.timeLabel}</label>
                    <input type="time" value={appTime} onChange={e => setAppTime(e.target.value)} className="w-full px-4 py-3 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none transition-all font-bold" />
                  </div>
                  <div className="md:col-span-2 space-y-1.5">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1">{t.contractorLabel}</label>
                    <select value={appContractor} onChange={e => setAppContractor(e.target.value)} className="w-full px-4 py-3 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none bg-white font-black">
                      {CONTRACTORS.map(c => <option key={c.id} value={c.id}>{c.icon} {(t as any)[c.labelKey]}</option>)}
                    </select>
                  </div>
                  <div className="md:col-span-2 space-y-1.5">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1">{t.tenantLabel}</label>
                    <input type="text" value={appTenant} onChange={e => setAppTenant(e.target.value)} className="w-full px-4 py-3 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none font-bold" placeholder="למשל: משפחת לוי" />
                  </div>
                  <div className="md:col-span-2 space-y-1.5">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1">{t.notesLabel}</label>
                    <textarea value={appNotes} onChange={e => setAppNotes(e.target.value)} rows={2} className="w-full px-4 py-3 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none resize-none font-medium" />
                  </div>
                  <button type="submit" className="md:col-span-2 bg-yellow-500 text-white font-black py-4 rounded-2xl hover:bg-yellow-600 transition-all shadow-lg active:scale-95 text-lg">
                    {t.addAppointment}
                  </button>
                </form>
              </section>

              <section>
                <h4 className="text-sm font-black text-gray-300 mb-5 uppercase tracking-widest">{t.upcomingAppointments}</h4>
                {unit.appointments.length === 0 ? <div className="text-center py-12 text-gray-400 border-2 border-dashed rounded-3xl italic font-medium">{t.noAppointments}</div> : (
                  <div className="space-y-4">
                    {unit.appointments.map(app => (
                      <div key={app.id} className={`p-5 rounded-2xl border-2 flex justify-between items-center transition-all ${app.isCompleted ? 'bg-gray-50 border-gray-100 opacity-60' : 'bg-white border-blue-50 shadow-sm'}`}>
                        <div className="flex-1">
                          <div className="flex items-center gap-3 mb-2">
                            <span className="text-2xl font-black text-blue-900">{app.time}</span>
                            <span className="text-xs font-black text-blue-400 bg-blue-50 px-2 py-1 rounded-md">{app.date}</span>
                          </div>
                          <div className="flex flex-wrap items-center gap-2">
                             <span className="text-md font-black text-gray-800">{app.tenantName}</span>
                             <span className={`text-[10px] px-2 py-0.5 rounded-lg border font-black uppercase shadow-sm ${app.contractor.includes('מנהל') ? 'bg-gray-800 text-white' : 'bg-blue-600 text-white border-blue-600'}`}>{app.contractor}</span>
                          </div>
                          <div className="text-sm text-gray-500 italic mt-2 font-medium">"{app.notes}"</div>
                        </div>
                        {!app.isCompleted && (
                          <button 
                            onClick={() => {
                              onSave({ completeAppointmentId: app.id });
                              setActiveTab('report'); // Suggest adding a report after completion
                            }}
                            className="bg-green-600 text-white px-5 py-3 rounded-2xl text-sm font-black hover:bg-green-700 shadow-md active:scale-95 transition-all"
                          >
                            ✔️ {t.appointmentDone}
                          </button>
                        )}
                      </div>
                    ))}
                  </div>
                )}
              </section>
            </div>
          )}

          {activeTab === 'report' && (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
              <section className="bg-blue-50/20 p-6 rounded-3xl border-2 border-blue-100/50">
                <form onSubmit={handleReportSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-5">
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1">{t.disciplineLabel}</label>
                    <div className="flex bg-white rounded-2xl border-2 border-gray-100 p-1 shadow-inner">
                      <button type="button" onClick={() => setReportDiscipline('plumbing')} className={`flex-1 py-3 rounded-xl text-xs font-black transition-all ${reportDiscipline === 'plumbing' ? 'bg-blue-600 text-white shadow-md' : 'text-gray-400'}`}>{t.tabPlumbing}</button>
                      <button type="button" onClick={() => setReportDiscipline('general')} className={`flex-1 py-3 rounded-xl text-xs font-black transition-all ${reportDiscipline === 'general' ? 'bg-blue-600 text-white shadow-md' : 'text-gray-400'}`}>{t.tabGeneral}</button>
                    </div>
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1">{t.contractorLabel}</label>
                    <select value={contractor} onChange={e => setContractor(e.target.value)} className="w-full px-4 py-3 rounded-2xl border-2 border-gray-100 focus:border-blue-500 outline-none bg-white font-black">
                      {CONTRACTORS.map(c => <option key={c.id} value={c.id}>{c.icon} {(t as any)[c.labelKey]}</option>)}
                    </select>
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1">{t.workerName}</label>
                    <input value={worker} onChange={e => setWorker(e.target.value)} className="w-full px-4 py-3 rounded-2xl border-2 border-gray-100 focus:border-blue-500 outline-none font-bold shadow-sm" placeholder={t.workerExample} />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1">{t.currentStatus}</label>
                    <select value={status} onChange={e => setStatus(e.target.value as TaskStatus)} className="w-full px-4 py-3 rounded-2xl border-2 border-gray-100 focus:border-blue-500 outline-none bg-white font-black shadow-sm">
                      {Object.entries(STATUS_CONFIG).map(([s, cfg]) => <option key={s} value={s}>{(t as any)[cfg.labelKey]}</option>)}
                    </select>
                  </div>
                  <div className="md:col-span-2 space-y-1.5">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1">{t.whatWasDone}</label>
                    <textarea value={desc} onChange={e => setDesc(e.target.value)} rows={4} className="w-full px-4 py-3 rounded-2xl border-2 border-gray-100 focus:border-blue-500 outline-none resize-none font-medium shadow-sm" placeholder={t.descriptionPlaceholder} />
                  </div>
                  <button type="submit" className="md:col-span-2 bg-blue-600 text-white font-black py-5 rounded-2xl hover:bg-blue-700 transition-all shadow-xl active:scale-95 text-lg">
                    {t.updateButton}
                  </button>
                </form>
              </section>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default UnitModal;

import React, { useState, useEffect } from 'react';
import { Unit, TaskStatus, Discipline, Appointment } from '../types';
import { STATUS_CONFIG, PUBLIC_AREAS, CONTRACTORS } from '../constants';
import { Language, translations } from '../translations';

interface Props {
  unit: Unit;
  onClose: () => void;
  onSave: (updates: { 
    newLog?: { status: TaskStatus, workerName: string, contractor: string, description: string, discipline: Discipline },
    newAppointment?: Omit<Appointment, 'id' | 'createdAt' | 'isCompleted'>,
    completeAppointmentId?: string
  }) => void;
  lang: Language;
  activeDiscipline: Discipline;
}

const UnitModal: React.FC<Props> = ({ unit, onClose, onSave, lang, activeDiscipline }) => {
  const [activeTab, setActiveTab] = useState<'report' | 'schedule' | 'history'>('history');
  const [worker, setWorker] = useState('');
  const [desc, setDesc] = useState('');
  const [status, setStatus] = useState<TaskStatus>(unit.statuses[activeDiscipline]);
  const [contractor, setContractor] = useState(CONTRACTORS[0].id);
  const [reportDiscipline, setReportDiscipline] = useState<Discipline>(activeDiscipline);

  // Appointment Form State
  const [appDate, setAppDate] = useState('');
  const [appTime, setAppTime] = useState('');
  const [appTenant, setAppTenant] = useState('');
  const [appContractor, setAppContractor] = useState(CONTRACTORS[0].id);
  const [appNotes, setAppNotes] = useState('');

  const t = translations[lang];

  // Sync internal status if discipline changes in report tab
  useEffect(() => {
    setStatus(unit.statuses[reportDiscipline]);
  }, [reportDiscipline, unit.statuses]);

  const handleQuickAction = (disc: Discipline) => {
    const currentStatus = unit.statuses[disc];

    if (currentStatus === TaskStatus.NOT_STARTED) {
      // Automatic "Start Work"
      onSave({
        newLog: {
          status: TaskStatus.IN_PROGRESS,
          workerName: "מערכת",
          contractor: disc === 'plumbing' ? (t as any).contractor_plumber : (t as any).contractor_workers,
          description: t.startedWorkLog,
          discipline: disc
        }
      });
    } else if (currentStatus === TaskStatus.IN_PROGRESS) {
      // Switch to "Finish Work" rubric
      setReportDiscipline(disc);
      setStatus(TaskStatus.DONE);
      setActiveTab('report');
    } else {
      // Re-open for other statuses
      setReportDiscipline(disc);
      setStatus(TaskStatus.IN_PROGRESS);
      setActiveTab('report');
    }
  };

  const handleReportSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!worker || !desc) return alert(t.alertFillFields);
    const selectedContractor = (t as any)[CONTRACTORS.find(c => c.id === contractor)?.labelKey || ''];
    onSave({ 
      newLog: { status, workerName: worker, contractor: selectedContractor, description: desc, discipline: reportDiscipline } 
    });
    setWorker('');
    setDesc('');
    setActiveTab('history');
  };

  const handleAppSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!appDate || !appTime || !appTenant) return alert(t.alertFillFields);
    const selectedContractor = (t as any)[CONTRACTORS.find(c => c.id === appContractor)?.labelKey || ''];
    onSave({ 
      newAppointment: { 
        date: appDate, 
        time: appTime, 
        tenantName: appTenant, 
        contractor: selectedContractor,
        notes: appNotes 
      } 
    });
    setAppDate('');
    setAppTime('');
    setAppTenant('');
    setAppNotes('');
  };

  const unitIdentifier = unit.id.split('-').slice(1).join('-');
  const isPublicArea = isNaN(Number(unitIdentifier));
  const publicAreaConfig = isPublicArea ? PUBLIC_AREAS.find(a => a.id === unitIdentifier) : null;
  const displayName = isPublicArea 
    ? (t as any)[publicAreaConfig?.labelKey || ''] 
    : `${t.apartment} ${unitIdentifier}`;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/70 backdrop-blur-sm">
      <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[95vh] border border-white/20">

        {/* Header with Title and Close Button */}
        <div className="p-6 border-b flex justify-between items-center bg-gray-50/90 sticky top-0 z-10">
          <div className={lang === 'ru' ? 'text-left' : 'text-right'}>
            <h3 className="text-2xl font-black text-blue-900 tracking-tight">{displayName}</h3>
            <div className="flex items-center gap-2">
               <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{t.building}: {unit.buildingId.split('-')[1]}</span>
               <span className="w-1 h-1 rounded-full bg-gray-300"></span>
               <span className="text-[10px] font-black text-blue-500 uppercase tracking-widest">{unit.history.length} {t.totalReports}</span>
            </div>
          </div>
          <button onClick={onClose} className="w-10 h-10 flex items-center justify-center hover:bg-red-50 hover:text-red-500 rounded-full transition-all text-3xl font-light">&times;</button>
        </div>

        {/* Dynamic Status Action Bar */}
        <div className="bg-slate-100/50 px-6 py-5 flex gap-4 border-b overflow-x-auto no-scrollbar shadow-inner">
          {(['general', 'plumbing'] as Discipline[]).map((disc) => {
            const currentStatus = unit.statuses[disc];
            const cfg = STATUS_CONFIG[currentStatus];
            const isWorking = currentStatus === TaskStatus.IN_PROGRESS;

            return (
              <div 
                key={disc} 
                onClick={() => handleQuickAction(disc)}
                className={`flex-1 min-w-[160px] p-4 rounded-2xl border-2 flex flex-col gap-2 transition-all cursor-pointer shadow-sm active:scale-95 group relative overflow-hidden ${cfg.color} ${isWorking ? 'ring-4 ring-blue-500/20' : 'hover:border-current'}`}
              >
                {isWorking && (
                   <div className="absolute top-0 right-0 w-20 h-20 bg-white/20 rotate-45 translate-x-10 -translate-y-10 group-hover:animate-ping"></div>
                )}

                <div className="flex items-center justify-between">
                  <span className="text-2xl">{disc === 'general' ? '👷' : '🚰'}</span>
                  <div className={`text-[9px] font-black uppercase px-2 py-0.5 rounded-full border border-current opacity-80`}>
                    {(t as any)[disc === 'general' ? 'tabGeneral' : 'tabPlumbing']}
                  </div>
                </div>

                <div className="flex flex-col">
                  <span className="text-xs font-black leading-tight">{(t as any)[cfg.labelKey]}</span>
                  <span className="text-[11px] font-bold mt-2 text-white bg-black/20 rounded-lg py-1 px-3 text-center transition-all group-hover:bg-black/40">
                    {currentStatus === TaskStatus.NOT_STARTED ? t.startWorkAction : 
                     currentStatus === TaskStatus.IN_PROGRESS ? t.finishWorkAction : t.reopenAction}
                  </span>
                </div>
              </div>
            );
          })}
        </div>

        {/* Modal Tabs */}
        <div className="flex border-b bg-white/80 backdrop-blur">
          <button 
            onClick={() => setActiveTab('history')}
            className={`flex-1 py-4 font-black text-xs md:text-sm transition-all flex items-center justify-center gap-2 ${activeTab === 'history' ? 'text-blue-600 border-b-4 border-blue-600' : 'text-gray-400 hover:text-gray-600'}`}
          >
            📜 {t.viewHistory}
          </button>
          <button 
            onClick={() => setActiveTab('schedule')}
            className={`flex-1 py-4 font-black text-xs md:text-sm transition-all flex items-center justify-center gap-2 ${activeTab === 'schedule' ? 'text-blue-600 border-b-4 border-blue-600' : 'text-gray-400 hover:text-gray-600'}`}
          >
            📅 {t.viewSchedule}
          </button>
          <button 
            onClick={() => setActiveTab('report')}
            className={`flex-1 py-4 font-black text-xs md:text-sm transition-all flex items-center justify-center gap-2 ${activeTab === 'report' ? 'text-blue-600 border-b-4 border-blue-600' : 'text-gray-400 hover:text-gray-600'}`}
          >
            📋 {t.newReport}
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 bg-gray-50/30">
          {activeTab === 'history' && (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
              <div className="flex justify-between items-center mb-6">
                <h4 className="text-xs font-black text-gray-400 uppercase tracking-widest">{t.workHistory}</h4>
                <div className="h-0.5 bg-gray-100 flex-1 mx-4"></div>
              </div>

              {unit.history.length === 0 ? (
                <div className="text-center py-20 text-gray-400 border-4 border-dashed border-gray-100 rounded-3xl flex flex-col items-center">
                  <span className="text-5xl mb-4 grayscale opacity-30">📂</span>
                  <p className="font-black text-lg">{t.noHistory}</p>
                  <p className="text-sm font-medium mt-1">לחץ על כפתור "התחל עבודה" כדי להתחיל</p>
                </div>
              ) : (
                <div className={`space-y-6 relative before:absolute ${lang === 'ru' ? 'before:left-4' : 'before:right-4'} before:top-2 before:bottom-2 before:w-1.5 before:bg-blue-50/50 before:rounded-full`}>
                  {unit.history.map((log) => (
                    <div key={log.id} className={`relative ${lang === 'ru' ? 'pl-12' : 'pr-12'}`}>
                      <div className={`absolute ${lang === 'ru' ? 'left-0' : 'right-0'} top-2 w-9 h-9 rounded-2xl border-4 border-white shadow-lg flex items-center justify-center text-sm z-10 transform rotate-3 ${STATUS_CONFIG[log.status].color.split(' ')[0]}`}>
                        {STATUS_CONFIG[log.status].icon}
                      </div>
                      <div className={`bg-white border border-gray-100 rounded-2xl p-5 shadow-sm hover:shadow-lg transition-all ${lang === 'ru' ? 'text-left' : 'text-right'}`}>
                        <div className="flex justify-between items-start mb-4 flex-wrap gap-2 border-b border-gray-50 pb-3">
                          <div className="flex flex-col">
                            <span className="font-black text-blue-900 text-lg leading-tight">{log.workerName}</span>
                            <div className="flex items-center gap-2 mt-2">
                              <span className={`text-[9px] px-2 py-1 rounded-md border font-black uppercase shadow-sm ${log.contractor.includes('מנהל') ? 'bg-gray-800 text-white border-gray-800' : 'bg-blue-600 text-white border-blue-600'}`}>
                                {log.contractor}
                              </span>
                              <span className="text-[9px] px-2 py-1 rounded-md bg-gray-100 text-gray-500 font-black border border-gray-200">
                                {(t as any)[log.discipline === 'plumbing' ? 'tabPlumbing' : 'tabGeneral']}
                              </span>
                            </div>
                          </div>
                          <div className="flex flex-col items-end">
                             <span className="text-[10px] font-black text-gray-300 bg-gray-50 px-2 py-1 rounded-md mb-2">
                               {new Date(log.timestamp).toLocaleDateString(lang === 'ru' ? 'ru-RU' : 'he-IL')} | {new Date(log.timestamp).toLocaleTimeString(lang === 'ru' ? 'ru-RU' : 'he-IL', {hour:'2-digit', minute:'2-digit'})}
                             </span>
                             <span className={`text-[9px] px-3 py-1 rounded-full border font-black uppercase tracking-wider ${STATUS_CONFIG[log.status].color}`}>
                               {(t as any)[STATUS_CONFIG[log.status].labelKey]}
                             </span>
                          </div>
                        </div>
                        <p className="text-sm text-gray-600 leading-relaxed font-bold bg-blue-50/20 p-4 rounded-xl border border-blue-100/30">
                          {log.description}
                        </p>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          )}

          {activeTab === 'schedule' && (
            <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-300">
              <section className="bg-yellow-50/40 p-6 rounded-3xl border-2 border-yellow-100/60 shadow-inner">
                <h4 className="text-xs font-black text-yellow-800 mb-6 uppercase tracking-widest flex items-center gap-3">
                  <span className="bg-yellow-100 p-2 rounded-lg">📅</span> {t.scheduleTitle}
                </h4>
                <form onSubmit={handleAppSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-5">
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1">{t.dateLabel}</label>
                    <input type="date" value={appDate} onChange={e => setAppDate(e.target.value)} className="w-full px-4 py-3 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none transition-all font-black" />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1">{t.timeLabel}</label>
                    <input type="time" value={appTime} onChange={e => setAppTime(e.target.value)} className="w-full px-4 py-3 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none transition-all font-black" />
                  </div>
                  <div className="md:col-span-2 space-y-1.5">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1">{t.contractorLabel}</label>
                    <select value={appContractor} onChange={e => setAppContractor(e.target.value)} className="w-full px-4 py-3 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none bg-white font-black">
                      {CONTRACTORS.map(c => <option key={c.id} value={c.id}>{c.icon} {(t as any)[c.labelKey]}</option>)}
                    </select>
                  </div>
                  <div className="md:col-span-2 space-y-1.5">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1">{t.tenantLabel}</label>
                    <input type="text" value={appTenant} onChange={e => setAppTenant(e.target.value)} className="w-full px-4 py-3 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none font-black shadow-sm" placeholder="שם מלא / טלפון" />
                  </div>
                  <div className="md:col-span-2 space-y-1.5">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1">{t.notesLabel}</label>
                    <textarea value={appNotes} onChange={e => setAppNotes(e.target.value)} rows={2} className="w-full px-4 py-3 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none resize-none font-bold" />
                  </div>
                  <button type="submit" className="md:col-span-2 bg-yellow-500 text-white font-black py-5 rounded-2xl hover:bg-yellow-600 transition-all shadow-lg active:scale-95 text-lg">
                    {t.addAppointment}
                  </button>
                </form>
              </section>

              <section>
                <h4 className="text-xs font-black text-gray-300 mb-5 uppercase tracking-widest">{t.upcomingAppointments}</h4>
                {unit.appointments.length === 0 ? <div className="text-center py-12 text-gray-400 border-4 border-dashed border-gray-100 rounded-3xl italic font-black">{t.noAppointments}</div> : (
                  <div className="space-y-4">
                    {unit.appointments.map(app => (
                      <div key={app.id} className={`p-6 rounded-3xl border-2 flex justify-between items-center transition-all ${app.isCompleted ? 'bg-gray-50 border-gray-100 opacity-60' : 'bg-white border-blue-50 shadow-md'}`}>
                        <div className="flex-1">
                          <div className="flex items-center gap-4 mb-3">
                            <span className="text-3xl font-black text-blue-900">{app.time}</span>
                            <span className="text-[10px] font-black text-blue-400 bg-blue-50 px-3 py-1.5 rounded-xl border border-blue-100 uppercase tracking-tighter">{app.date}</span>
                          </div>
                          <div className="flex flex-wrap items-center gap-2">
                             <span className="text-lg font-black text-gray-800">{app.tenantName}</span>
                             <span className={`text-[10px] px-2 py-1 rounded-lg border font-black uppercase shadow-sm ${app.contractor.includes('מנהל') ? 'bg-gray-800 text-white' : 'bg-blue-600 text-white border-blue-600'}`}>{app.contractor}</span>
                          </div>
                          <div className="text-sm text-gray-500 italic mt-3 font-bold bg-slate-50 p-2 rounded-lg">"{app.notes}"</div>
                        </div>
                        {!app.isCompleted && (
                          <button 
                            onClick={() => {
                              onSave({ completeAppointmentId: app.id });
                              setActiveTab('report');
                            }}
                            className="bg-green-600 text-white px-6 py-4 rounded-2xl text-md font-black hover:bg-green-700 shadow-xl active:scale-95 transition-all"
                          >
                            {t.appointmentDone}
                          </button>
                        )}
                      </div>
                    ))}
                  </div>
                )}
              </section>
            </div>
          )}

          {activeTab === 'report' && (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
              <section className="bg-blue-50/30 p-8 rounded-[2.5rem] border-2 border-blue-100 shadow-inner">
                <h4 className="text-sm font-black text-blue-800 mb-8 uppercase tracking-[0.2em] text-center border-b pb-4 border-blue-100/50">
                   🚀 {t.newReport}
                </h4>
                <form onSubmit={handleReportSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.disciplineLabel}</label>
                    <div className="flex bg-white rounded-2xl border-2 border-gray-100 p-1.5 shadow-sm">
                      <button type="button" onClick={() => setReportDiscipline('plumbing')} className={`flex-1 py-3.5 rounded-xl text-xs font-black transition-all ${reportDiscipline === 'plumbing' ? 'bg-blue-600 text-white shadow-xl scale-[1.02]' : 'text-gray-400 hover:bg-gray-50'}`}>{t.tabPlumbing}</button>
                      <button type="button" onClick={() => setReportDiscipline('general')} className={`flex-1 py-3.5 rounded-xl text-xs font-black transition-all ${reportDiscipline === 'general' ? 'bg-blue-600 text-white shadow-xl scale-[1.02]' : 'text-gray-400 hover:bg-gray-50'}`}>{t.tabGeneral}</button>
                    </div>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.contractorLabel}</label>
                    <select value={contractor} onChange={e => setContractor(e.target.value)} className="w-full px-5 py-4 rounded-2xl border-2 border-gray-100 focus:border-blue-500 outline-none bg-white font-black shadow-sm">
                      {CONTRACTORS.map(c => <option key={c.id} value={c.id}>{c.icon} {(t as any)[c.labelKey]}</option>)}
                    </select>
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.workerName}</label>
                    <input value={worker} onChange={e => setWorker(e.target.value)} className="w-full px-5 py-4 rounded-2xl border-2 border-gray-100 focus:border-blue-500 outline-none font-black shadow-sm placeholder:opacity-30" placeholder={t.workerExample} />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.currentStatus}</label>
                    <select value={status} onChange={e => setStatus(e.target.value as TaskStatus)} className="w-full px-5 py-4 rounded-2xl border-2 border-gray-100 focus:border-blue-500 outline-none bg-white font-black shadow-sm">
                      {Object.entries(STATUS_CONFIG).map(([s, cfg]) => <option key={s} value={s}>{(t as any)[cfg.labelKey]}</option>)}
                    </select>
                  </div>
                  <div className="md:col-span-2 space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.whatWasDone}</label>
                    <textarea value={desc} onChange={e => setDesc(e.target.value)} rows={5} className="w-full px-5 py-4 rounded-3xl border-2 border-gray-100 focus:border-blue-500 outline-none resize-none font-bold shadow-sm placeholder:opacity-30" placeholder={t.descriptionPlaceholder} />
                  </div>
                  <button type="submit" className="md:col-span-2 bg-blue-600 text-white font-black py-6 rounded-3xl hover:bg-blue-700 transition-all shadow-2xl active:scale-95 text-xl tracking-[0.1em]">
                    {t.updateButton}
                  </button>
                </form>
              </section>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default UnitModal;

import React, { useState, useEffect } from 'react';
import { Unit, TaskStatus, Discipline, Appointment, TaskLog } from '../types';
import { STATUS_CONFIG, PUBLIC_AREAS, CONTRACTORS } from '../constants';
import { Language, translations } from '../translations';

interface Props {
  unit: Unit;
  onClose: () => void;
  onSave: (updates: { 
    newLog?: { status: TaskStatus, workerName: string, contractor: string, description: string, discipline: Discipline },
    newAppointment?: Omit<Appointment, 'id' | 'createdAt' | 'isCompleted'>,
    completeAppointmentId?: string
  }) => void;
  lang: Language;
  activeDiscipline: Discipline;
}

const UnitModal: React.FC<Props> = ({ unit, onClose, onSave, lang, activeDiscipline }) => {
  const [activeTab, setActiveTab] = useState<'report' | 'schedule' | 'history'>('history');
  const [worker, setWorker] = useState('');
  const [desc, setDesc] = useState('');
  const [status, setStatus] = useState<TaskStatus>(unit.statuses[activeDiscipline]);
  const [contractor, setContractor] = useState(CONTRACTORS[0].id);
  const [reportDiscipline, setReportDiscipline] = useState<Discipline>(activeDiscipline);

  // Appointment Form State
  const [appDate, setAppDate] = useState('');
  const [appTime, setAppTime] = useState('');
  const [appTenant, setAppTenant] = useState('');
  const [appContractor, setAppContractor] = useState(CONTRACTORS[0].id);
  const [appNotes, setAppNotes] = useState('');

  const t = translations[lang];

  // Sync internal status if discipline changes in report tab
  useEffect(() => {
    setStatus(unit.statuses[reportDiscipline]);
  }, [reportDiscipline, unit.statuses]);

  const handleQuickAction = (disc: Discipline) => {
    const currentStatus = unit.statuses[disc];

    if (currentStatus === TaskStatus.NOT_STARTED) {
      onSave({
        newLog: {
          status: TaskStatus.IN_PROGRESS,
          workerName: "מערכת",
          contractor: disc === 'plumbing' ? (t as any).contractor_plumber : (t as any).contractor_workers,
          description: t.startedWorkLog,
          discipline: disc
        }
      });
    } else if (currentStatus === TaskStatus.IN_PROGRESS) {
      setReportDiscipline(disc);
      setStatus(TaskStatus.DONE);
      setActiveTab('report');
    } else {
      setReportDiscipline(disc);
      setStatus(TaskStatus.IN_PROGRESS);
      setActiveTab('report');
    }
  };

  const handleContinueFromHistory = (log: TaskLog) => {
    setReportDiscipline(log.discipline);
    setWorker(log.workerName);
    // Find the contractor ID based on the label stored in history
    const contractorObj = CONTRACTORS.find(c => (t as any)[c.labelKey] === log.contractor);
    if (contractorObj) setContractor(contractorObj.id);

    // Default to "DONE" when continuing an "IN_PROGRESS" task
    setStatus(TaskStatus.DONE);
    setDesc(log.description + " - "); // Append to existing description
    setActiveTab('report');
  };

  const handleReportSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!worker || !desc) return alert(t.alertFillFields);
    const selectedContractor = (t as any)[CONTRACTORS.find(c => c.id === contractor)?.labelKey || ''];
    onSave({ 
      newLog: { status, workerName: worker, contractor: selectedContractor, description: desc, discipline: reportDiscipline } 
    });
    setWorker('');
    setDesc('');
    setActiveTab('history');
  };

  const handleAppSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!appDate || !appTime || !appTenant) return alert(t.alertFillFields);
    const selectedContractor = (t as any)[CONTRACTORS.find(c => c.id === appContractor)?.labelKey || ''];
    onSave({ 
      newAppointment: { 
        date: appDate, 
        time: appTime, 
        tenantName: appTenant, 
        contractor: selectedContractor,
        notes: appNotes 
      } 
    });
    setAppDate('');
    setAppTime('');
    setAppTenant('');
    setAppNotes('');
  };

  const unitIdentifier = unit.id.split('-').slice(1).join('-');
  const isPublicArea = isNaN(Number(unitIdentifier));
  const publicAreaConfig = isPublicArea ? PUBLIC_AREAS.find(a => a.id === unitIdentifier) : null;
  const displayName = isPublicArea 
    ? (t as any)[publicAreaConfig?.labelKey || ''] 
    : `${t.apartment} ${unitIdentifier}`;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/70 backdrop-blur-sm">
      <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[95vh] border border-white/20">

        {/* Header with Title and Close Button */}
        <div className="p-6 border-b flex justify-between items-center bg-gray-50/90 sticky top-0 z-10">
          <div className={lang === 'ru' ? 'text-left' : 'text-right'}>
            <h3 className="text-2xl font-black text-blue-900 tracking-tight">{displayName}</h3>
            <div className="flex items-center gap-2">
               <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{t.building}: {unit.buildingId.split('-')[1]}</span>
               <span className="w-1 h-1 rounded-full bg-gray-300"></span>
               <span className="text-[10px] font-black text-blue-500 uppercase tracking-widest">{unit.history.length} {t.totalReports}</span>
            </div>
          </div>
          <button onClick={onClose} className="w-10 h-10 flex items-center justify-center hover:bg-red-50 hover:text-red-500 rounded-full transition-all text-3xl font-light">&times;</button>
        </div>

        {/* Dynamic Status Action Bar */}
        <div className="bg-slate-100/50 px-6 py-5 flex gap-4 border-b overflow-x-auto no-scrollbar shadow-inner">
          {(['general', 'plumbing'] as Discipline[]).map((disc) => {
            const currentStatus = unit.statuses[disc];
            const cfg = STATUS_CONFIG[currentStatus];
            const isWorking = currentStatus === TaskStatus.IN_PROGRESS;

            return (
              <div 
                key={disc} 
                onClick={() => handleQuickAction(disc)}
                className={`flex-1 min-w-[160px] p-4 rounded-2xl border-2 flex flex-col gap-2 transition-all cursor-pointer shadow-sm active:scale-95 group relative overflow-hidden ${cfg.color} ${isWorking ? 'ring-4 ring-blue-500/20' : 'hover:border-current'}`}
              >
                {isWorking && (
                   <div className="absolute top-0 right-0 w-20 h-20 bg-white/20 rotate-45 translate-x-10 -translate-y-10 group-hover:animate-ping"></div>
                )}

                <div className="flex items-center justify-between">
                  <span className="text-2xl">{disc === 'general' ? '👷' : '🚰'}</span>
                  <div className={`text-[9px] font-black uppercase px-2 py-0.5 rounded-full border border-current opacity-80`}>
                    {(t as any)[disc === 'general' ? 'tabGeneral' : 'tabPlumbing']}
                  </div>
                </div>

                <div className="flex flex-col">
                  <span className="text-xs font-black leading-tight">{(t as any)[cfg.labelKey]}</span>
                  <span className="text-[11px] font-bold mt-2 text-white bg-black/20 rounded-lg py-1 px-3 text-center transition-all group-hover:bg-black/40">
                    {currentStatus === TaskStatus.NOT_STARTED ? t.startWorkAction : 
                     currentStatus === TaskStatus.IN_PROGRESS ? t.finishWorkAction : t.reopenAction}
                  </span>
                </div>
              </div>
            );
          })}
        </div>

        {/* Modal Tabs */}
        <div className="flex border-b bg-white/80 backdrop-blur">
          <button 
            onClick={() => setActiveTab('history')}
            className={`flex-1 py-4 font-black text-xs md:text-sm transition-all flex items-center justify-center gap-2 ${activeTab === 'history' ? 'text-blue-600 border-b-4 border-blue-600' : 'text-gray-400 hover:text-gray-600'}`}
          >
            📜 {t.viewHistory}
          </button>
          <button 
            onClick={() => setActiveTab('schedule')}
            className={`flex-1 py-4 font-black text-xs md:text-sm transition-all flex items-center justify-center gap-2 ${activeTab === 'schedule' ? 'text-blue-600 border-b-4 border-blue-600' : 'text-gray-400 hover:text-gray-600'}`}
          >
            📅 {t.viewSchedule}
          </button>
          <button 
            onClick={() => setActiveTab('report')}
            className={`flex-1 py-4 font-black text-xs md:text-sm transition-all flex items-center justify-center gap-2 ${activeTab === 'report' ? 'text-blue-600 border-b-4 border-blue-600' : 'text-gray-400 hover:text-gray-600'}`}
          >
            📋 {t.newReport}
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 bg-gray-50/30">
          {activeTab === 'history' && (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
              <div className="flex justify-between items-center mb-6">
                <h4 className="text-xs font-black text-gray-400 uppercase tracking-widest">{t.workHistory}</h4>
                <div className="h-0.5 bg-gray-100 flex-1 mx-4"></div>
              </div>

              {unit.history.length === 0 ? (
                <div className="text-center py-20 text-gray-400 border-4 border-dashed border-gray-100 rounded-3xl flex flex-col items-center">
                  <span className="text-5xl mb-4 grayscale opacity-30">📂</span>
                  <p className="font-black text-lg">{t.noHistory}</p>
                  <p className="text-sm font-medium mt-1">לחץ על כפתור "התחל עבודה" כדי להתחיל</p>
                </div>
              ) : (
                <div className={`space-y-6 relative before:absolute ${lang === 'ru' ? 'before:left-4' : 'before:right-4'} before:top-2 before:bottom-2 before:w-1.5 before:bg-blue-50/50 before:rounded-full`}>
                  {unit.history.map((log) => {
                    const isInProgress = log.status === TaskStatus.IN_PROGRESS;
                    return (
                      <div key={log.id} className={`relative ${lang === 'ru' ? 'pl-12' : 'pr-12'}`}>
                        <div className={`absolute ${lang === 'ru' ? 'left-0' : 'right-0'} top-2 w-9 h-9 rounded-2xl border-4 border-white shadow-lg flex items-center justify-center text-sm z-10 transform rotate-3 ${STATUS_CONFIG[log.status].color.split(' ')[0]}`}>
                          {STATUS_CONFIG[log.status].icon}
                        </div>
                        <div 
                          className={`bg-white border-2 rounded-2xl p-5 shadow-sm transition-all ${lang === 'ru' ? 'text-left' : 'text-right'} ${isInProgress ? 'border-blue-400 shadow-md ring-4 ring-blue-500/5 hover:scale-[1.01] cursor-pointer' : 'border-gray-100'}`}
                          onClick={() => isInProgress && handleContinueFromHistory(log)}
                        >
                          <div className="flex justify-between items-start mb-4 flex-wrap gap-2 border-b border-gray-50 pb-3">
                            <div className="flex flex-col">
                              <span className="font-black text-blue-900 text-lg leading-tight">{log.workerName}</span>
                              <div className="flex items-center gap-2 mt-2">
                                <span className={`text-[9px] px-2 py-1 rounded-md border font-black uppercase shadow-sm ${log.contractor.includes('מנהל') ? 'bg-gray-800 text-white border-gray-800' : 'bg-blue-600 text-white border-blue-600'}`}>
                                  {log.contractor}
                                </span>
                                <span className="text-[9px] px-2 py-1 rounded-md bg-gray-100 text-gray-500 font-black border border-gray-200">
                                  {(t as any)[log.discipline === 'plumbing' ? 'tabPlumbing' : 'tabGeneral']}
                                </span>
                              </div>
                            </div>
                            <div className="flex flex-col items-end">
                               <span className="text-[10px] font-black text-gray-300 bg-gray-50 px-2 py-1 rounded-md mb-2">
                                 {new Date(log.timestamp).toLocaleDateString(lang === 'ru' ? 'ru-RU' : 'he-IL')} | {new Date(log.timestamp).toLocaleTimeString(lang === 'ru' ? 'ru-RU' : 'he-IL', {hour:'2-digit', minute:'2-digit'})}
                               </span>
                               <span className={`text-[9px] px-3 py-1 rounded-full border font-black uppercase tracking-wider ${STATUS_CONFIG[log.status].color}`}>
                                 {(t as any)[STATUS_CONFIG[log.status].labelKey]}
                               </span>
                            </div>
                          </div>

                          <p className="text-sm text-gray-600 leading-relaxed font-bold bg-blue-50/20 p-4 rounded-xl border border-blue-100/30">
                            {log.description}
                          </p>

                          {isInProgress && (
                            <div className="mt-4 flex justify-center">
                              <button 
                                onClick={(e) => {
                                  e.stopPropagation();
                                  handleContinueFromHistory(log);
                                }}
                                className="bg-blue-600 text-white text-[11px] font-black px-4 py-2 rounded-xl shadow-lg hover:bg-blue-700 transition-all flex items-center gap-2"
                              >
                                ✍️ המשך/עדכון עבודה
                              </button>
                            </div>
                          )}
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          )}

          {activeTab === 'schedule' && (
            <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-300">
              <section className="bg-yellow-50/40 p-6 rounded-3xl border-2 border-yellow-100/60 shadow-inner">
                <h4 className="text-xs font-black text-yellow-800 mb-6 uppercase tracking-widest flex items-center gap-3">
                  <span className="bg-yellow-100 p-2 rounded-lg">📅</span> {t.scheduleTitle}
                </h4>
                <form onSubmit={handleAppSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-5">
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1">{t.dateLabel}</label>
                    <input type="date" value={appDate} onChange={e => setAppDate(e.target.value)} className="w-full px-4 py-3 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none transition-all font-black" />
                  </div>
                  <div className="space-y-1.5">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1">{t.timeLabel}</label>
                    <input type="time" value={appTime} onChange={e => setAppTime(e.target.value)} className="w-full px-4 py-3 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none transition-all font-black" />
                  </div>
                  <div className="md:col-span-2 space-y-1.5">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1">{t.contractorLabel}</label>
                    <select value={appContractor} onChange={e => setAppContractor(e.target.value)} className="w-full px-4 py-3 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none bg-white font-black">
                      {CONTRACTORS.map(c => <option key={c.id} value={c.id}>{c.icon} {(t as any)[c.labelKey]}</option>)}
                    </select>
                  </div>
                  <div className="md:col-span-2 space-y-1.5">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1">{t.tenantLabel}</label>
                    <input type="text" value={appTenant} onChange={e => setAppTenant(e.target.value)} className="w-full px-4 py-3 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none font-black shadow-sm" placeholder="שם מלא / טלפון" />
                  </div>
                  <div className="md:col-span-2 space-y-1.5">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1">{t.notesLabel}</label>
                    <textarea value={appNotes} onChange={e => setAppNotes(e.target.value)} rows={2} className="w-full px-4 py-3 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none resize-none font-bold" />
                  </div>
                  <button type="submit" className="md:col-span-2 bg-yellow-500 text-white font-black py-5 rounded-2xl hover:bg-yellow-600 transition-all shadow-lg active:scale-95 text-lg">
                    {t.addAppointment}
                  </button>
                </form>
              </section>

              <section>
                <h4 className="text-xs font-black text-gray-300 mb-5 uppercase tracking-widest">{t.upcomingAppointments}</h4>
                {unit.appointments.length === 0 ? <div className="text-center py-12 text-gray-400 border-4 border-dashed border-gray-100 rounded-3xl italic font-black">{t.noAppointments}</div> : (
                  <div className="space-y-4">
                    {unit.appointments.map(app => (
                      <div key={app.id} className={`p-6 rounded-3xl border-2 flex justify-between items-center transition-all ${app.isCompleted ? 'bg-gray-50 border-gray-100 opacity-60' : 'bg-white border-blue-50 shadow-md'}`}>
                        <div className="flex-1">
                          <div className="flex items-center gap-4 mb-3">
                            <span className="text-3xl font-black text-blue-900">{app.time}</span>
                            <span className="text-[10px] font-black text-blue-400 bg-blue-50 px-3 py-1.5 rounded-xl border border-blue-100 uppercase tracking-tighter">{app.date}</span>
                          </div>
                          <div className="flex flex-wrap items-center gap-2">
                             <span className="text-lg font-black text-gray-800">{app.tenantName}</span>
                             <span className={`text-[10px] px-2 py-1 rounded-lg border font-black uppercase shadow-sm ${app.contractor.includes('מנהל') ? 'bg-gray-800 text-white' : 'bg-blue-600 text-white border-blue-600'}`}>{app.contractor}</span>
                          </div>
                          <div className="text-sm text-gray-500 italic mt-3 font-bold bg-slate-50 p-2 rounded-lg">"{app.notes}"</div>
                        </div>
                        {!app.isCompleted && (
                          <button 
                            onClick={() => {
                              onSave({ completeAppointmentId: app.id });
                              setActiveTab('report');
                            }}
                            className="bg-green-600 text-white px-6 py-4 rounded-2xl text-md font-black hover:bg-green-700 shadow-xl active:scale-95 transition-all"
                          >
                            {t.appointmentDone}
                          </button>
                        )}
                      </div>
                    ))}
                  </div>
                )}
              </section>
            </div>
          )}

          {activeTab === 'report' && (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
              <section className="bg-blue-50/30 p-8 rounded-[2.5rem] border-2 border-blue-100 shadow-inner">
                <h4 className="text-sm font-black text-blue-800 mb-8 uppercase tracking-[0.2em] text-center border-b pb-4 border-blue-100/50">
                   🚀 {t.newReport}
                </h4>
                <form onSubmit={handleReportSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.disciplineLabel}</label>
                    <div className="flex bg-white rounded-2xl border-2 border-gray-100 p-1.5 shadow-sm">
                      <button type="button" onClick={() => setReportDiscipline('plumbing')} className={`flex-1 py-3.5 rounded-xl text-xs font-black transition-all ${reportDiscipline === 'plumbing' ? 'bg-blue-600 text-white shadow-xl scale-[1.02]' : 'text-gray-400 hover:bg-gray-50'}`}>{t.tabPlumbing}</button>
                      <button type="button" onClick={() => setReportDiscipline('general')} className={`flex-1 py-3.5 rounded-xl text-xs font-black transition-all ${reportDiscipline === 'general' ? 'bg-blue-600 text-white shadow-xl scale-[1.02]' : 'text-gray-400 hover:bg-gray-50'}`}>{t.tabGeneral}</button>
                    </div>
                  </div>
                  <div className="space-y-2">
