            {selectedBuildingId && (
              <section className="mt-6 animate-in fade-in slide-in-from-bottom-4 duration-500">
                {viewMode === 'units' ? (
                  <UnitGrid buildingId={selectedBuildingId} state={state} onSelectUnit={(num) => setSelectedUnitId(num)} lang={lang} discipline={activeDiscipline} />
