import React, { useState, useEffect } from 'react';
import { Unit, TaskStatus, Discipline, Appointment, TaskLog } from '../types';
import { STATUS_CONFIG, PUBLIC_AREAS, CONTRACTORS } from '../constants';
import { Language, translations } from '../translations';

interface Props {
  unit: Unit;
  onClose: () => void;
  onSave: (updates: { 
    newLog?: { status: TaskStatus, workerName: string, contractor: string, description: string, discipline: Discipline },
    updateLogStatus?: { logId: string, newStatus: TaskStatus },
    newAppointment?: Omit<Appointment, 'id' | 'createdAt' | 'isCompleted'>,
    completeAppointmentId?: string
  }) => void;
  lang: Language;
  activeDiscipline: Discipline;
}

const UnitModal: React.FC<Props> = ({ unit, onClose, onSave, lang, activeDiscipline }) => {
  const [activeTab, setActiveTab] = useState<'report' | 'schedule' | 'history'>('history');
  const [worker, setWorker] = useState('');
  const [desc, setDesc] = useState('');
  const [status, setStatus] = useState<TaskStatus>(unit.statuses[activeDiscipline]);
  const [contractor, setContractor] = useState(CONTRACTORS[0].id);
  const [reportDiscipline, setReportDiscipline] = useState<Discipline>(activeDiscipline);
  const [editingLogId, setEditingLogId] = useState<string | null>(null);

  // Appointment Form State
  const [appDate, setAppDate] = useState('');
  const [appTime, setAppTime] = useState('');
  const [appTenant, setAppTenant] = useState('');
  const [appContractor, setAppContractor] = useState(CONTRACTORS[0].id);
  const [appNotes, setAppNotes] = useState('');

  const t = translations[lang];

  // Sync internal status if discipline changes in report tab
  useEffect(() => {
    setStatus(unit.statuses[reportDiscipline]);
  }, [reportDiscipline, unit.statuses]);

  const handleQuickAction = (disc: Discipline) => {
    const currentStatus = unit.statuses[disc];

    if (currentStatus === TaskStatus.NOT_STARTED) {
      onSave({
        newLog: {
          status: TaskStatus.IN_PROGRESS,
          workerName: "מערכת",
          contractor: disc === 'plumbing' ? (t as any).contractor_plumber : (t as any).contractor_workers,
          description: t.startedWorkLog,
          discipline: disc
        }
      });
    } else if (currentStatus === TaskStatus.IN_PROGRESS) {
      setReportDiscipline(disc);
      setStatus(TaskStatus.DONE);
      setActiveTab('report');
    } else {
      setReportDiscipline(disc);
      setStatus(TaskStatus.IN_PROGRESS);
      setActiveTab('report');
    }
  };

  const handleQuickStatusUpdate = (logId: string, newStatus: TaskStatus) => {
    onSave({ updateLogStatus: { logId, newStatus } });
    setEditingLogId(null);
  };

  const handleReportSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!worker || !desc) return alert(t.alertFillFields);
    const selectedContractor = (t as any)[CONTRACTORS.find(c => c.id === contractor)?.labelKey || ''];
    onSave({ 
      newLog: { status, workerName: worker, contractor: selectedContractor, description: desc, discipline: reportDiscipline } 
    });
    setWorker('');
    setDesc('');
    setActiveTab('history');
  };

  const handleAppSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!appDate || !appTime || !appTenant) return alert(t.alertFillFields);
    const selectedContractor = (t as any)[CONTRACTORS.find(c => c.id === appContractor)?.labelKey || ''];
    onSave({ 
      newAppointment: { 
        date: appDate, 
        time: appTime, 
        tenantName: appTenant, 
        contractor: selectedContractor,
        notes: appNotes 
      } 
    });
    setAppDate('');
    setAppTime('');
    setAppTenant('');
    setAppNotes('');
  };

  const unitIdentifier = unit.id.split('-').slice(1).join('-');
  const isPublicArea = isNaN(Number(unitIdentifier));
  const publicAreaConfig = isPublicArea ? PUBLIC_AREAS.find(a => a.id === unitIdentifier) : null;
  const displayName = isPublicArea 
    ? (t as any)[publicAreaConfig?.labelKey || ''] 
    : `${t.apartment} ${unitIdentifier}`;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/70 backdrop-blur-sm">
      <div className="bg-white w-full max-w-2xl rounded-3xl shadow-2xl overflow-hidden flex flex-col max-h-[95vh] border border-white/20">

