            <h3 className="text-2xl font-black text-blue-900 tracking-tight">{displayName}</h3>
            <div className="flex items-center gap-2">
               <span className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{t.building}: {unit.buildingId.split('-')[1]}</span>
               <span className="w-1 h-1 rounded-full bg-gray-300"></span>
               <span className="text-[10px] font-black text-blue-500 uppercase tracking-widest">{unit.history.length} {t.totalReports}</span>
            </div>
          </div>
          <button onClick={onClose} className="w-10 h-10 flex items-center justify-center hover:bg-red-50 hover:text-red-500 rounded-full transition-all text-3xl font-light">&times;</button>
        </div>

        {/* Dynamic Status Action Bar */}
        <div className="bg-slate-100/50 px-6 py-5 flex gap-4 border-b overflow-x-auto no-scrollbar shadow-inner">
