                  <span className="text-2xl">{disc === 'general' ? '👷' : '🚰'}</span>
                  <div className={`text-[9px] font-black uppercase px-2 py-0.5 rounded-full border border-current opacity-80`}>
                    {(t as any)[disc === 'general' ? 'tabGeneral' : 'tabPlumbing']}
