          >
            📅 {t.viewSchedule}
          </button>
          <button 
            onClick={() => setActiveTab('report')}
            className={`flex-1 py-4 font-black text-xs md:text-sm transition-all flex items-center justify-center gap-2 ${activeTab === 'report' ? 'text-blue-600 border-b-4 border-blue-600' : 'text-gray-400 hover:text-gray-600'}`}
          >
            📋 {t.newReport}
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 bg-gray-50/30">
          {activeTab === 'history' && (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
              <div className="flex justify-between items-center mb-6">
                <h4 className="text-xs font-black text-gray-400 uppercase tracking-widest">{t.workHistory}</h4>
                <div className="h-0.5 bg-gray-100 flex-1 mx-4"></div>
              </div>

              {unit.history.length === 0 ? (
                <div className="text-center py-20 text-gray-400 border-4 border-dashed border-gray-100 rounded-3xl flex flex-col items-center">
                  <span className="text-5xl mb-4 grayscale opacity-30">📂</span>
                  <p className="font-black text-lg">{t.noHistory}</p>
