                                 onClick={() => setEditingLogId(log.id)}
                                 className={`text-[9px] px-3 py-1 rounded-full border font-black uppercase tracking-wider transition-all hover:brightness-90 ${STATUS_CONFIG[log.status].color}`}
                               >
                                 {(t as any)[STATUS_CONFIG[log.status].labelKey]} ✏️
                               </button>
                             )}
                          </div>
                        </div>
                        <p className="text-sm text-gray-600 leading-relaxed font-bold bg-blue-50/20 p-4 rounded-xl border border-blue-100/30">
                          {log.description}
                        </p>

                        {/* Quick Action: Mark as Done if not already done */}
                        {log.status !== TaskStatus.DONE && (
                          <div className="mt-4 flex justify-end">
                            <button 
                              onClick={() => handleQuickStatusUpdate(log.id, TaskStatus.DONE)}
