import React, { useState, useEffect, useMemo } from 'react';
import { ProjectState, TaskStatus, Unit, Discipline, Appointment } from './types';
import { initializeData, getUnit, updateUnit } from './services/dataService';
import BuildingSelector from './components/BuildingSelector';
import UnitGrid from './components/UnitGrid';
import UnitModal from './components/UnitModal';
import ContractorView from './components/ContractorView';
import ScheduleView from './components/ScheduleView';
import ProjectHistoryView from './components/ProjectHistoryView';
import { Language, translations } from './translations';
import { PUBLIC_AREAS, STATUS_CONFIG } from './constants';

const App: React.FC = () => {
  const [state, setState] = useState<ProjectState>(() => initializeData());
  const [selectedBuildingId, setSelectedBuildingId] = useState<string | null>(null);
  const [selectedUnitId, setSelectedUnitId] = useState<string | number | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'units' | 'public' | 'contractors' | 'schedule' | 'history'>('units');

  const [lang, setLang] = useState<Language>(() => {
    return (localStorage.getItem('app_lang') as Language) || 'he';
  });

  useEffect(() => {
    localStorage.setItem('app_lang', lang);
    document.documentElement.dir = lang === 'he' ? 'rtl' : 'ltr';
    document.documentElement.lang = lang;
  }, [lang]);

  const t = translations[lang];

  useEffect(() => {
    if (!selectedBuildingId && state.buildings.length > 0) {
      setSelectedBuildingId(state.buildings[0].id);
    }
  }, [state.buildings, selectedBuildingId]);

  const activeUnit = useMemo(() => {
    if (!selectedBuildingId || selectedUnitId === null) return null;
    return getUnit(state, selectedBuildingId, selectedUnitId);
  }, [state, selectedBuildingId, selectedUnitId]);

  const handleUpdateUnit = (updates: { 
    newLog?: { status: TaskStatus, workerName: string, contractor: string, description: string, discipline: Discipline },
    updateLogStatus?: { logId: string, newStatus: TaskStatus },
    newAppointment?: Omit<Appointment, 'id' | 'createdAt' | 'isCompleted'>,
    completeAppointmentId?: string
  }) => {
    if (!activeUnit) return;
    const newState = updateUnit(state, activeUnit, {
      newLog: updates.newLog,
      updateLogStatus: updates.updateLogStatus,
      newAppointment: updates.newAppointment,
      completeAppointmentId: updates.completeAppointmentId
    });
    setState(newState);
  };

  const filteredBuildings = state.buildings.filter(b => {
    const buildingName = lang === 'ru' ? b.name.replace('בניין', 'Здание') : b.name;
    return buildingName.includes(searchTerm) || b.id.includes(searchTerm) || b.name.includes(searchTerm);
  });

  const toggleLanguage = () => {
    setLang(prev => prev === 'he' ? 'ru' : 'he');
  };

  const handleSelectFromOtherView = (buildingId: string, unitId: string | number) => {
    setSelectedBuildingId(buildingId);
    setSelectedUnitId(unitId);
    setViewMode('units');
  };

  return (
    <div className={`min-h-screen bg-slate-50 ${lang === 'ru' ? 'text-left' : 'text-right'}`} dir={lang === 'he' ? 'rtl' : 'ltr'}>
      <header className="sticky top-0 z-40 bg-blue-900 text-white shadow-lg p-4">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-3 w-full md:w-auto">
            <div className="bg-white p-2 px-3 rounded-lg text-blue-900 text-xl font-black shadow-lg">בדק</div>
            <div className="flex-1">
              <h1 className="text-xl font-black leading-none">{t.appName}</h1>
              <p className="text-[10px] text-blue-300 mt-1 uppercase tracking-widest font-bold">{t.appSubName}</p>
            </div>
            <button onClick={toggleLanguage} className="md:hidden bg-blue-800 hover:bg-blue-700 px-3 py-1 rounded-full text-xs font-bold transition-colors border border-blue-600">
              {t.langToggle}
            </button>
          </div>

          <div className="flex items-center gap-4 w-full md:w-auto">
            <div className="flex-1 md:w-64 relative">
              <input type="text" placeholder={t.searchPlaceholder} value={searchTerm} onChange={e => setSearchTerm(e.target.value)} className={`w-full bg-blue-800/50 border border-blue-400/30 rounded-full ${lang === 'ru' ? 'pl-10 pr-4' : 'pr-10 pl-4'} py-2 text-sm placeholder:text-blue-300 outline-none focus:ring-2 focus:ring-white/40 font-bold transition-all`} />
              <span className={`absolute ${lang === 'ru' ? 'right-3' : 'right-3'} top-2.5 opacity-50`}>🔍</span>
            </div>
            <button onClick={toggleLanguage} className="hidden md:block bg-blue-800 hover:bg-blue-700 px-4 py-2 rounded-full text-sm font-bold transition-colors border border-blue-600 shadow-inner">
              {t.langToggle}
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto pb-24 px-4">
        {/* Navigation Tabs */}
        <div className="flex gap-2 my-6 bg-slate-200/50 p-1.5 rounded-2xl w-full overflow-x-auto no-scrollbar md:w-fit mx-auto md:mx-0 shadow-inner border border-slate-300/30">
          <button onClick={() => setViewMode('units')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2.5 rounded-xl font-black transition-all ${viewMode === 'units' ? 'bg-white shadow-md text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewUnits}</button>
          <button onClick={() => setViewMode('public')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2.5 rounded-xl font-black transition-all ${viewMode === 'public' ? 'bg-white shadow-md text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewPublic}</button>
          <button onClick={() => setViewMode('contractors')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2.5 rounded-xl font-black transition-all ${viewMode === 'contractors' ? 'bg-white shadow-md text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewContractors}</button>
          <button onClick={() => setViewMode('schedule')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2.5 rounded-xl font-black transition-all ${viewMode === 'schedule' ? 'bg-white shadow-md text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewSchedule}</button>
          <button onClick={() => setViewMode('history')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2.5 rounded-xl font-black transition-all ${viewMode === 'history' ? 'bg-white shadow-md text-blue-600' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewHistory}</button>
        </div>

        {viewMode === 'contractors' ? (
          <ContractorView state={state} lang={lang} onSelectUnit={handleSelectFromOtherView} />
        ) : viewMode === 'schedule' ? (
          <ScheduleView state={state} lang={lang} onSelectUnit={handleSelectFromOtherView} />
        ) : viewMode === 'history' ? (
          <ProjectHistoryView state={state} lang={lang} onSelectUnit={handleSelectFromOtherView} />
        ) : (
          <>
            <section className="mt-4">
              <BuildingSelector buildings={filteredBuildings} selectedBuildingId={selectedBuildingId} onSelect={setSelectedBuildingId} state={state} lang={lang} discipline="general" />
            </section>

            {selectedBuildingId && (
              <section className="mt-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                {viewMode === 'units' ? (
                  <UnitGrid buildingId={selectedBuildingId} state={state} onSelectUnit={(num) => setSelectedUnitId(num)} lang={lang} />
                ) : (
                  <div className="bg-white rounded-3xl shadow-xl p-8 border border-gray-100">
                    <h2 className="text-2xl font-black text-gray-800 mb-8 flex items-center gap-3">
                       <span className="bg-blue-50 p-2 rounded-xl">🏢</span> {t.publicAreas}
                    </h2>
                    <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-5">
                      {PUBLIC_AREAS.map(area => {
                        const unitData = getUnit(state, selectedBuildingId, area.id);
                        // Simplified Status Rollup
                        const statuses = Object.values(unitData.statuses);
                        let finalStatus = TaskStatus.NOT_STARTED;
                        if (statuses.includes(TaskStatus.BLOCKED)) finalStatus = TaskStatus.BLOCKED;
                        else if (statuses.includes(TaskStatus.NEEDS_FOLLOWUP)) finalStatus = TaskStatus.NEEDS_FOLLOWUP;
                        else if (statuses.includes(TaskStatus.IN_PROGRESS)) finalStatus = TaskStatus.IN_PROGRESS;
                        else if (statuses.every(s => s === TaskStatus.DONE)) finalStatus = TaskStatus.DONE;

                        const config = STATUS_CONFIG[finalStatus];
                        return (
                          <button key={area.id} onClick={() => setSelectedUnitId(area.id)} className={`flex items-center gap-5 p-6 rounded-2xl border-2 transition-all hover:shadow-xl active:scale-95 text-right group ${config.color}`}>
                            <span className="text-4xl group-hover:scale-110 transition-transform">{area.icon}</span>
                            <div className="flex flex-col">
                              <span className="font-black text-xl">{(t as any)[area.labelKey]}</span>
                              <span className="text-xs font-bold opacity-70">{(t as any)[config.labelKey]}</span>
                            </div>
                          </button>
                        );
                      })}
                    </div>
                  </div>
                )}
              </section>
            )}
          </>
        )}
      </main>

      {activeUnit && (
        <UnitModal unit={activeUnit} onClose={() => setSelectedUnitId(null)} onSave={handleUpdateUnit} lang={lang} activeDiscipline="general" />
      )}

      <footer className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-md border-t p-4 text-center text-[10px] text-gray-400 z-30 font-bold uppercase tracking-widest shadow-[0_-10px_20px_-15px_rgba(0,0,0,0.1)]">
        {t.footerInfo}
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
import { ProjectState, TaskStatus } from '../types';
import { STATUS_CONFIG, UNITS_PER_BUILDING } from '../constants';
import { getUnit } from '../services/dataService';
import { Language, translations } from '../translations';

interface Props {
  buildingId: string;
  state: ProjectState;
  onSelectUnit: (unitNumber: number) => void;
  lang: Language;
}

const UnitGrid: React.FC<Props> = ({ buildingId, state, onSelectUnit, lang }) => {
  const units = Array.from({ length: UNITS_PER_BUILDING }, (_, i) => i + 1);
  const t = translations[lang];

  return (
    <div className="bg-white rounded-3xl shadow-xl p-8 border border-gray-100">
      <div className="flex flex-col md:flex-row md:items-center justify-between mb-8 gap-6">
        <h2 className="text-2xl font-black text-gray-800 flex items-center gap-3">
          <span className="bg-blue-50 p-2 rounded-xl">🏘️</span> {t.unitList}
        </h2>
        <div className="flex gap-3 flex-wrap">
          {Object.entries(STATUS_CONFIG).map(([status, config]) => (
            <div key={status} className="flex items-center gap-2 bg-slate-50 px-3 py-1.5 rounded-full border border-slate-100 shadow-sm">
              <span className={`w-3 h-3 rounded-full ${config.color.split(' ')[0]}`}></span>
              <span className="text-[11px] font-black text-gray-500">{(t as any)[config.labelKey]}</span>
            </div>
          ))}
        </div>
      </div>

      <div className="grid grid-cols-4 sm:grid-cols-6 md:grid-cols-8 lg:grid-cols-10 gap-4">
        {units.map((num) => {
          const unitData = getUnit(state, buildingId, num);
          // Unified Status logic: show the "most urgent" status of the unit
          const statuses = Object.values(unitData.statuses);
          let finalStatus = TaskStatus.NOT_STARTED;

          if (statuses.includes(TaskStatus.BLOCKED)) finalStatus = TaskStatus.BLOCKED;
          else if (statuses.includes(TaskStatus.NEEDS_FOLLOWUP)) finalStatus = TaskStatus.NEEDS_FOLLOWUP;
          else if (statuses.includes(TaskStatus.IN_PROGRESS)) finalStatus = TaskStatus.IN_PROGRESS;
          else if (statuses.every(s => s === TaskStatus.DONE)) finalStatus = TaskStatus.DONE;

          const config = STATUS_CONFIG[finalStatus];

          return (
            <button
              key={num}
              onClick={() => onSelectUnit(num)}
              className={`aspect-square flex flex-col items-center justify-center rounded-2xl border-2 transition-all hover:shadow-xl hover:-translate-y-1 active:scale-95 ${config.color} shadow-sm`}
            >
              <span className="text-[10px] font-black uppercase opacity-50 tracking-tighter">{t.unitLabel}</span>
              <span className="text-xl font-black">{num}</span>
            </button>
          );
        })}
      </div>
    </div>
  );
};

