import React, { useState, useEffect } from 'react';
import { Unit, TaskStatus, Discipline, Appointment, TaskLog } from '../types';
import { STATUS_CONFIG, PUBLIC_AREAS, CONTRACTORS } from '../constants';
import { Language, translations } from '../translations';

interface Props {
  unit: Unit;
  onClose: () => void;
  onSave: (updates: { 
    newLog?: { status: TaskStatus, workerName: string, contractor: string, description: string, discipline: Discipline },
    updateLogStatus?: { logId: string, newStatus: TaskStatus },
    newAppointment?: Omit<Appointment, 'id' | 'createdAt' | 'isCompleted'>,
    completeAppointmentId?: string
  }) => void;
  lang: Language;
  activeDiscipline: Discipline;
}

const UnitModal: React.FC<Props> = ({ unit, onClose, onSave, lang, activeDiscipline }) => {
  const [activeTab, setActiveTab] = useState<'report' | 'schedule' | 'history'>('history');
  const [worker, setWorker] = useState('');
  const [desc, setDesc] = useState('');
  const [status, setStatus] = useState<TaskStatus>(unit.statuses[activeDiscipline]);
  const [contractor, setContractor] = useState(CONTRACTORS[0].id);
  const [reportDiscipline, setReportDiscipline] = useState<Discipline>(activeDiscipline);
  const [editingLogId, setEditingLogId] = useState<string | null>(null);

  // Appointment Form State
  const [appDate, setAppDate] = useState('');
  const [appTime, setAppTime] = useState('');
  const [appTenant, setAppTenant] = useState('');
  const [appContractor, setAppContractor] = useState(CONTRACTORS[0].id);
  const [appNotes, setAppNotes] = useState('');

  const t = translations[lang];

  // Sync internal status if discipline changes in report tab
  useEffect(() => {
    setStatus(unit.statuses[reportDiscipline]);
  }, [reportDiscipline, unit.statuses]);

  const handleQuickStatusUpdate = (logId: string, newStatus: TaskStatus) => {
    onSave({ updateLogStatus: { logId, newStatus } });
    setEditingLogId(null);
  };

  const handleStartTask = (disc: Discipline) => {
    onSave({
      newLog: {
        status: TaskStatus.IN_PROGRESS,
        workerName: "מערכת",
