                   🚀 {t.newReport}
                </h4>
                <form onSubmit={handleReportSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-8">
                  <div className="space-y-3">
                    <label className="text-[11px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.disciplineLabel}</label>
                    <div className="flex bg-white rounded-2xl border-2 border-gray-100 p-2 shadow-sm">
                      <button type="button" onClick={() => setReportDiscipline('plumbing')} className={`flex-1 py-4 rounded-xl text-xs font-black transition-all ${reportDiscipline === 'plumbing' ? 'bg-blue-600 text-white shadow-xl scale-[1.03]' : 'text-gray-400 hover:bg-gray-50'}`}>{t.tabPlumbing}</button>
                      <button type="button" onClick={() => setReportDiscipline('general')} className={`flex-1 py-4 rounded-xl text-xs font-black transition-all ${reportDiscipline === 'general' ? 'bg-blue-600 text-white shadow-xl scale-[1.03]' : 'text-gray-400 hover:bg-gray-50'}`}>{t.tabGeneral}</button>
                    </div>
