  const [contractor, setContractor] = useState(CONTRACTORS[0].id);
  const [editingLogId, setEditingLogId] = useState<string | null>(null);

  // Default status for new report
  const [status, setStatus] = useState<TaskStatus>(TaskStatus.DONE);

  // Appointment Form State
  const [appDate, setAppDate] = useState('');
  const [appTime, setAppTime] = useState('');
  const [appTenant, setAppTenant] = useState('');
  const [appContractor, setAppContractor] = useState(CONTRACTORS[0].id);
  const [appNotes, setAppNotes] = useState('');

  const t = translations[lang];

  // Unified Status rollup for display
  const getUnifiedStatus = () => {
    const statuses = Object.values(unit.statuses);
    if (statuses.includes(TaskStatus.BLOCKED)) return TaskStatus.BLOCKED;
    if (statuses.includes(TaskStatus.NEEDS_FOLLOWUP)) return TaskStatus.NEEDS_FOLLOWUP;
    if (statuses.includes(TaskStatus.IN_PROGRESS)) return TaskStatus.IN_PROGRESS;
    if (statuses.every(s => s === TaskStatus.DONE)) return TaskStatus.DONE;
    return TaskStatus.NOT_STARTED;
  };

  const currentUnifiedStatus = getUnifiedStatus();
  const statusCfg = STATUS_CONFIG[currentUnifiedStatus];

  const handleQuickStatusUpdate = (logId: string, newStatus: TaskStatus) => {
    onSave({ updateLogStatus: { logId, newStatus } });
    setEditingLogId(null);
  };

  const handleReportSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!worker || !desc) return alert(t.alertFillFields);

    // Automatically determine discipline based on contractor
    // This removes the need for a separate discipline selector
    const discipline: Discipline = contractor === 'plumber' ? 'plumbing' : 'general';
    const selectedContractor = (t as any)[CONTRACTORS.find(c => c.id === contractor)?.labelKey || ''];

    onSave({ 
      newLog: { status, workerName: worker, contractor: selectedContractor, description: desc, discipline } 
    });

    setWorker('');
    setDesc('');
    setStatus(TaskStatus.DONE);
    setActiveTab('history');
  };

  const handleAppSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!appDate || !appTime || !appTenant) return alert(t.alertFillFields);
    const selectedContractor = (t as any)[CONTRACTORS.find(c => c.id === appContractor)?.labelKey || ''];
    onSave({ 
      newAppointment: { 
        date: appDate, 
        time: appTime, 
        tenantName: appTenant, 
        contractor: selectedContractor,
        notes: appNotes 
      } 
    });
    setAppDate('');
    setAppTime('');
    setAppTenant('');
    setAppNotes('');
  };

  const unitIdentifier = unit.id.split('-').slice(1).join('-');
  const isPublicArea = isNaN(Number(unitIdentifier));
  const publicAreaConfig = isPublicArea ? PUBLIC_AREAS.find(a => a.id === unitIdentifier) : null;
  const displayName = isPublicArea 
    ? (t as any)[publicAreaConfig?.labelKey || ''] 
    : `${t.apartment} ${unitIdentifier}`;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-md">
      <div className="bg-white w-full max-w-2xl rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col max-h-[92vh] border border-white/20">

        {/* Compact Header */}
        <div className="px-8 py-6 border-b flex justify-between items-center bg-white">
          <div className={lang === 'ru' ? 'text-left' : 'text-right'}>
            <h3 className="text-3xl font-black text-blue-900 tracking-tight">{displayName}</h3>
            <div className="flex items-center gap-3 mt-1">
               <span className="text-[11px] font-black text-gray-400 uppercase tracking-[0.2em]">{t.building}: {unit.buildingId.split('-')[1]}</span>
               <span className={`text-[10px] px-3 py-0.5 rounded-full font-black border-2 ${statusCfg.color}`}>
                 {(t as any)[statusCfg.labelKey]}
               </span>
            </div>
          </div>
          <button onClick={onClose} className="w-12 h-12 flex items-center justify-center hover:bg-red-50 hover:text-red-500 rounded-2xl transition-all text-4xl font-light shadow-sm bg-slate-50">&times;</button>
        </div>

        {/* Action Quickbar - Simplified to just "New Report" */}
        <div className="bg-slate-50 px-8 py-4 border-b flex items-center justify-between">
           <div className="flex items-center gap-2">
              <span className="text-sm font-black text-gray-400 uppercase tracking-widest">{t.openTaskStatus}:</span>
              <span className="w-3 h-3 rounded-full animate-pulse bg-blue-500 shadow-[0_0_8px_rgba(59,130,246,0.6)]"></span>
           </div>
           <button 
             onClick={() => setActiveTab('report')} 
             className="bg-blue-600 text-white px-8 py-3 rounded-2xl text-sm font-black shadow-lg hover:bg-blue-700 active:scale-95 transition-all flex items-center gap-2"
           >
             <span>➕</span> {t.newReport}
           </button>
        </div>

        {/* Modal Tabs */}
        <div className="flex bg-white">
          <button 
            onClick={() => setActiveTab('history')}
            className={`flex-1 py-4 font-black text-xs md:text-sm transition-all border-b-4 ${activeTab === 'history' ? 'text-blue-600 border-blue-600 bg-blue-50/30' : 'text-gray-400 border-transparent hover:text-gray-600'}`}
          >
            📜 {t.viewHistory}
          </button>
          <button 
            onClick={() => setActiveTab('schedule')}
            className={`flex-1 py-4 font-black text-xs md:text-sm transition-all border-b-4 ${activeTab === 'schedule' ? 'text-blue-600 border-blue-600 bg-blue-50/30' : 'text-gray-400 border-transparent hover:text-gray-600'}`}
          >
            📅 {t.viewSchedule}
          </button>
        </div>

        <div className="flex-1 overflow-y-auto p-8 bg-slate-50/30">
          {activeTab === 'history' && (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
              <div className="flex justify-between items-center mb-8">
                <h4 className="text-xs font-black text-gray-400 uppercase tracking-[0.2em]">{t.workHistory}</h4>
              </div>

              {unit.history.length === 0 ? (
                <div className="text-center py-24 text-gray-400 border-4 border-dashed border-gray-100 rounded-[2.5rem] flex flex-col items-center">
                  <span className="text-6xl mb-6 grayscale opacity-20">📂</span>
                  <p className="font-black text-xl">{t.noHistory}</p>
                </div>
              ) : (
                <div className={`space-y-6 relative before:absolute ${lang === 'ru' ? 'before:left-5' : 'before:right-5'} before:top-2 before:bottom-2 before:w-1 before:bg-blue-100/50 before:rounded-full`}>
                  {unit.history.map((log) => {
                    const isTaskActive = log.status === TaskStatus.IN_PROGRESS || log.status === TaskStatus.NEEDS_FOLLOWUP || log.status === TaskStatus.BLOCKED;
                    return (
                      <div key={log.id} className={`relative ${lang === 'ru' ? 'pl-14' : 'pr-14'}`}>
                        <div className={`absolute ${lang === 'ru' ? 'left-0' : 'right-0'} top-2 w-10 h-10 rounded-2xl border-4 border-white shadow-xl flex items-center justify-center text-lg z-10 transform rotate-2 ${STATUS_CONFIG[log.status].color.split(' ')[0]}`}>
                          {STATUS_CONFIG[log.status].icon}
                        </div>
                        <div className={`bg-white border-2 rounded-[2rem] p-6 shadow-sm transition-all ${lang === 'ru' ? 'text-left' : 'text-right'} ${isTaskActive ? 'border-blue-300 ring-4 ring-blue-500/5 shadow-md' : 'border-gray-100'}`}>
                          <div className="flex justify-between items-start mb-4 flex-wrap gap-3 border-b border-gray-50 pb-4">
                            <div className="flex flex-col">
                              <span className="font-black text-blue-900 text-xl leading-none">{log.workerName}</span>
                              <div className="flex items-center gap-2 mt-3">
                                <span className={`text-[10px] px-3 py-1 rounded-lg border font-black uppercase shadow-sm ${log.contractor.includes('מנהל') ? 'bg-slate-800 text-white border-slate-800' : 'bg-blue-600 text-white border-blue-600'}`}>
                                  {log.contractor}
                                </span>
                              </div>
                            </div>
                            <div className="flex flex-col items-end">
                               <span className="text-[11px] font-black text-gray-300 bg-gray-50 px-3 py-1 rounded-lg mb-3">
                                 {new Date(log.timestamp).toLocaleDateString(lang === 'ru' ? 'ru-RU' : 'he-IL')} | {new Date(log.timestamp).toLocaleTimeString(lang === 'ru' ? 'ru-RU' : 'he-IL', {hour:'2-digit', minute:'2-digit'})}
                               </span>

                               {editingLogId === log.id ? (
                                 <div className="flex gap-1.5 bg-slate-100 p-1.5 rounded-xl border border-slate-200">
                                   {Object.entries(STATUS_CONFIG).map(([s, cfg]) => (
                                     <button 
                                       key={s} 
                                       onClick={() => handleQuickStatusUpdate(log.id, s as TaskStatus)}
                                       className={`w-8 h-8 rounded-lg flex items-center justify-center transition-all hover:scale-110 shadow-sm ${cfg.color.split(' ')[0]}`}
                                     >
                                       {cfg.icon}
                                     </button>
                                   ))}
                                 </div>
                               ) : (
                                 <button 
                                   onClick={() => setEditingLogId(log.id)}
                                   className={`text-[10px] px-4 py-1.5 rounded-full border-2 font-black uppercase tracking-widest transition-all hover:shadow-md ${STATUS_CONFIG[log.status].color}`}
                                 >
                                   {(t as any)[STATUS_CONFIG[log.status].labelKey]} ✏️
                                 </button>
                               )}
                            </div>
                          </div>

                          <p className="text-sm text-gray-700 leading-relaxed font-bold bg-blue-50/20 p-4 rounded-2xl border border-blue-100/30">
                            {log.description}
                          </p>

                          {isTaskActive && (
                            <div className="mt-4 flex justify-end">
                              <button 
                                onClick={() => handleQuickStatusUpdate(log.id, TaskStatus.DONE)}
                                className="bg-green-600 text-white text-xs font-black px-6 py-2 rounded-xl shadow-xl hover:bg-green-700 transition-all flex items-center gap-2 active:scale-95"
                              >
                                {t.markCompletedAction}
                              </button>
                            </div>
                          )}
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          )}

          {activeTab === 'schedule' && (
            <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-300">
              <section className="bg-yellow-50/40 p-8 rounded-[2.5rem] border-2 border-yellow-100/60 shadow-inner">
                <h4 className="text-xs font-black text-yellow-800 mb-8 uppercase tracking-[0.2em] flex items-center gap-4">
                  <span className="bg-yellow-100 p-3 rounded-2xl">📅</span> {t.scheduleTitle}
                </h4>
                <form onSubmit={handleAppSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.dateLabel}</label>
                    <input type="date" value={appDate} onChange={e => setAppDate(e.target.value)} className="w-full px-5 py-4 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none transition-all font-black bg-white shadow-sm" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.timeLabel}</label>
                    <input type="time" value={appTime} onChange={e => setAppTime(e.target.value)} className="w-full px-5 py-4 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none transition-all font-black bg-white shadow-sm" />
                  </div>
                  <div className="md:col-span-2 space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.contractorLabel}</label>
                    <select value={appContractor} onChange={e => setAppContractor(e.target.value)} className="w-full px-5 py-4 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none bg-white font-black shadow-sm">
                      {CONTRACTORS.map(c => <option key={c.id} value={c.id}>{c.icon} {(t as any)[c.labelKey]}</option>)}
                    </select>
                  </div>
                  <div className="md:col-span-2 space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.tenantLabel}</label>
                    <input type="text" value={appTenant} onChange={e => setAppTenant(e.target.value)} className="w-full px-5 py-4 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none font-black shadow-sm bg-white" placeholder="שם מלא / טלפון" />
                  </div>
                  <div className="md:col-span-2 space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.notesLabel}</label>
                    <textarea value={appNotes} onChange={e => setAppNotes(e.target.value)} rows={2} className="w-full px-5 py-4 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none resize-none font-bold bg-white shadow-sm" />
                  </div>
                  <button type="submit" className="md:col-span-2 bg-yellow-500 text-white font-black py-6 rounded-3xl hover:bg-yellow-600 transition-all shadow-xl active:scale-95 text-lg">
                    {t.addAppointment}
                  </button>
                </form>
              </section>

              <section>
                <h4 className="text-xs font-black text-gray-300 mb-6 uppercase tracking-[0.2em]">{t.upcomingAppointments}</h4>
                {unit.appointments.length === 0 ? (
                  <div className="text-center py-16 text-gray-400 border-4 border-dashed border-gray-100 rounded-[2.5rem] italic font-black">
                    {t.noAppointments}
                  </div>
                ) : (
                  <div className="space-y-5">
                    {unit.appointments.map(app => (
                      <div key={app.id} className={`p-8 rounded-[2rem] border-2 flex justify-between items-center transition-all ${app.isCompleted ? 'bg-gray-50 border-gray-100 opacity-60' : 'bg-white border-blue-50 shadow-lg'}`}>
                        <div className="flex-1">
                          <div className="flex items-center gap-5 mb-4">
                            <span className="text-4xl font-black text-blue-900">{app.time}</span>
                            <span className="text-[11px] font-black text-blue-400 bg-blue-50 px-4 py-2 rounded-xl border border-blue-100 uppercase tracking-widest">{app.date}</span>
                          </div>
                          <div className="flex flex-wrap items-center gap-3">
                             <span className="text-xl font-black text-gray-800">{app.tenantName}</span>
                             <span className={`text-[11px] px-3 py-1 rounded-lg border font-black uppercase shadow-sm ${app.contractor.includes('מנהל') ? 'bg-slate-800 text-white' : 'bg-blue-600 text-white border-blue-600'}`}>{app.contractor}</span>
                          </div>
                          <div className="text-sm text-gray-500 italic mt-4 font-bold bg-slate-50 p-4 rounded-2xl border border-slate-100">"{app.notes}"</div>
                        </div>
                        {!app.isCompleted && (
                          <button 
                            onClick={() => {
                              onSave({ completeAppointmentId: app.id });
                              setActiveTab('report');
                            }}
                            className="bg-green-600 text-white px-8 py-5 rounded-2xl text-md font-black hover:bg-green-700 shadow-2xl active:scale-95 transition-all"
                          >
                            {t.appointmentDone}
                          </button>
                        )}
                      </div>
                    ))}
                  </div>
                )}
              </section>
            </div>
          )}

          {activeTab === 'report' && (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
              <section className="bg-blue-50/40 p-10 rounded-[3rem] border-2 border-blue-100 shadow-inner">
                <h4 className="text-md font-black text-blue-800 mb-10 uppercase tracking-[0.3em] text-center border-b-2 pb-6 border-blue-100/50">
                   🚀 {t.newReport}
                </h4>
                <form onSubmit={handleReportSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-8">

                  {/* Company Provider - Combined with Contractor */}
                  <div className="space-y-3">
                    <label className="text-[11px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.contractorLabel}</label>
                    <select value={contractor} onChange={e => setContractor(e.target.value)} className="w-full px-6 py-5 rounded-2xl border-2 border-gray-100 focus:border-blue-500 outline-none bg-white font-black shadow-sm text-lg">
                      {CONTRACTORS.map(c => <option key={c.id} value={c.id}>{c.icon} {(t as any)[c.labelKey]}</option>)}
                    </select>
                  </div>

                  <div className="space-y-3">
                    <label className="text-[11px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.workerName}</label>
                    <input value={worker} onChange={e => setWorker(e.target.value)} className="w-full px-6 py-5 rounded-2xl border-2 border-gray-100 focus:border-blue-500 outline-none font-black shadow-sm text-lg placeholder:opacity-20" placeholder={t.workerExample} />
                  </div>

                  <div className="space-y-3">
                    <label className="text-[11px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.currentStatus}</label>
                    <select value={status} onChange={e => setStatus(e.target.value as TaskStatus)} className="w-full px-6 py-5 rounded-2xl border-2 border-gray-100 focus:border-blue-500 outline-none bg-white font-black shadow-sm text-lg">
                      {Object.entries(STATUS_CONFIG).map(([s, cfg]) => <option key={s} value={s}>{(t as any)[cfg.labelKey]}</option>)}
                    </select>
                  </div>

                  <div className="md:col-span-2 space-y-3">
                    <label className="text-[11px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.whatWasDone}</label>
                    <textarea value={desc} onChange={e => setDesc(e.target.value)} rows={5} className="w-full px-6 py-5 rounded-[2.5rem] border-2 border-gray-100 focus:border-blue-500 outline-none resize-none font-bold shadow-sm text-lg placeholder:opacity-20" placeholder={t.descriptionPlaceholder} />
                  </div>

                  <button type="submit" className="md:col-span-2 bg-blue-600 text-white font-black py-7 rounded-[2rem] hover:bg-blue-700 transition-all shadow-2xl active:scale-95 text-2xl tracking-[0.2em]">
                    {t.updateButton}
                  </button>
                </form>
              </section>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

