      <div className="bg-white w-full max-w-2xl rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col max-h-[92vh] border border-white/20">

        {/* Header Section */}
        <div className="px-8 py-6 border-b flex justify-between items-center bg-white">
          <div className={lang === 'ru' ? 'text-left' : 'text-right'}>
            <h3 className="text-3xl font-black text-blue-900 tracking-tight">{displayName}</h3>
            <div className="flex items-center gap-3 mt-1">
               <span className="text-[11px] font-black text-gray-400 uppercase tracking-[0.2em]">{t.building}: {unit.buildingId.split('-')[1]}</span>
            </div>
          </div>
          <button onClick={onClose} className="w-12 h-12 flex items-center justify-center hover:bg-red-50 hover:text-red-500 rounded-2xl transition-all text-4xl font-light shadow-sm bg-slate-50">&times;</button>
        </div>

        {/* Tab Navigation */}
        <div className="flex bg-white border-b">
          <button onClick={() => setActiveTab('history')} className={`flex-1 py-4 font-black text-xs md:text-sm transition-all border-b-4 ${activeTab === 'history' ? 'text-blue-600 border-blue-600 bg-blue-50/30' : 'text-gray-400 border-transparent hover:text-gray-600'}`}>📜 {t.viewHistory}</button>
          <button onClick={() => setActiveTab('schedule')} className={`flex-1 py-4 font-black text-xs md:text-sm transition-all border-b-4 ${activeTab === 'schedule' ? 'text-blue-600 border-blue-600 bg-blue-50/30' : 'text-gray-400 border-transparent hover:text-gray-600'}`}>📅 {t.viewSchedule}</button>
          <button onClick={() => setActiveTab('report')} className={`flex-1 py-4 font-black text-xs md:text-sm transition-all border-b-4 ${activeTab === 'report' ? 'text-blue-600 border-blue-600 bg-blue-50/30' : 'text-gray-400 border-transparent hover:text-gray-600'}`}>➕ {t.newReport}</button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 bg-slate-50/30">
          {activeTab === 'history' && (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-300 space-y-6">

              {/* "THE RUBRIC" - Active Task Highlight */}
              {activeTasks.length > 0 ? (
                <div className="space-y-4">
                  <h4 className="text-[10px] font-black text-blue-500 uppercase tracking-widest px-2">{t.activeTask}</h4>
                  {activeTasks.map(task => (
                    <div key={task.id} className="bg-white border-2 border-blue-400 rounded-[2rem] p-6 shadow-xl relative overflow-hidden ring-8 ring-blue-500/5">
                      <div className="absolute top-0 left-0 w-2 h-full bg-blue-500"></div>
                      <div className="flex justify-between items-start mb-4">
                        <div>
                          <span className="font-black text-blue-900 text-xl block">{task.workerName}</span>
                          <span className="text-[10px] bg-blue-600 text-white px-3 py-1 rounded-lg font-black uppercase mt-1 inline-block">{task.contractor}</span>
                        </div>
                        <div className={`text-xs font-black px-3 py-1 rounded-full border-2 ${STATUS_CONFIG[task.status].color}`}>
                          {(t as any)[STATUS_CONFIG[task.status].labelKey]}
                        </div>
                      </div>
                      <p className="text-sm font-bold text-gray-700 bg-blue-50/50 p-4 rounded-xl border border-blue-100 mb-6">
                        {task.description}
                      </p>
                      <div className="flex gap-3">
                        <button 
                          onClick={() => handleQuickStatusUpdate(task.id, TaskStatus.DONE)}
                          className="flex-1 bg-green-600 text-white py-3 rounded-xl font-black text-sm shadow-lg hover:bg-green-700 active:scale-95 transition-all flex items-center justify-center gap-2"
                        >
                          ✅ {t.finishWorkAction}
                        </button>
                        <button 
                          onClick={() => handleQuickStatusUpdate(task.id, TaskStatus.NEEDS_FOLLOWUP)}
                          className="flex-1 bg-yellow-500 text-white py-3 rounded-xl font-black text-sm shadow-lg hover:bg-yellow-600 active:scale-95 transition-all"
                        >
                          🔄 {t.needsFollowup}
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              ) : unit.history.length === 0 ? (
                <div className="text-center py-16">
                   <button onClick={handleStartWork} className="bg-blue-600 text-white px-10 py-6 rounded-[2rem] text-xl font-black shadow-2xl hover:bg-blue-700 active:scale-95 transition-all">
                     🚀 התחל משימה חדשה
                   </button>
                   <p className="text-gray-400 font-bold mt-4">אין היסטוריה לדירה זו עדיין</p>
                </div>
              ) : null}

              {/* General History List */}
              <div className="space-y-4 pt-4">
                <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-2">{t.workHistory}</h4>
                <div className="space-y-4">
                  {unit.history.map((log) => (
                    <div key={log.id} className={`bg-white border rounded-2xl p-4 shadow-sm flex items-center gap-4 transition-all hover:border-blue-200 ${log.status === TaskStatus.DONE ? 'opacity-60 grayscale-[0.5]' : ''}`}>
                      <div className={`w-10 h-10 rounded-xl flex items-center justify-center text-xl shadow-sm ${STATUS_CONFIG[log.status].color.split(' ')[0]}`}>
                        {STATUS_CONFIG[log.status].icon}
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex justify-between items-center">
                           <span className="font-black text-blue-900 truncate">{log.workerName}</span>
                           <span className="text-[9px] text-gray-300 font-bold">{new Date(log.timestamp).toLocaleDateString()}</span>
                        </div>
                        <p className="text-xs text-gray-500 line-clamp-1 mt-0.5">{log.description}</p>
                      </div>
                      <button 
                        onClick={() => setEditingLogId(editingLogId === log.id ? null : log.id)}
                        className="p-2 hover:bg-gray-100 rounded-lg text-gray-400"
                      >
                        ✏️
                      </button>
                      {editingLogId === log.id && (
                         <div className="absolute left-6 right-6 bg-white border-2 border-blue-500 p-2 rounded-xl shadow-2xl flex gap-1 z-20 animate-in fade-in zoom-in-95 duration-200">
                           {Object.entries(STATUS_CONFIG).map(([s, cfg]) => (
                             <button key={s} onClick={() => handleQuickStatusUpdate(log.id, s as TaskStatus)} className={`flex-1 py-2 rounded-lg text-sm ${cfg.color.split(' ')[0]}`}>{cfg.icon}</button>
                           ))}
                         </div>
                      )}
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}

          {activeTab === 'schedule' && (
            <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-300">
              <section className="bg-yellow-50/40 p-8 rounded-[2.5rem] border-2 border-yellow-100/60 shadow-inner">
                <h4 className="text-xs font-black text-yellow-800 mb-8 uppercase tracking-[0.2em] flex items-center gap-4"><span className="bg-yellow-100 p-3 rounded-2xl">📅</span> {t.scheduleTitle}</h4>
                <form onSubmit={handleAppSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.dateLabel}</label>
                    <input type="date" value={appDate} onChange={e => setAppDate(e.target.value)} className="w-full px-5 py-4 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none transition-all font-black bg-white shadow-sm" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.timeLabel}</label>
                    <input type="time" value={appTime} onChange={e => setAppTime(e.target.value)} className="w-full px-5 py-4 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none transition-all font-black bg-white shadow-sm" />
                  </div>
                  <div className="md:col-span-2 space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.contractorLabel}</label>
                    <select value={appContractor} onChange={e => setAppContractor(e.target.value)} className="w-full px-5 py-4 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none bg-white font-black shadow-sm">
                      {CONTRACTORS.map(c => <option key={c.id} value={c.id}>{c.icon} {(t as any)[c.labelKey]}</option>)}
                    </select>
                  </div>
                  <div className="md:col-span-2 space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.tenantLabel}</label>
                    <input type="text" value={appTenant} onChange={e => setAppTenant(e.target.value)} className="w-full px-5 py-4 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none font-black shadow-sm bg-white" placeholder="שם מלא / טלפון" />
                  </div>
                  <div className="md:col-span-2 space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.notesLabel}</label>
                    <textarea value={appNotes} onChange={e => setAppNotes(e.target.value)} rows={2} className="w-full px-5 py-4 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none resize-none font-bold bg-white shadow-sm" />
                  </div>
                  <button type="submit" className="md:col-span-2 bg-yellow-500 text-white font-black py-6 rounded-3xl hover:bg-yellow-600 transition-all shadow-xl active:scale-95 text-lg">{t.addAppointment}</button>
                </form>
              </section>
            </div>
          )}

          {activeTab === 'report' && (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
              <section className="bg-blue-50/40 p-8 rounded-[3rem] border-2 border-blue-100 shadow-inner">
                <h4 className="text-md font-black text-blue-800 mb-8 uppercase tracking-[0.3em] text-center border-b-2 pb-6 border-blue-100/50">🚀 {t.newReport}</h4>
                <form onSubmit={handleReportSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-3">
                    <label className="text-[11px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.contractorLabel}</label>
                    <select value={contractor} onChange={e => setContractor(e.target.value)} className="w-full px-6 py-5 rounded-2xl border-2 border-gray-100 focus:border-blue-500 outline-none bg-white font-black shadow-sm text-lg">
                      {CONTRACTORS.map(c => <option key={c.id} value={c.id}>{c.icon} {(t as any)[c.labelKey]}</option>)}
                    </select>
                  </div>
                  <div className="space-y-3">
                    <label className="text-[11px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.workerName}</label>
                    <input value={worker} onChange={e => setWorker(e.target.value)} className="w-full px-6 py-5 rounded-2xl border-2 border-gray-100 focus:border-blue-500 outline-none font-black shadow-sm text-lg placeholder:opacity-20" placeholder={t.workerExample} />
                  </div>
                  <div className="space-y-3">
                    <label className="text-[11px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.currentStatus}</label>
                    <select value={status} onChange={e => setStatus(e.target.value as TaskStatus)} className="w-full px-6 py-5 rounded-2xl border-2 border-gray-100 focus:border-blue-500 outline-none bg-white font-black shadow-sm text-lg">
                      {Object.entries(STATUS_CONFIG).map(([s, cfg]) => <option key={s} value={s}>{(t as any)[cfg.labelKey]}</option>)}
                    </select>
                  </div>
                  <div className="md:col-span-2 space-y-3">
                    <label className="text-[11px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.whatWasDone}</label>
                    <textarea value={desc} onChange={e => setDesc(e.target.value)} rows={5} className="w-full px-6 py-5 rounded-[2.5rem] border-2 border-gray-100 focus:border-blue-500 outline-none resize-none font-bold shadow-sm text-lg placeholder:opacity-20" placeholder={t.descriptionPlaceholder} />
                  </div>
                  <button type="submit" className="md:col-span-2 bg-blue-600 text-white font-black py-7 rounded-[2rem] hover:bg-blue-700 transition-all shadow-2xl active:scale-95 text-2xl tracking-[0.2em]">{t.updateButton}</button>
                </form>
              </section>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default UnitModal;

export enum TaskStatus {
  NOT_STARTED = 'NOT_STARTED',
  IN_PROGRESS = 'IN_PROGRESS',
  DONE = 'DONE',
  NEEDS_FOLLOWUP = 'NEEDS_FOLLOWUP',
  BLOCKED = 'BLOCKED'
}

export type Discipline = 'plumbing' | 'general';

export interface Appointment {
  id: string;
  date: string;
  time: string;
  tenantName: string;
  contractor: string;
  notes: string;
  isCompleted: boolean;
  createdAt: number;
}

export interface TaskLog {
  id: string;
  timestamp: number;
  workerName: string;
  contractor: string;
  description: string;
  status: TaskStatus;
  discipline: Discipline;
  images?: string[]; // Array of base64 strings
}

export interface Unit {
  id: string;
  buildingId: string;
  number: number;
  statuses: Record<Discipline, TaskStatus>;
  history: TaskLog[];
  appointments: Appointment[];
}

export interface Building {
  id: string;
  name: string;
  totalUnits: number;
}

export interface ProjectState {
  buildings: Building[];
  units: Record<string, Unit>;
}

import React, { useState, useEffect, useRef } from 'react';
import { Unit, TaskStatus, Discipline, Appointment, TaskLog } from '../types';
import { STATUS_CONFIG, PUBLIC_AREAS, CONTRACTORS } from '../constants';
import { Language, translations } from '../translations';

interface Props {
  unit: Unit;
  onClose: () => void;
  onSave: (updates: { 
    newLog?: { status: TaskStatus, workerName: string, contractor: string, description: string, discipline: Discipline, images?: string[] },
    updateLogStatus?: { logId: string, newStatus: TaskStatus },
    newAppointment?: Omit<Appointment, 'id' | 'createdAt' | 'isCompleted'>,
    completeAppointmentId?: string
  }) => void;
  lang: Language;
  activeDiscipline: Discipline;
}

const UnitModal: React.FC<Props> = ({ unit, onClose, onSave, lang, activeDiscipline }) => {
  const [activeTab, setActiveTab] = useState<'report' | 'schedule' | 'history'>('history');
  const [worker, setWorker] = useState('');
  const [desc, setDesc] = useState('');
  const [contractor, setContractor] = useState(CONTRACTORS[0].id);
  const [editingLogId, setEditingLogId] = useState<string | null>(null);
  const [status, setStatus] = useState<TaskStatus>(TaskStatus.DONE);
  const [selectedImages, setSelectedImages] = useState<string[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Appointment Form State
  const [appDate, setAppDate] = useState('');
  const [appTime, setAppTime] = useState('');
  const [appTenant, setAppTenant] = useState('');
  const [appContractor, setAppContractor] = useState(CONTRACTORS[0].id);
  const [appNotes, setAppNotes] = useState('');

  const t = translations[lang];

  // Helper to find active tasks (logs that are not DONE)
  const activeTasks = unit.history.filter(log => log.status !== TaskStatus.DONE);

  const handleQuickStatusUpdate = (logId: string, newStatus: TaskStatus) => {
    onSave({ updateLogStatus: { logId, newStatus } });
    setEditingLogId(null);
  };

  const handleStartWork = () => {
    setActiveTab('report');
    setStatus(TaskStatus.IN_PROGRESS);
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files) {
      Array.from(files).forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => {
          setSelectedImages(prev => [...prev, reader.result as string]);
        };
        reader.readAsDataURL(file);
      });
    }
  };

  const removeImage = (index: number) => {
    setSelectedImages(prev => prev.filter((_, i) => i !== index));
  };

  const handleReportSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!worker || !desc) return alert(t.alertFillFields);

    const discipline: Discipline = contractor === 'plumber' ? 'plumbing' : 'general';
    const selectedContractorLabel = (t as any)[CONTRACTORS.find(c => c.id === contractor)?.labelKey || ''];

    onSave({ 
      newLog: { 
        status, 
        workerName: worker, 
        contractor: selectedContractorLabel, 
        description: desc, 
        discipline,
        images: selectedImages.length > 0 ? selectedImages : undefined
      } 
    });

    setWorker('');
    setDesc('');
    setSelectedImages([]);
    setStatus(TaskStatus.DONE);
    setActiveTab('history');
  };

  const handleAppSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!appDate || !appTime || !appTenant) return alert(t.alertFillFields);
    const selectedContractor = (t as any)[CONTRACTORS.find(c => c.id === appContractor)?.labelKey || ''];
    onSave({ 
      newAppointment: { 
        date: appDate, 
        time: appTime, 
        tenantName: appTenant, 
        contractor: selectedContractor,
        notes: appNotes 
      } 
    });
    setAppDate('');
    setAppTime('');
    setAppTenant('');
    setAppNotes('');
  };

  const unitIdentifier = unit.id.split('-').slice(1).join('-');
  const isPublicArea = isNaN(Number(unitIdentifier));
  const publicAreaConfig = isPublicArea ? PUBLIC_AREAS.find(a => a.id === unitIdentifier) : null;
  const displayName = isPublicArea 
    ? (t as any)[publicAreaConfig?.labelKey || ''] 
    : `${t.apartment} ${unitIdentifier}`;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-md">
      <div className="bg-white w-full max-w-2xl rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col max-h-[92vh] border border-white/20">

        {/* Header Section */}
        <div className="px-8 py-6 border-b flex justify-between items-center bg-white">
          <div className={lang === 'ru' ? 'text-left' : 'text-right'}>
            <h3 className="text-3xl font-black text-blue-900 tracking-tight">{displayName}</h3>
            <div className="flex items-center gap-3 mt-1">
               <span className="text-[11px] font-black text-gray-400 uppercase tracking-[0.2em]">{t.building}: {unit.buildingId.split('-')[1]}</span>
            </div>
          </div>
          <button onClick={onClose} className="w-12 h-12 flex items-center justify-center hover:bg-red-50 hover:text-red-500 rounded-2xl transition-all text-4xl font-light shadow-sm bg-slate-50">&times;</button>
        </div>

        {/* Tab Navigation */}
        <div className="flex bg-white border-b sticky top-0 z-10">
          <button onClick={() => setActiveTab('history')} className={`flex-1 py-4 font-black text-xs md:text-sm transition-all border-b-4 ${activeTab === 'history' ? 'text-blue-600 border-blue-600 bg-blue-50/30' : 'text-gray-400 border-transparent hover:text-gray-600'}`}>📜 {t.viewHistory}</button>
          <button onClick={() => setActiveTab('schedule')} className={`flex-1 py-4 font-black text-xs md:text-sm transition-all border-b-4 ${activeTab === 'schedule' ? 'text-blue-600 border-blue-600 bg-blue-50/30' : 'text-gray-400 border-transparent hover:text-gray-600'}`}>📅 {t.viewSchedule}</button>
          <button onClick={() => setActiveTab('report')} className={`flex-1 py-4 font-black text-xs md:text-sm transition-all border-b-4 ${activeTab === 'report' ? 'text-blue-600 border-blue-600 bg-blue-50/30' : 'text-gray-400 border-transparent hover:text-gray-600'}`}>➕ {t.newReport}</button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 bg-slate-50/30">
          {activeTab === 'history' && (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-300 space-y-6">

              {/* "THE RUBRIC" - Active Task Highlight (Execution Window) */}
              {activeTasks.length > 0 ? (
                <div className="space-y-4">
                  <div className="flex items-center justify-between px-2">
                    <h4 className="text-[10px] font-black text-blue-500 uppercase tracking-widest">{t.activeTask}</h4>
                    <span className="flex items-center gap-1.5 text-[9px] font-bold text-blue-400 bg-blue-50 px-2 py-0.5 rounded-full border border-blue-100 animate-pulse">
                      <span className="w-1.5 h-1.5 bg-blue-500 rounded-full"></span> בביצוע
                    </span>
                  </div>
                  {activeTasks.map(task => (
                    <div key={task.id} className="bg-white border-2 border-blue-500 rounded-[2.5rem] p-6 shadow-2xl relative overflow-hidden ring-8 ring-blue-500/5">
                      <div className="absolute top-0 left-0 w-3 h-full bg-blue-600"></div>
                      <div className="flex justify-between items-start mb-4">
                        <div className="flex items-center gap-3">
                          <div className="w-12 h-12 rounded-2xl bg-blue-50 flex items-center justify-center text-2xl border-2 border-blue-100 shadow-inner">
                            {task.contractor.includes('אינסטלטור') ? '🚰' : '👷'}
                          </div>
                          <div>
                            <span className="font-black text-blue-900 text-xl block leading-tight">{task.workerName}</span>
                            <span className="text-[10px] bg-blue-600 text-white px-2 py-0.5 rounded-md font-black uppercase mt-1 inline-block shadow-sm">{task.contractor}</span>
                          </div>
                        </div>
                        <div className={`text-[10px] font-black px-3 py-1 rounded-full border-2 shadow-sm ${STATUS_CONFIG[task.status].color}`}>
                          {(t as any)[STATUS_CONFIG[task.status].labelKey]}
                        </div>
                      </div>

                      <div className="bg-slate-50/80 p-5 rounded-3xl border border-slate-100 shadow-inner mb-6">
                        <p className="text-sm font-bold text-gray-700 leading-relaxed">
                          {task.description}
                        </p>
                        {task.images && task.images.length > 0 && (
                          <div className="grid grid-cols-3 gap-3 mt-4">
                            {task.images.map((img, idx) => (
                              <div key={idx} className="aspect-square rounded-2xl overflow-hidden border-2 border-white shadow-md cursor-pointer hover:scale-105 transition-transform" onClick={() => window.open(img)}>
                                <img src={img} alt="progress" className="w-full h-full object-cover" />
                              </div>
                            ))}
                          </div>
                        )}
                      </div>

                      <div className="flex gap-4">
                        <button 
                          onClick={() => handleQuickStatusUpdate(task.id, TaskStatus.DONE)}
                          className="flex-1 bg-green-600 text-white py-4 rounded-2xl font-black text-sm shadow-xl hover:bg-green-700 active:scale-95 transition-all flex items-center justify-center gap-2"
                        >
                          ✅ {t.finishWorkAction}
                        </button>
                        <button 
                          onClick={() => handleQuickStatusUpdate(task.id, TaskStatus.NEEDS_FOLLOWUP)}
                          className="flex-1 bg-yellow-500 text-white py-4 rounded-2xl font-black text-sm shadow-xl hover:bg-yellow-600 active:scale-95 transition-all"
                        >
                          🔄 {t.needsFollowup}
                        </button>
                      </div>
                    </div>
                  ))}
                </div>
              ) : unit.history.length === 0 ? (
                <div className="text-center py-20 bg-white rounded-[3rem] border-2 border-dashed border-gray-100">
                   <div className="text-6xl mb-6 opacity-20 grayscale">🏗️</div>
                   <button onClick={handleStartWork} className="bg-blue-600 text-white px-10 py-6 rounded-[2rem] text-xl font-black shadow-2xl hover:bg-blue-700 active:scale-95 transition-all">
                     🚀 פתח משימה חדשה לביצוע
                   </button>
                   <p className="text-gray-400 font-bold mt-4 tracking-tight">לחץ כאן כדי להתחיל מעקב על הדירה</p>
                </div>
              ) : null}

              {/* General History List */}
              <div className="space-y-4 pt-4">
                <div className="flex items-center justify-between px-2">
                  <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{t.workHistory}</h4>
                </div>
                <div className="space-y-4">
                  {unit.history.map((log) => (
