import React, { useState, useEffect, useMemo } from 'react';
import { ProjectState, TaskStatus, Unit, Discipline, Appointment } from './types';
import { initializeData, getUnit, updateUnit } from './services/dataService';
import BuildingSelector from './components/BuildingSelector';
import UnitGrid from './components/UnitGrid';
import UnitModal from './components/UnitModal';
import ContractorView from './components/ContractorView';
import ScheduleView from './components/ScheduleView';
import ProjectHistoryView from './components/ProjectHistoryView';
import { Language, translations } from './translations';
import { PUBLIC_AREAS, STATUS_CONFIG } from './constants';

const Logo = () => (
  <svg width="140" height="50" viewBox="0 0 200 80" fill="none" xmlns="http://www.w3.org/2000/svg" className="drop-shadow-sm">
    <path d="M40 50L70 10L100 50H40Z" fill="#71717A" fillOpacity="0.8"/>
    <path d="M75 50L105 15L135 50H75Z" fill="#A1A1AA" fillOpacity="0.6"/>
    <path d="M10 50L40 20L70 50H10Z" fill="#3F3F46" fillOpacity="0.9"/>
    <text x="0" y="70" fontFamily="Heebo" fontWeight="800" fontSize="22" fill="#18181B">ארזי הנגב</text>
    <text x="0" y="82" fontFamily="Heebo" fontWeight="500" fontSize="8" fill="#52525B">ייזום ובניה בע"מ</text>
  </svg>
);

const App: React.FC = () => {
  const [state, setState] = useState<ProjectState>(() => initializeData());
  const [selectedBuildingId, setSelectedBuildingId] = useState<string | null>(null);
  const [selectedUnitId, setSelectedUnitId] = useState<string | number | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [viewMode, setViewMode] = useState<'units' | 'public' | 'contractors' | 'schedule' | 'history'>('units');

  const [lang, setLang] = useState<Language>(() => {
    return (localStorage.getItem('app_lang') as Language) || 'he';
  });

  useEffect(() => {
    localStorage.setItem('app_lang', lang);
    document.documentElement.dir = lang === 'he' ? 'rtl' : 'ltr';
    document.documentElement.lang = lang;
  }, [lang]);

  const t = translations[lang];

  useEffect(() => {
    if (!selectedBuildingId && state.buildings.length > 0) {
      setSelectedBuildingId(state.buildings[0].id);
    }
  }, [state.buildings, selectedBuildingId]);

  const activeUnit = useMemo(() => {
    if (!selectedBuildingId || selectedUnitId === null) return null;
    return getUnit(state, selectedBuildingId, selectedUnitId);
  }, [state, selectedBuildingId, selectedUnitId]);

  // Fix: updated newLog parameter to include optional images field to match UnitModal's onSave requirement
  const handleUpdateUnit = (updates: { 
    newLog?: { status: TaskStatus, workerName: string, contractor: string, description: string, discipline: Discipline, images?: string[] },
    updateLogStatus?: { logId: string, newStatus: TaskStatus },
    newAppointment?: Omit<Appointment, 'id' | 'createdAt' | 'isCompleted'>,
    completeAppointmentId?: string
  }) => {
    if (!activeUnit) return;
    const newState = updateUnit(state, activeUnit, {
      newLog: updates.newLog,
      updateLogStatus: updates.updateLogStatus,
      newAppointment: updates.newAppointment,
      completeAppointmentId: updates.completeAppointmentId
    });
    setState(newState);
  };

  const filteredBuildings = state.buildings.filter(b => {
    const buildingName = lang === 'ru' ? b.name.replace('בניין', 'Здание') : b.name;
    return buildingName.includes(searchTerm) || b.id.includes(searchTerm) || b.name.includes(searchTerm);
  });

  const toggleLanguage = () => {
    setLang(prev => prev === 'he' ? 'ru' : 'he');
  };

  const handleSelectFromOtherView = (buildingId: string, unitId: string | number) => {
    setSelectedBuildingId(buildingId);
    setSelectedUnitId(unitId);
    setViewMode('units');
  };

  return (
    <div className={`min-h-screen bg-slate-50 ${lang === 'ru' ? 'text-left' : 'text-right'}`} dir={lang === 'he' ? 'rtl' : 'ltr'}>
      <header className="sticky top-0 z-40 bg-white border-b border-gray-100 shadow-sm p-3">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="flex items-center gap-6 w-full md:w-auto">
            <Logo />
            <div className="h-10 w-[1px] bg-gray-200 hidden md:block"></div>
            <div className="flex-1">
              <h1 className="text-lg font-black leading-none text-blue-900">{t.appName}</h1>
              <p className="text-[9px] text-gray-400 mt-1 uppercase tracking-widest font-bold">{t.appSubName}</p>
            </div>
            <button onClick={toggleLanguage} className="md:hidden bg-slate-100 hover:bg-slate-200 px-3 py-1.5 rounded-full text-xs font-bold transition-colors border text-gray-600">
              {t.langToggle}
            </button>
          </div>

          <div className="flex items-center gap-4 w-full md:w-auto">
            <div className="flex-1 md:w-64 relative">
              <input 
                type="text" 
                placeholder={t.searchPlaceholder} 
                value={searchTerm} 
                onChange={e => setSearchTerm(e.target.value)} 
                className={`w-full bg-gray-50 border border-gray-200 rounded-full ${lang === 'ru' ? 'pl-10 pr-4' : 'pr-10 pl-4'} py-2 text-sm placeholder:text-gray-300 outline-none focus:ring-2 focus:ring-blue-500/20 font-bold transition-all`} 
              />
              <span className={`absolute ${lang === 'ru' ? 'right-3' : 'right-3'} top-2.5 opacity-30`}>🔍</span>
            </div>
            <button onClick={toggleLanguage} className="hidden md:block bg-slate-50 hover:bg-slate-100 px-4 py-2 rounded-full text-sm font-bold transition-colors border text-gray-500 shadow-sm">
              {t.langToggle}
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto pb-24 px-4">
        {/* Navigation Tabs */}
        <div className="flex gap-2 my-6 bg-slate-200/40 p-1.5 rounded-2xl w-full overflow-x-auto no-scrollbar md:w-fit mx-auto md:mx-0 shadow-inner border border-slate-300/20">
          <button onClick={() => setViewMode('units')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2.5 rounded-xl font-black transition-all ${viewMode === 'units' ? 'bg-white shadow-md text-blue-700' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewUnits}</button>
          <button onClick={() => setViewMode('public')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2.5 rounded-xl font-black transition-all ${viewMode === 'public' ? 'bg-white shadow-md text-blue-700' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewPublic}</button>
          <button onClick={() => setViewMode('contractors')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2.5 rounded-xl font-black transition-all ${viewMode === 'contractors' ? 'bg-white shadow-md text-blue-700' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewContractors}</button>
          <button onClick={() => setViewMode('schedule')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2.5 rounded-xl font-black transition-all ${viewMode === 'schedule' ? 'bg-white shadow-md text-blue-700' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewSchedule}</button>
          <button onClick={() => setViewMode('history')} className={`whitespace-nowrap flex-1 md:flex-none px-6 py-2.5 rounded-xl font-black transition-all ${viewMode === 'history' ? 'bg-white shadow-md text-blue-700' : 'text-gray-500 hover:text-gray-700'}`}>{t.viewHistory}</button>
        </div>

        {viewMode === 'contractors' ? (
          <ContractorView state={state} lang={lang} onSelectUnit={handleSelectFromOtherView} />
        ) : viewMode === 'schedule' ? (
          <ScheduleView state={state} lang={lang} onSelectUnit={handleSelectFromOtherView} />
        ) : viewMode === 'history' ? (
          <ProjectHistoryView state={state} lang={lang} onSelectUnit={handleSelectFromOtherView} />
        ) : (
          <>
            <section className="mt-4">
              <BuildingSelector buildings={filteredBuildings} selectedBuildingId={selectedBuildingId} onSelect={setSelectedBuildingId} state={state} lang={lang} discipline="general" />
            </section>

            {selectedBuildingId && (
              <section className="mt-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                {viewMode === 'units' ? (
                  <UnitGrid buildingId={selectedBuildingId} state={state} onSelectUnit={(num) => setSelectedUnitId(num)} lang={lang} />
                ) : (
                  <div className="bg-white rounded-3xl shadow-xl p-8 border border-gray-100">
                    <h2 className="text-2xl font-black text-gray-800 mb-8 flex items-center gap-3">
                       <span className="bg-blue-50 p-2 rounded-xl">🏢</span> {t.publicAreas}
                    </h2>
                    <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 gap-5">
                      {PUBLIC_AREAS.map(area => {
                        const unitData = getUnit(state, selectedBuildingId, area.id);
                        const statuses = Object.values(unitData.statuses);
                        let finalStatus = TaskStatus.NOT_STARTED;
                        if (statuses.includes(TaskStatus.BLOCKED)) finalStatus = TaskStatus.BLOCKED;
                        else if (statuses.includes(TaskStatus.NEEDS_FOLLOWUP)) finalStatus = TaskStatus.NEEDS_FOLLOWUP;
                        else if (statuses.includes(TaskStatus.IN_PROGRESS)) finalStatus = TaskStatus.IN_PROGRESS;
                        else if (statuses.every(s => s === TaskStatus.DONE)) finalStatus = TaskStatus.DONE;

                        const config = STATUS_CONFIG[finalStatus];
                        return (
                          <button key={area.id} onClick={() => setSelectedUnitId(area.id)} className={`flex items-center gap-5 p-6 rounded-2xl border-2 transition-all hover:shadow-xl active:scale-95 text-right group ${config.color}`}>
                            <span className="text-4xl group-hover:scale-110 transition-transform">{area.icon}</span>
                            <div className="flex flex-col">
                              <span className="font-black text-xl">{(t as any)[area.labelKey]}</span>
                              <span className="text-xs font-bold opacity-70">{(t as any)[config.labelKey]}</span>
                            </div>
                          </button>
                        );
                      })}
                    </div>
                  </div>
                )}
              </section>
            )}
          </>
        )}
      </main>

      {activeUnit && (
        <UnitModal unit={activeUnit} onClose={() => setSelectedUnitId(null)} onSave={handleUpdateUnit} lang={lang} activeDiscipline="general" />
      )}

      <footer className="fixed bottom-0 left-0 right-0 bg-white/90 backdrop-blur-md border-t p-4 text-center text-[10px] text-gray-400 z-30 font-bold uppercase tracking-widest shadow-sm">
        {t.footerInfo}
      </footer>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { Unit, TaskStatus, Discipline, Appointment, TaskLog } from '../types';
import { STATUS_CONFIG, PUBLIC_AREAS, CONTRACTORS } from '../constants';
import { Language, translations } from '../translations';

interface Props {
  unit: Unit;
  onClose: () => void;
  onSave: (updates: { 
    newLog?: { status: TaskStatus, workerName: string, contractor: string, description: string, discipline: Discipline, images?: string[] },
    updateLogStatus?: { logId: string, newStatus: TaskStatus },
    newAppointment?: Omit<Appointment, 'id' | 'createdAt' | 'isCompleted'>,
    completeAppointmentId?: string
  }) => void;
  lang: Language;
  activeDiscipline: Discipline;
}

const UnitModal: React.FC<Props> = ({ unit, onClose, onSave, lang, activeDiscipline }) => {
  const [activeTab, setActiveTab] = useState<'report' | 'schedule' | 'history'>('history');
  const [worker, setWorker] = useState('');
  const [desc, setDesc] = useState('');
  const [contractor, setContractor] = useState(CONTRACTORS[0].id);
  const [editingLogId, setEditingLogId] = useState<string | null>(null);
  const [status, setStatus] = useState<TaskStatus>(TaskStatus.DONE);
  const [selectedImages, setSelectedImages] = useState<string[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Appointment Form State
  const [appDate, setAppDate] = useState('');
  const [appTime, setAppTime] = useState('');
  const [appTenant, setAppTenant] = useState('');
  const [appContractor, setAppContractor] = useState(CONTRACTORS[0].id);
  const [appNotes, setAppNotes] = useState('');

  // Summary Form State
  const [summarizingAppId, setSummarizingAppId] = useState<string | null>(null);
  const [visitSummary, setVisitSummary] = useState('');
  const [needsFollowup, setNeedsFollowup] = useState(false);
  const [followupContractorId, setFollowupContractorId] = useState(CONTRACTORS[1].id); // Default to workers

  const t = translations[lang];

  const activeTasks = unit.history.filter(log => log.status !== TaskStatus.DONE);
  const upcomingAppointments = unit.appointments.filter(app => !app.isCompleted);

  const handleQuickStatusUpdate = (logId: string, newStatus: TaskStatus) => {
    onSave({ updateLogStatus: { logId, newStatus } });
    setEditingLogId(null);
  };

  const handleStartWork = () => {
    setActiveTab('report');
    setStatus(TaskStatus.IN_PROGRESS);
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files) {
      Array.from(files).forEach((file: File) => {
        const reader = new FileReader();
        reader.onloadend = () => {
          setSelectedImages(prev => [...prev, reader.result as string]);
        };
        reader.readAsDataURL(file);
      });
    }
  };

  const removeImage = (index: number) => {
    setSelectedImages(prev => prev.filter((_, i) => i !== index));
  };

  const handleReportSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!worker || !desc) return alert(t.alertFillFields);
    const discipline: Discipline = contractor === 'plumber' ? 'plumbing' : 'general';
    const selectedContractorLabel = (t as any)[CONTRACTORS.find(c => c.id === contractor)?.labelKey || ''];
    onSave({ 
      newLog: { status, workerName: worker, contractor: selectedContractorLabel, description: desc, discipline, images: selectedImages.length > 0 ? selectedImages : undefined } 
    });
    setWorker(''); setDesc(''); setSelectedImages([]); setStatus(TaskStatus.DONE); setActiveTab('history');
  };

  const handleAppSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!appDate || !appTime || !appTenant) return alert(t.alertFillFields);
    const selectedContractor = (t as any)[CONTRACTORS.find(c => c.id === appContractor)?.labelKey || ''];
    onSave({ newAppointment: { date: appDate, time: appTime, tenantName: appTenant, contractor: selectedContractor, notes: appNotes } });
    setAppDate(''); setAppTime(''); setAppTenant(''); setAppNotes('');
  };

  const handleSaveVisitSummary = (e: React.FormEvent) => {
    e.preventDefault();
    if (!visitSummary) return alert(t.alertFillFields);

    const updates: any = { completeAppointmentId: summarizingAppId };

    // Create a history log for the visit itself
    const managerLabel = (t as any)[CONTRACTORS.find(c => c.id === 'manager')?.labelKey || ''];
    updates.newLog = {
      status: needsFollowup ? TaskStatus.NEEDS_FOLLOWUP : TaskStatus.DONE,
      workerName: "סיכום ביקור",
      contractor: managerLabel,
      description: visitSummary,
      discipline: 'general'
    };

    // If followup is needed, the next task will be for the selected contractor
    if (needsFollowup) {
      const selectedContractorLabel = (t as any)[CONTRACTORS.find(c => c.id === followupContractorId)?.labelKey || ''];
      // We'll let the user create the specific contractor task in the history log by tagging it
      updates.newLog.description = `[${selectedContractorLabel}] ${visitSummary}`;
    }

    onSave(updates);
    setSummarizingAppId(null);
    setVisitSummary('');
    setNeedsFollowup(false);
    setActiveTab('history');
  };

  const unitIdentifier = unit.id.split('-').slice(1).join('-');
  const isPublicArea = isNaN(Number(unitIdentifier));
  const publicAreaConfig = isPublicArea ? PUBLIC_AREAS.find(a => a.id === unitIdentifier) : null;
  const displayName = isPublicArea ? (t as any)[publicAreaConfig?.labelKey || ''] : `${t.apartment} ${unitIdentifier}`;

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-md">
      <div className="bg-white w-full max-w-2xl rounded-[2.5rem] shadow-2xl overflow-hidden flex flex-col max-h-[92vh] border border-white/20">

        {/* Header Section */}
        <div className="px-8 py-6 border-b flex justify-between items-center bg-white">
          <div className={lang === 'ru' ? 'text-left' : 'text-right'}>
            <h3 className="text-3xl font-black text-blue-900 tracking-tight">{displayName}</h3>
            <div className="flex items-center gap-3 mt-1">
               <span className="text-[11px] font-black text-gray-400 uppercase tracking-[0.2em]">{t.building}: {unit.buildingId.split('-')[1]}</span>
            </div>
          </div>
          <button onClick={onClose} className="w-12 h-12 flex items-center justify-center hover:bg-red-50 hover:text-red-500 rounded-2xl transition-all text-4xl font-light shadow-sm bg-slate-50">&times;</button>
        </div>

        {/* Tab Navigation */}
        <div className="flex bg-white border-b sticky top-0 z-10">
          <button onClick={() => setActiveTab('history')} className={`flex-1 py-4 font-black text-xs md:text-sm transition-all border-b-4 ${activeTab === 'history' ? 'text-blue-600 border-blue-600 bg-blue-50/30' : 'text-gray-400 border-transparent hover:text-gray-600'}`}>📜 {t.viewHistory}</button>
          <button onClick={() => setActiveTab('schedule')} className={`flex-1 py-4 font-black text-xs md:text-sm transition-all border-b-4 ${activeTab === 'schedule' ? 'text-blue-600 border-blue-600 bg-blue-50/30' : 'text-gray-400 border-transparent hover:text-gray-600'}`}>📅 {t.viewSchedule}</button>
          <button onClick={() => setActiveTab('report')} className={`flex-1 py-4 font-black text-xs md:text-sm transition-all border-b-4 ${activeTab === 'report' ? 'text-blue-600 border-blue-600 bg-blue-50/30' : 'text-gray-400 border-transparent hover:text-gray-600'}`}>➕ {t.newReport}</button>
        </div>

        <div className="flex-1 overflow-y-auto p-6 bg-slate-50/30">
          {activeTab === 'history' && (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-300 space-y-6">
              {activeTasks.length > 0 ? (
                <div className="space-y-4">
                  <div className="flex items-center justify-between px-2">
                    <h4 className="text-[10px] font-black text-blue-500 uppercase tracking-widest">{t.activeTask}</h4>
                  </div>
                  {activeTasks.map(task => (
                    <div key={task.id} className="bg-white border-2 border-blue-500 rounded-[2.5rem] p-6 shadow-2xl relative overflow-hidden ring-8 ring-blue-500/5">
                      <div className="absolute top-0 left-0 w-3 h-full bg-blue-600"></div>
                      <div className="flex justify-between items-start mb-4">
                        <div className="flex items-center gap-3">
                          <div className="w-12 h-12 rounded-2xl bg-blue-50 flex items-center justify-center text-2xl border-2 border-blue-100 shadow-inner">{task.contractor.includes('אינסטלטור') ? '🚰' : '👷'}</div>
                          <div>
                            <span className="font-black text-blue-900 text-xl block leading-tight">{task.workerName}</span>
                            <span className="text-[10px] bg-blue-600 text-white px-2 py-0.5 rounded-md font-black uppercase mt-1 inline-block shadow-sm">{task.contractor}</span>
                          </div>
                        </div>
                        <div className={`text-[10px] font-black px-3 py-1 rounded-full border-2 shadow-sm ${STATUS_CONFIG[task.status].color}`}>{(t as any)[STATUS_CONFIG[task.status].labelKey]}</div>
                      </div>
                      <div className="bg-slate-50/80 p-5 rounded-3xl border border-slate-100 shadow-inner mb-6">
                        <p className="text-sm font-bold text-gray-700 leading-relaxed">{task.description}</p>
                        {task.images && task.images.length > 0 && (
                          <div className="grid grid-cols-3 gap-3 mt-4">
                            {task.images.map((img, idx) => (
                              <div key={idx} className="aspect-square rounded-2xl overflow-hidden border-2 border-white shadow-md cursor-pointer hover:scale-105 transition-transform" onClick={() => window.open(img)}>
                                <img src={img} alt="progress" className="w-full h-full object-cover" />
                              </div>
                            ))}
                          </div>
                        )}
                      </div>
                      <div className="flex gap-4">
                        <button onClick={() => handleQuickStatusUpdate(task.id, TaskStatus.DONE)} className="flex-1 bg-green-600 text-white py-4 rounded-2xl font-black text-sm shadow-xl hover:bg-green-700 active:scale-95 transition-all flex items-center justify-center gap-2">✅ {t.finishWorkAction}</button>
                        <button onClick={() => handleQuickStatusUpdate(task.id, TaskStatus.NEEDS_FOLLOWUP)} className="flex-1 bg-yellow-500 text-white py-4 rounded-2xl font-black text-sm shadow-xl hover:bg-yellow-600 active:scale-95 transition-all">🔄 {t.needsFollowup}</button>
                      </div>
                    </div>
                  ))}
                </div>
              ) : unit.history.length === 0 ? (
                <div className="text-center py-20 bg-white rounded-[3rem] border-2 border-dashed border-gray-100">
                   <div className="text-6xl mb-6 opacity-20 grayscale">🏗️</div>
                   <button onClick={handleStartWork} className="bg-blue-600 text-white px-10 py-6 rounded-[2rem] text-xl font-black shadow-2xl hover:bg-blue-700 active:scale-95 transition-all">🚀 פתח משימה חדשה לביצוע</button>
                </div>
              ) : null}
              <div className="space-y-4 pt-4">
                <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest px-2">{t.workHistory}</h4>
                <div className="space-y-4">
                  {unit.history.map((log) => (
                    <div key={log.id} className={`bg-white border rounded-[2rem] p-5 shadow-sm flex flex-col transition-all hover:border-blue-200 ${log.status === TaskStatus.DONE ? 'opacity-60 grayscale-[0.5]' : ''}`}>
                      <div className="flex items-center gap-4 mb-3">
                        <div className={`w-12 h-12 rounded-2xl flex items-center justify-center text-2xl shadow-inner border-2 ${STATUS_CONFIG[log.status].color.split(' ')[0]}`}>{STATUS_CONFIG[log.status].icon}</div>
                        <div className="flex-1 min-w-0">
                          <div className="flex justify-between items-center">
                             <span className="font-black text-blue-900 truncate text-lg">{log.workerName}</span>
                             <span className="text-[10px] text-gray-300 font-black bg-gray-50 px-2 py-1 rounded-lg">{new Date(log.timestamp).toLocaleDateString()}</span>
                          </div>
                          <span className="text-[10px] text-gray-400 font-bold uppercase">{log.contractor}</span>
                        </div>
                      </div>
                      <p className="text-xs text-gray-600 font-medium leading-relaxed bg-slate-50/50 p-3 rounded-xl border border-slate-100">{log.description}</p>
                    </div>
                  ))}
                </div>
              </div>
            </div>
          )}

          {activeTab === 'schedule' && (
            <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-300">
              {/* Existing Appointments Section */}
              {upcomingAppointments.length > 0 && (
                <div className="space-y-4">
                  <h4 className="text-[10px] font-black text-blue-500 uppercase tracking-widest px-2">{t.upcomingAppointments}</h4>
                  {upcomingAppointments.map(app => (
                    <div key={app.id} className="bg-white border-2 border-slate-100 rounded-[2rem] p-6 shadow-sm">
                      {summarizingAppId === app.id ? (
                        <form onSubmit={handleSaveVisitSummary} className="space-y-4 animate-in zoom-in-95 duration-200">
                           <h5 className="font-black text-blue-900 text-lg border-b pb-2 mb-4">📝 {t.summarizeVisit}</h5>
                           <div className="space-y-2">
                             <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{t.visitSummaryPlaceholder}</label>
                             <textarea 
                               value={visitSummary} 
                               onChange={e => setVisitSummary(e.target.value)} 
                               rows={3} 
                               className="w-full p-4 rounded-2xl border-2 border-blue-100 focus:border-blue-500 outline-none font-bold bg-blue-50/30" 
                               placeholder={t.visitSummaryPlaceholder}
                             />
                           </div>
                           <div className="flex items-center gap-4 bg-slate-50 p-4 rounded-2xl border">
                             <label className="flex items-center gap-3 cursor-pointer">
                               <input type="checkbox" checked={needsFollowup} onChange={e => setNeedsFollowup(e.target.checked)} className="w-6 h-6 rounded-lg accent-blue-600" />
                               <span className="font-black text-gray-700 text-sm">{t.needFollowupTask}</span>
                             </label>
                           </div>
                           {needsFollowup && (
                             <div className="space-y-2 animate-in slide-in-from-top-2">
                               <label className="text-[10px] font-black text-gray-400 uppercase tracking-widest">{t.followupContractor}</label>
                               <select 
                                 value={followupContractorId} 
                                 onChange={e => setFollowupContractorId(e.target.value)} 
                                 className="w-full p-4 rounded-xl border-2 border-blue-100 bg-white font-black"
                               >
                                 {CONTRACTORS.filter(c => c.id !== 'manager').map(c => <option key={c.id} value={c.id}>{c.icon} {(t as any)[c.labelKey]}</option>)}
                               </select>
                             </div>
                           )}
                           <div className="flex gap-2 pt-2">
                             <button type="submit" className="flex-1 bg-blue-600 text-white py-4 rounded-2xl font-black shadow-xl hover:bg-blue-700 transition-all">{t.saveSummary}</button>
                             <button type="button" onClick={() => setSummarizingAppId(null)} className="px-6 bg-slate-200 text-gray-600 rounded-2xl font-black hover:bg-slate-300">ביטול</button>
                           </div>
                        </form>
                      ) : (
                        <div className="flex justify-between items-start">
                          <div>
                            <div className="flex items-center gap-3 mb-2">
                               <span className="bg-blue-600 text-white text-[10px] font-black px-3 py-1 rounded-lg">{app.date} | {app.time}</span>
                               <span className="text-gray-400 font-black text-[10px] uppercase">{app.contractor}</span>
                            </div>
                            <span className="font-black text-blue-900 text-xl block">{app.tenantName}</span>
                            {app.notes && <p className="text-xs text-gray-500 mt-2 italic font-bold">"{app.notes}"</p>}
                          </div>
                          <button 
                            onClick={() => setSummarizingAppId(app.id)} 
                            className="bg-white border-2 border-blue-500 text-blue-600 px-6 py-2.5 rounded-xl text-xs font-black hover:bg-blue-50 transition-all shadow-sm"
                          >
                            ✏️ {t.summarizeVisit}
                          </button>
                        </div>
                      )}
                    </div>
                  ))}
                </div>
              )}

              <section className="bg-yellow-50/40 p-8 rounded-[2.5rem] border-2 border-yellow-100/60 shadow-inner">
                <h4 className="text-xs font-black text-yellow-800 mb-8 uppercase tracking-[0.2em] flex items-center gap-4"><span className="bg-yellow-100 p-3 rounded-2xl">📅</span> {t.scheduleTitle}</h4>
                <form onSubmit={handleAppSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.dateLabel}</label>
                    <input type="date" value={appDate} onChange={e => setAppDate(e.target.value)} className="w-full px-5 py-4 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none transition-all font-black bg-white shadow-sm" />
                  </div>
                  <div className="space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.timeLabel}</label>
                    <input type="time" value={appTime} onChange={e => setAppTime(e.target.value)} className="w-full px-5 py-4 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none transition-all font-black bg-white shadow-sm" />
                  </div>
                  <div className="md:col-span-2 space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.contractorLabel}</label>
                    <select value={appContractor} onChange={e => setAppContractor(e.target.value)} className="w-full px-5 py-4 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none bg-white font-black shadow-sm">
                      {CONTRACTORS.map(c => <option key={c.id} value={c.id}>{c.icon} {(t as any)[c.labelKey]}</option>)}
                    </select>
                  </div>
                  <div className="md:col-span-2 space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.tenantLabel}</label>
                    <input type="text" value={appTenant} onChange={e => setAppTenant(e.target.value)} className="w-full px-5 py-4 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none font-black shadow-sm bg-white" placeholder="שם מלא / טלפון" />
                  </div>
                  <div className="md:col-span-2 space-y-2">
                    <label className="text-[10px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.notesLabel}</label>
                    <textarea value={appNotes} onChange={e => setAppNotes(e.target.value)} rows={2} className="w-full px-5 py-4 rounded-2xl border-2 border-gray-100 focus:border-yellow-400 outline-none resize-none font-bold bg-white shadow-sm" />
                  </div>
                  <button type="submit" className="md:col-span-2 bg-yellow-500 text-white font-black py-6 rounded-3xl hover:bg-yellow-600 transition-all shadow-xl active:scale-95 text-lg">{t.addAppointment}</button>
                </form>
              </section>
            </div>
          )}

          {activeTab === 'report' && (
            <div className="animate-in fade-in slide-in-from-bottom-2 duration-300">
              <section className="bg-blue-50/40 p-8 rounded-[3rem] border-2 border-blue-100 shadow-inner">
                <h4 className="text-md font-black text-blue-800 mb-8 uppercase tracking-[0.3em] text-center border-b-2 pb-6 border-blue-100/50">🚀 {t.newReport}</h4>
                <form onSubmit={handleReportSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  <div className="space-y-3">
                    <label className="text-[11px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.contractorLabel}</label>
                    <select value={contractor} onChange={e => setContractor(e.target.value)} className="w-full px-6 py-5 rounded-2xl border-2 border-gray-100 focus:border-blue-500 outline-none bg-white font-black shadow-sm text-lg">
                      {CONTRACTORS.map(c => <option key={c.id} value={c.id}>{c.icon} {(t as any)[c.labelKey]}</option>)}
                    </select>
                  </div>
                  <div className="space-y-3">
                    <label className="text-[11px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.workerName}</label>
                    <input value={worker} onChange={e => setWorker(e.target.value)} className="w-full px-6 py-5 rounded-2xl border-2 border-gray-100 focus:border-blue-500 outline-none font-black shadow-sm text-lg placeholder:opacity-20" placeholder={t.workerExample} />
                  </div>
                  <div className="space-y-3">
                    <label className="text-[11px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.currentStatus}</label>
                    <select value={status} onChange={e => setStatus(e.target.value as TaskStatus)} className="w-full px-6 py-5 rounded-2xl border-2 border-gray-100 focus:border-blue-500 outline-none bg-white font-black shadow-sm text-lg">
                      {Object.entries(STATUS_CONFIG).map(([s, cfg]) => <option key={s} value={s}>{(t as any)[cfg.labelKey]}</option>)}
                    </select>
                  </div>
                  <div className="space-y-3">
                    <label className="text-[11px] font-black text-gray-400 uppercase px-1 tracking-widest">צרף תמונות 📸</label>
                    <div className="flex items-center gap-3">
                      <button type="button" onClick={() => fileInputRef.current?.click()} className="w-full px-6 py-5 rounded-2xl border-2 border-dashed border-blue-300 bg-white text-blue-500 font-black hover:bg-blue-50 transition-colors flex items-center justify-center gap-2"><span>📷</span> העלה תמונות</button>
                      <input type="file" ref={fileInputRef} onChange={handleImageChange} className="hidden" multiple accept="image/*" />
                    </div>
                  </div>
                  <div className="md:col-span-2">
                    {selectedImages.length > 0 && (
                      <div className="flex flex-wrap gap-3 mb-4 p-4 bg-white rounded-3xl border shadow-inner">
                        {selectedImages.map((img, idx) => (
                          <div key={idx} className="relative w-20 h-20 rounded-xl overflow-hidden group">
                            <img src={img} alt="preview" className="w-full h-full object-cover" />
                            <button type="button" onClick={() => removeImage(idx)} className="absolute top-1 right-1 w-6 h-6 bg-red-500 text-white rounded-full flex items-center justify-center text-xs font-bold opacity-0 group-hover:opacity-100 transition-opacity">&times;</button>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
                  <div className="md:col-span-2 space-y-3">
                    <label className="text-[11px] font-black text-gray-400 uppercase px-1 tracking-widest">{t.whatWasDone}</label>
                    <textarea value={desc} onChange={e => setDesc(e.target.value)} rows={4} className="w-full px-6 py-5 rounded-[2.5rem] border-2 border-gray-100 focus:border-blue-500 outline-none resize-none font-bold shadow-sm text-lg placeholder:opacity-20" placeholder={t.descriptionPlaceholder} />
                  </div>
                  <button type="submit" className="md:col-span-2 bg-blue-600 text-white font-black py-7 rounded-[2rem] hover:bg-blue-700 transition-all shadow-2xl active:scale-95 text-2xl tracking-[0.2em]">{t.updateButton}</button>
                </form>
              </section>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default UnitModal;
